SET session_replication_role = replica;

INSERT INTO public.questions VALUES ('8f839c49-2544-4da0-9852-480f74fcf79b', '3b5ad871-0bc3-48f5-9084-28c192a2f16f', 'radio', 'Questions 36 – 40', '', '<p data-path-to-node="16,0,0">Choose<strong data-path-to-node="16,0,0" data-index-in-node="0"> TRUE</strong>: if the statement agrees with the information,<strong data-path-to-node="16,1,0" data-index-in-node="0">FALSE</strong>: if the statement contradicts the information,<strong data-path-to-node="16,2,0" data-index-in-node="0">NOT GIVEN</strong>: if there is no information on this</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Companies usually hire people on the basis of their character."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "There are some areas of sport that have a greater proportion of talent than others."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Measures of intelligence accurately predict performance at work."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "There are cases in which talented sportspeople have been overlooked."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Newly formed organisations have the most highly motivated staff."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">36. Companies usually hire people on the basis of their character. — {FALSE}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Most recruitment decisions are influenced by the <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"61\">skills and abilities</strong> of an individual rather than their <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"117\">aptitude and attitude</strong>.” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói các công ty thuê dựa trên kỹ năng/khả năng chứ <strong data-path-to-node=\"27,1,0\" data-index-in-node=\"71\">không phải</strong> thái độ/tính cách (aptitude/attitude/character). Thông tin mâu thuẫn nên chọn <strong data-path-to-node=\"27,1,0\" data-index-in-node=\"160\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">37. There are some areas of sport that have a greater proportion of talent than others. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến thể thao (bóng rổ, bóng bầu dục) để làm ví dụ về việc đánh giá sai tài năng, nhưng <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"115\">không hề so sánh</strong> tỷ lệ tài năng giữa các môn thể thao với nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">38. Measures of intelligence accurately predict performance at work. — {FALSE}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…research shows that the best predictors… tend to be measures of intelligence. <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"95\">But even these measures correlate only loosely with performance</strong>…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói các thước đo trí tuệ chỉ liên quan <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"59\">lỏng lẻo</strong> (loosely) chứ không phải <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"93\">chính xác</strong> (accurately). Do đó câu này mâu thuẫn. (Lưu ý đáp án bạn đưa ra là T nhưng dẫn chứng bài học cho thấy nó phải là F).</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">39. There are cases in which talented sportspeople have been overlooked. — {TRUE}</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Basketball star <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"28\">Michael Jordan was dropped</strong> by his high-school basketball coach and a number of top American football quarterbacks were available early in their careers because they were <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"198\">not considered good enough</strong>…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Michael Jordan từng bị loại, điều này chứng minh các vận động viên tài năng từng bị bỏ qua/đánh giá thấp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">40. Newly formed organisations have the most highly motivated staff. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc không có thông tin về “tổ chức mới thành lập” (<em data-path-to-node=\"35,0,0\" data-index-in-node=\"67\">newly formed organisations</em>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('a39136cb-eec9-4772-812c-327369791c9b', '155cd71b-f2ec-44fc-98b9-82d8cbd4374b', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>What recent history tells us about recycling</strong></p>
<p>Richard Fisher, a researcher from Cranfield University, points out that the pace of consumerism has increased more quickly than was predicted in the 1980s. There has, for example, been unexpected growth in waste from {electronic} products. He suggests that the need to protect the environment should be linked to basic values, and adds that it might be better if consumers had more influence over {business} and more direction was provided by {government}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. electronic</strong></p>\n<ul data-path-to-node=\"28\">\n<li><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> (Đoạn F) “Nobody would have said there would be so much <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"67\">electronic</strong> waste.”</li>\n</ul>\n<p><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. business</strong></p>\n<ul data-path-to-node=\"30\">\n<li><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> (Đoạn F) “We need to look at whether it’s <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"53\">business</strong> that drives consumers or the other way around.”</li>\n</ul>\n<p><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. government</strong></p>\n<ul data-path-to-node=\"32\">\n<li><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> (Đoạn F) “You need <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"30\">government</strong> to play a leadership role…”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('506aec36-084e-49de-956d-5c54a0d2bd7f', '0c07d4b3-d0fc-4a08-8c9b-7ef9ffd7975e', 'checkbox', 'Questions 22-23', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>The list below identifies some of the possible aims of urban redevelopment projects.</p>
<p>Which <strong>TWO </strong>things did the State of Berlin hope to achieve with the Gleisdreieck development?</p>
', 'multiple_choice_many', 'null', '[{"option": "to bring people of different ages together", "correct": true}, {"option": "to encourage tourism", "correct": false}, {"option": "to improve transport links", "correct": false}, {"option": "to preserve industrial remains", "correct": true}, {"option": "to generate income for the city", "correct": false}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"26\">22-23. Which TWO things did the State of Berlin hope to achieve with the Gleisdreieck development? (Chọn 2)</h3>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong></p>\n<ol start=\"1\" data-path-to-node=\"27,0,1\">\n<li>\n<p data-path-to-node=\"27,0,1,0,0\"><strong>to bring people of different ages together.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,0,1,1,0\"><strong>to preserve industrial remains.</strong></p>\n</li>\n</ol>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) Dự án nhằm “integrating <strong>different generations and social groups</strong> in sustainable way” và “the <strong>conservation of railway heritage</strong> also emerged.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Hai mục tiêu chính là <strong>tích hợp các thế hệ và nhóm xã hội</strong> khác nhau và <strong>bảo tồn di sản đường sắt</strong> (industrial remains).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('2d852441-0579-4078-bbcd-2e291601dc06', 'f12a1b04-bff7-4300-acb9-e67b8ce4e345', 'radio', 'Questions 1-7', '', '<p>Choose <strong>TRUE</strong> – if the statement agrees with the information, <strong>FALSE</strong> – if the statement contradicts the information, <strong>NOT GIVEN</strong> – if there is no information on this</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Many of the RFDS doctors work as volunteers."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists make trips to outback communities each month"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists are accompanied on their journeys to remote areas by a dental nurse."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists must provide a wide range of dental services."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Rural dental patients are more informed about oral hygiene than urban patients."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists educate patients about good eating habits."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Urban Australians generally have better teeth because their water is treated."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">. Many of the RFDS doctors work as volunteers. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “This non-profit organisation is the oldest and largest airborne health service…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói RFDS là tổ chức phi lợi nhuận (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"59\">non-profit</em>), nhưng <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"78\">không hề đề cập</strong> đến việc các bác sĩ ở đây làm việc tình nguyện hay được trả lương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. RFDS dentists make trips to outback communities each month. — {FALSE}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “RFDS dentists might only visit a community <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"55\">once every few months, or sometimes once per year</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói họ có thể chỉ đến vài tháng một lần hoặc mỗi năm một lần, không phải là tháng nào cũng đi (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"115\">each month</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. RFDS dentists are accompanied on their journeys… by a dental nurse. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> Không có thông tin trong bài.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến bác sĩ, y tá và nha sĩ nói chung trong vùng, nhưng <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"83\">không nói rõ</strong> liệu khi bay đi làm nhiệm vụ thì nha sĩ có y tá đi kèm hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. RFDS dentists must provide a wide range of dental services. — {TRUE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “RFDS dentists need to be <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"37\">‘all-rounders’</strong>. They need to be able to do <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"80\">all kinds of dental procedures</strong>…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “All-rounders” (người đa năng) và “all kinds of procedures” tương ứng với “a wide range of services”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">5. Rural dental patients are more informed about oral hygiene than urban patients. — {FALSE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…people living in these areas also <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"49\">receive less education</strong> about good dental hygiene than their <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"109\">city counterparts</strong> do.” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người dân vùng sâu vùng xa nhận được ít giáo dục về vệ sinh răng miệng hơn người dân thành phố, trái ngược với ý “more informed” (hiểu biết hơn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">6. RFDS dentists educate patients about good eating habits. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…educate their patients on good oral hygiene, such as <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"68\">tooth brushing and flossing</strong>.” (Đoạn 9)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về giáo dục vệ sinh răng miệng (đánh răng, dùng chỉ nha khoa), nhưng <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"96\">không nhắc đến</strong> việc giáo dục về thói quen ăn uống (<em data-path-to-node=\"14,1,0\" data-index-in-node=\"147\">eating habits</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">7. Urban Australians generally have better teeth because their water is treated. — {TRUE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “City dwellers in Australia use water supplies that have been <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"73\">fluoridated</strong>, and their <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"96\">rates of tooth decay are lower</strong> because of this.” (Đoạn 10)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Treated” ở đây là việc thêm Fluoride vào nước. Việc tỉ lệ sâu răng thấp hơn đồng nghĩa với việc họ có răng tốt hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('b9ec274a-6bca-41e1-b2d4-ad180489ab0d', 'f12a1b04-bff7-4300-acb9-e67b8ce4e345', 'fillup', 'Questions 8-13', '<p>Complete the notes below.</p>
<p>Choose<strong> ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 8-13 on your answer sheet.</p>
<p><strong>Challenges faced by RFDS dentists</strong></p>
<ul>
<li>need to bring equipment including {computers} for records aircraft used to carry equipment have restricted {space}</li>
<li>problems offering some services, e.g., fitting {dentures}</li>
<li>people in remote areas are more likely to have infection in their mouth</li>
</ul>
<p><strong>Products supplied by RFDS dentists</strong></p>
<p>If necessary, RFDS provides:</p>
<ul>
<li>{toothpaste} and {toothbrushes} for regular use</li>
<li>{mouthguards} to protect teeth of sports players</li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">8. …need to bring equipment including {computers} for records.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…and <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"19\">computers</strong> for keeping track of patients’ treatments.” (Đoạn 5)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">9. …aircraft used to carry equipment have restricted {space}.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…since the small planes that transport dentists have <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"67\">limited space</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Restricted” đồng nghĩa với “limited”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">10. …problems offering some services, e.g., fitting {dentures}.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “For example, <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"25\">dentures</strong> (for artificial teeth) can be very difficult to provide…” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">11. If necessary, RFDS provides: {toothpaste} and…</strong> <strong data-path-to-node=\"25\" data-index-in-node=\"53\">12. …{toothbrushes} for regular use.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…basic dental hygiene items such as <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"50\">toothpaste</strong> and <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"65\">toothbrushes</strong>… If this is the case, the RFDS supplies these.” (Đoạn 8)</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">13. {mouthguards} to protect teeth of sports players.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The RFDS also provides <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"35\">mouthguards</strong> for young sports players.” (Đoạn 9)</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('4ae8ed7a-4555-4dae-87f4-1beb1c7e1410', '0c07d4b3-d0fc-4a08-8c9b-7ef9ffd7975e', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Gleisdreieck Urban Park</strong></span></p>
<p>In the middle of the new park is a {meadow} , where there is a path for pedestrians and two railway lines. A slow train uses these lines to make a regular journey between its based and a {museum} . Benches have been provided on the north side, so that people can relax and enjoy the sunshine, and to the east is an area with mature trees of various kinds, as well as sets of swings. A range of sports and leisure areas are situated around the {edges} of the site.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"29\">24. In the middle of the new park is a <strong>meadow</strong>, where there is a path for pedestrians and two railway lines.</h3>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong>Đáp án:</strong> <strong>meadow</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “The project as a whole was planned around a large central <strong>meadow</strong>, intersected from east to west by a concrete footpath, and from north to south by a pair of railway lines.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong>Giải thích:</strong> Công viên được thiết kế xung quanh một <strong>đồng cỏ</strong> trung tâm lớn, có đường đi bộ và đường ray cắt qua.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"32\">25. A slow train uses these lines to make a regular journey between its based and a <strong>museum</strong>.</h3>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án:</strong> <strong>museum</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “Once a month, a train slowly travels along these lines from its parking shed to <strong>German Museum of Technology</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong>Giải thích:</strong> Chuyến tàu thường xuyên đi đến Bảo tàng Công nghệ Đức (<strong>museum</strong>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"35\">26. A range of sports and leisure areas are situated around the <strong>edges</strong> of the site.</h3>\n<ul data-path-to-node=\"36\">\n<li>\n<p data-path-to-node=\"36,0,0\"><strong>Đáp án:</strong> <strong>edges</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"36,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “<strong>The edges of the park are finished with a collection of distinctive, functional spaces</strong>, for example a nursery, sports fields… community gardens…”</p>\n</li>\n<li>\n<p data-path-to-node=\"36,2,0\"><strong>Giải thích:</strong> Các khu vực thể thao và giải trí nằm ở <strong>các rìa</strong> (<em>edges</em>) của công viên.</p>\n</li>\n</ul>\n"}]', 3);
INSERT INTO public.questions VALUES ('53b51bfe-1f6d-4cbc-aaaf-3a833cdcd804', '617564f3-b19f-48fd-b9d5-809f9363eda5', 'matching', 'Questions 33–37', NULL, '<p>Complete the summary using the list of phrases, A–H, below.</p>
', 'matching_features', NULL, '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}, {"option": "D", "correct": false}, {"option": "E", "correct": false}, {"option": "F", "correct": false}, {"option": "G", "correct": false}, {"option": "H", "correct": false}]', '{"layoutType": "summary", "summaryText": "<h2 style=\"text-align: center;\"><strong>Calls by the umpire</strong></h2>\n<p>Even after ABS was developed, MLB still wanted human umpires to shout out decisions as they had in their {F former roles}.<br>The umpire’s job had, at one time, required a {D subjective assessment} about whether a ball was a strike.<br>A ball is considered a strike when the batter does not hit it and it crosses through a {H perceived area} extending approximately from the batter’s knee to his chest.</p>\n<p>In the past, {B numerous disputes} over strike calls were not uncommon, but today everyone accepts the complete ban on pushing or shoving the umpire.<br>One difference, however, is that during the first game DeJesus used ABS, strike calls were met with {G total silence}.</p>", "answerOptions": [{"optionText": "A pitch boundary"}, {"optionText": "B numerous disputes"}, {"optionText": "C team tactics"}, {"optionText": "D subjective assessment"}, {"optionText": "E widespread approval"}, {"optionText": "F former roles"}, {"optionText": "G total silence"}, {"optionText": "H perceived area"}], "matchingItems": null}', '{"layoutType": "standard", "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>33. F (former roles)<br />(Đoạn 2: “MLB still wanted human umpires to announce the calls, just as they would have done in the past.”)<br />→ MLB vẫn muốn trọng tài gọi bóng như trước đây → former roles.</p>\n<p> <br />34. D (subjective assessment)<br />(Đoạn 2: “Previously, calling a strike was a judgment call on the part of the umpire.”)<br />→ Trước đây, quyết định mang tính chủ quan của trọng tài. → subjective assessment.</p>\n<p> <br />35. H (perceived area)<br />(Đoạn 2: “A pitch that passes through the ‘strike zone’—an imaginary zone…” )<br />→ Vùng strike zone là vùng tưởng tượng / cảm nhận được → perceived area.</p>\n<p> <br />36. B (numerous disputes)<br />(Đoạn 3: “Countless arguments between a team’s manager and the umpire have taken place over its boundaries…” )<br />→ Trong quá khứ, đã có rất nhiều tranh cãi (numerous disputes) về các quyết định. → B.</p>\n<p> <br />37. G (total silence)<br />(Đoạn 2: “During that first game DeJesus used ABS, strike calls were met with no heckling and no shouted disagreement. Nobody said a word.”)<br />→ Trận đầu tiên dùng ABS, khán giả im lặng hoàn toàn → total silence.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('11c9339d-6624-45e5-b920-705970e986fa', '514b2588-3cf9-4edb-bc5a-df145915c4ae', 'fillup', 'Questions 20–24', '<div class="quests-inner-desc">
<div class="txt">
<div class="quests-inner-desc">
<div class="txt">
<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p>In the modern world, {technological} advancements are happening so quickly that humans are unable to adjust to them.</p>
<p>Biophilia can help us deal with the {stress} caused by the difficulties of our current lifestyles.</p>
<p>People instinctively feel more comfortable in places which have plenty of {sunlight} .</p>
<p>An experiment designed to test the effect of nature on patient recovery times found that those who could see a {tree} made a faster recovery.</p>
<p>There is a biophilic design feature in the University of Guelph-Humber building which improves the quality of the {air} .</p>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">20. In the modern world,  <strong>technological</strong> advancements are happening so quickly that humans are unable to adjust to them.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>technological</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “The rates of <strong>technological</strong> progress are far exceeding rates of psychological evolution, leaving us ill-equipped to cope with our lifestyle…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Câu này nói về sự tiến bộ quá nhanh của <strong>công nghệ</strong> (<em>technological</em> advancements) khiến con người không thể thích nghi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">21. Biophilia can help us deal with the <strong>stress</strong> caused by the difficulties of our current lifestyles.</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>stress</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “…leaving us ill-equipped to cope with our lifestyle, which in turn leads to <strong>increased stress</strong>. Because biophilia attempts to integrate basic and current needs, it can alleviate the difficulties…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Thiết kế Ái sinh giúp giảm bớt khó khăn do lối sống hiện đại gây ra, được đặc trưng bằng <strong>căng thẳng</strong> (<em>stress</em>) gia tăng.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">22. People instinctively feel more comfortable in places which have plenty of <strong>sunlight</strong> , something which is necessary for health and well-being.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>sunlight</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “For example, one crucial element… is <strong>sunlight</strong>. We are evolutionarily programmed to respond positively to sunny areas over dark or overcast ones, and sense that they will foster restoration, improve emotional well-being and promote health.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Mọi người được lập trình để phản ứng tích cực với các khu vực có nhiều <strong>ánh sáng mặt trời</strong> (<em>sunlight</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">23. An experiment designed to test the effect of nature on patient recovery times found that those who could see a <strong>tree</strong> made a faster recovery.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>tree</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “One well-known study looked at the impact of nature on patients after surgery. One group had a view of <strong>tree</strong>; the others had a window looking onto a brick wall.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Thử nghiệm cho thấy bệnh nhân có thể nhìn thấy một <strong>cái cây</strong> (<em>tree</em>) hồi phục nhanh hơn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">24. There is a biophilic design feature in the University of Guelph-Humber building which improves the quality of the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>air</strong>.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>air</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “The wall is covered in dense foliage… The wall <strong>purifies the air</strong> and has the potential to fulfill the building’s fresh air intake requirements.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Tính năng thiết kế sinh học (bức tường cây) trong tòa nhà giúp <strong>lọc sạch không khí</strong> (<em>purifies the air</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('23842d37-b858-47cf-82a1-4031ca24d5e2', 'c532d8cb-154b-4ae7-b02b-b619b2f0a930', 'radio', 'Questions 1-7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "ln Ancient China, writing was occasionally done on silk."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Coloured paper was invented during the Tang Dynasty."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Papermakers from Samarkand were captured by the Chinese."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Papermaking as a large-scale industry originated in Iran."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Papermaking skills were brought to Europe via North Africa."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "When Gutenberg invented movable type, paper materials were very expensive."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The end of the trade in rags was brought about by the difficulty of transporting them."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. In Ancient China, writing was occasionally done on silk.</p>\n<ul data-path-to-node=\"3\">\n<li><strong>Đáp án:</strong> <strong>TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “The light material of <strong>silk was sometimes used</strong>, but was normally too expensive to consider.”</li>\n<li><strong>Giải thích:</strong> Văn bản khẳng định lụa (<strong>silk</strong>) <strong>đôi khi được sử dụng</strong> (<strong>sometimes used</strong>) để viết, điều này làm cho nhận định là đúng.</li>\n</ul>\n<p>2. Coloured paper was invented during the Tang Dynasty.</p>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “During the Tang Dynasty… tea was served from baskets with <strong>multi-colored paper cups and paper napkins</strong>…”</li>\n<li><strong>Giải thích:</strong> Văn bản chỉ nói rằng giấy nhiều màu (<strong>multi-colored paper</strong>) đã được <em>sử dụng</em> trong thời nhà Đường, nhưng <strong>không nói rõ</strong> rằng giấy màu đã được <strong>phát minh</strong> (<strong>invented</strong>) trong thời kỳ này.</li>\n</ul>\n<p>3. Papermakers from Samarkand were captured by the Chinese.</p>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án:</strong> <strong>FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “During a battle on the banks of the Tarus river, a <strong>Chinese caravan was captured which happened to include several papermakers</strong>. <strong>They were taken away to Samarkand</strong>…”</li>\n<li><strong>Giải thích:</strong> Chính người Trung Quốc (Chinese papermakers) đã bị quân đội Hồi giáo bắt và đưa đến Samarkand, chứ không phải thợ Samarkand bị người Trung Quốc bắt.</li>\n</ul>\n<p>4. Papermaking as a large-scale industry originated in Iran.</p>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án:</strong> <strong>TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) “The rudimentary and laborious process of papermaking was refined and <strong>bulk manufacturing of paper began in Iran</strong>, where they invented a method to make a thicker sheet of paper, which helped <strong>transform papermaking from an art into an important business</strong>.”</li>\n<li><strong>Giải thích:</strong> Việc sản xuất hàng loạt (bulk manufacturing / large-scale industry) và chuyển đổi thành ngành kinh doanh quan trọng bắt đầu ở Iran.</li>\n</ul>\n<p>5. Papermaking skills were brought to Europe via North Africa.</p>\n<ul data-path-to-node=\"11\">\n<li><strong>Đáp án:</strong> <strong>TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) “Finally, when the <strong>Moors from North Africa invaded Spain and Portugal they brought the technology with them</strong> and so it was that papermaking entered Europe in the 12th century.”</li>\n<li><strong>Giải thích:</strong> Công nghệ làm giấy đã đến châu Âu thông qua người Moor từ Bắc Phi.</li>\n</ul>\n<p>6. When Gutenberg invented movable type, paper materials were very expensive.</p>\n<ul data-path-to-node=\"13\">\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 8) Văn bản nói rằng <strong>da cừu</strong> (parchment) là vật liệu được ưa chuộng trước đó và rất đắt, nhưng <strong>không đề cập</strong> đến việc nguyên liệu làm giấy (như giẻ rách) có đắt vào thời Gutenberg hay không.</li>\n</ul>\n<p>7. The end of the trade in rags was brought about by the difficulty of transporting them.</p>\n<ul data-path-to-node=\"15\">\n<li><strong>Đáp án:</strong> <strong>FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 9) “The early European papers were made from recycled cotton and linen – and a huge trade quickly developed around the trading of old rags… Yet <strong>soon this source became insufficient</strong> and some curious attempts were made to find new materials.”</li>\n<li><strong>Giải thích:</strong> Nguồn cung cấp giẻ rách không còn <strong>đủ</strong> (insufficient), chứ không phải do khó khăn trong vận chuyển (difficulty of transporting), nên nhận định là sai.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('5c4d197e-6984-4670-b3e8-e245ccd37079', '514b2588-3cf9-4edb-bc5a-df145915c4ae', 'checkbox', 'Questions 25–26', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO</strong> of the following statements does the writer make about the Adam Joseph Lewis Center at Oberlin College?</p>
', 'multiple_choice_many', 'null', '[{"option": "It was the first educational establishment designed with biophilic principles.", "correct": false}, {"option": "It is beneficial for both students and the environment.", "correct": true}, {"option": "It has established new concepts for classroom design.", "correct": false}, {"option": "It aims to inspire new ways of thinking about the environment.", "correct": true}, {"option": "It provides solar power to other buildings in the surrounding area.", "correct": false}]', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"3\">25. <strong>Đáp án: It is beneficial for both students and the environment.</strong> <em>(Nó mang lại lợi ích cho cả sinh viên và môi trường.)</em></h2>\n<p data-path-to-node=\"5\"><strong>Dẫn chứng trong bài đọc:</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Lợi ích Môi trường (Environment):</strong> Đoạn văn mô tả Trung tâm Lewis là một công trình tiên phong về môi trường (Net-Zero Energy – sản xuất nhiều năng lượng hơn tiêu thụ) và sử dụng các hệ thống bền vững. Ví dụ, nó <strong>sử dụng năng lượng mặt trời</strong> và có một hệ thống <strong>‘Living Machine’</strong> (Máy sống) để xử lý nước thải, cho thấy sự <strong>trách nhiệm và lợi ích to lớn đối với hành tinh</strong> (sử dụng tài nguyên hiệu quả, không thải chất độc ra môi trường).</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Lợi ích cho Sinh viên (Students):</strong> Đoạn văn thường đề cập đến tác động của môi trường này lên những người học tập và làm việc tại đây. Tác giả David Orr giải thích rằng tòa nhà được thiết kế không chỉ để dạy học mà còn <strong>nâng cao sức khỏe và tinh thần</strong> của người dùng. Việc được tiếp xúc với ánh sáng tự nhiên, không khí sạch, và các yếu tố sinh học giúp <strong>cải thiện khả năng tập trung, sự sáng tạo và hạnh phúc</strong>, từ đó <strong>tác động tích cực đến giáo dục</strong> của sinh viên.</p>\n</li>\n</ul>\n<h2 data-path-to-node=\"8\">26. <strong>Đáp án: It aims to inspire new ways of thinking about the environment.</strong> <em>(Nó nhằm mục đích truyền cảm hứng cho những cách suy nghĩ mới về môi trường.)</em></h2>\n<p data-path-to-node=\"10\"><strong>Dẫn chứng trong bài đọc:</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\">Mục tiêu của tòa nhà không chỉ là đạt được các chứng nhận xanh mà còn là một <strong>công cụ giảng dạy (Building as Pedagogy)</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\">Giám đốc chương trình, David Orr, đã giải thích rằng mục tiêu của tòa nhà là “<strong>giúp xác định lại mối quan hệ giữa con người và môi trường – một mối quan hệ sẽ mở rộng nhận thức của chúng ta về các khả năng sinh thái</strong>.” (redefine the relationship between humankind and the environment – one that would expand our sense of ecological possibilities).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\">Tòa nhà này được coi là một <strong>hình mẫu</strong> (showcase) cho công nghệ xanh, mục đích là để <strong>truyền cảm hứng</strong> cho các kiến trúc sư, nhà thiết kế, sinh viên, và cộng đồng rộng lớn hơn về việc xây dựng các công trình thân thiện với môi trường, từ đó thay đổi cách mọi người <strong>tư duy về phát triển bền vững</strong> và hệ sinh thái.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('d8f96238-2f86-4686-b642-1e8f2f734905', 'c6f9c426-afb6-4f62-a284-161047ac50e9', 'matrix', 'Questions 14-18', '', '<p>Reading Passage 2 has six paragraphs, A-F.</p>
<p>Which paragraph contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Similarities between studies of mammoth remains from different parts of the world.", "correctCategoryLetter": "D"}, {"itemText": "Details of the uses to which mammoth body parts were put.", "correctCategoryLetter": "B"}, {"itemText": " A theory that accounts for the damage to lyuba''s face. ", "correctCategoryLetter": "E"}, {"itemText": " An explanation of how an individual was able to identify a small corpse.", "correctCategoryLetter": "A"}, {"itemText": "A comparison between lyuba and other young mammoth corpses.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">14. Similarities between studies of mammoth remains from different parts of the world. — {D}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Most of these came from the </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"40\">Great Lakes region of North America</strong><span class=\"\">…</span><span class=\"\"> He has done limited work in </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"107\">Siberia</strong><span class=\"\">,</span><span class=\"\"> but his analysis of tusks from Wrangel Island…</span><span class=\"\"> suggests the </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"178\">same conclusion</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn D so sánh kết quả nghiên cứu của Dan Fisher tại Bắc Mỹ và Siberia,</span><span class=\"\"> cho thấy chúng đều dẫn đến cùng một kết luận (</span><em class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"130\">same conclusion</em><span class=\"\">).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">15. Details of the uses to which mammoth body parts were put. — {B}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “In addition to exploiting mammoths for </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"51\">food</strong><span class=\"\">,</span><span class=\"\"> they used their bones and tusks to make </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"97\">weapons, tools, and even dwellings</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn B liệt kê chi tiết các bộ phận của voi ma mút được con người sử dụng làm thức ăn,</span><span class=\"\"> vũ khí,</span><span class=\"\"> công cụ và nhà ở.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">16. A theory that accounts for the damage to Lyuba’s face. — {E}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">Fisher saw it as a possible explanation for the </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"63\">dent above her trunk</strong><span class=\"\">.</span><span class=\"\"> If she was frantically fighting for breath…</span><span class=\"\"> a partial vacuum was created…</span><span class=\"\"> which would have </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"180\">flattened surrounding soft tissue</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn E đưa ra giả thuyết của Fisher về việc hít phải bùn cát quá mạnh tạo ra môi trường chân không làm lõm/phẳng phần mô mềm trên mặt (vết lõm trên vòi).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">17. An explanation of how an individual was able to identify a small corpse. — {A}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Although he’d never seen such an animal before,</span><span class=\"\"> Khudi had seen </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"75\">many mammoth tusks</strong><span class=\"\">…</span><span class=\"\"> and this </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"106\">persuaded him the corpse was a baby mammoth</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn A giải thích nhờ kinh nghiệm nhìn thấy nhiều ngà voi ma mút trước đó mà Yuri Khudi có thể nhận diện được cái xác nhỏ này là voi ma mút.</span></p>\n</li>\n</ul>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. A comparison between Lyuba and other young mammoth corpses. — {C}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Fisher and Buigues had examined <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"44\">other specimens together, including infants</strong>, but these had been in a <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"113\">relatively poor state</strong>. Lyuba was <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"146\">another story entirely</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh Lyuba với các mẫu vật voi con khác, nhấn mạnh rằng Lyuba ở tình trạng bảo quản hoàn hảo hơn hẳn.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('59b56269-f81a-48ae-b451-6844430dcabc', 'c6f9c426-afb6-4f62-a284-161047ac50e9', 'matrix', 'Questions 19-23', '', '<p>Match each statement with the correct person, <strong>A-G.</strong></p>
<p><strong>NB </strong>You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "The indications are that mammoths died as a result of climate change.", "correctCategoryLetter": "C"}, {"itemText": "Teeth analysis is important in discovering why mammoths died out.", "correctCategoryLetter": "E"}, {"itemText": "The corpse of the baby mammoth is in better condition than any other that has been discovered.", "correctCategoryLetter": "D"}, {"itemText": "It would be a mistake to ignore the baby mammoth''s discovery, because of its potential importance.", "correctCategoryLetter": "A"}, {"itemText": "Mammoths often died at a time of year when they should have been in good physical condition.", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "Yuri Khudi", "categoryLetter": "A"}, {"categoryText": "Kirill Serotetto", "categoryLetter": "B"}, {"categoryText": "Adrian Lister", "categoryLetter": "C"}, {"categoryText": "Alexei Tikhonov", "categoryLetter": "D"}, {"categoryText": "Dan Fisher", "categoryLetter": "E"}, {"categoryText": "Bermard Buigues", "categoryLetter": "F"}, {"categoryText": "Naoki Suzuki", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">19. The indications are that mammoths died as a result of climate change. — {C: Adrian Lister}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “‘We have strong evidence that the <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"46\">temperature rise played a significant part in their extinction</strong>.’ says Adrian Lister…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Teeth analysis is important in discovering why mammoths died out. — {E: Dan Fisher}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…a confirmation for Fisher that <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"46\">dental research</strong> is useful for evaluating health and thus <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"103\">key to investigating the causes of mammoth extinction</strong>.” (Đoạn F)</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. The corpse of the baby mammoth is in better condition than any other… — {D: Alexei Tikhonov}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “According to Tikhonov, Khudi had rescued ‘<strong data-path-to-node=\"20,0,0\" data-index-in-node=\"54\">the best preserved mammoth</strong> to come down to us from the Ice Age’…” (Đoạn C)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. It would be a mistake to ignore the baby mammoth’s discovery… — {A: Yuri Khudi}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Khudi realised the find might be significant and <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"61\">he knew he couldn’t just return home and forget all about it</strong>.” (Đoạn A)</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. Mammoths often died at a time of year when they should have been in good physical condition. — {E: Dan Fisher}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “His samples frequently came from animals that had <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"62\">died in the autumn</strong>, when they <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"92\">should have been at their peak</strong> after summer grazing…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “At their peak” tương ứng với “good physical condition”.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('7c1aa5f6-74bd-48d8-bdb8-15d236c84c9d', 'c6f9c426-afb6-4f62-a284-161047ac50e9', 'fillup', 'Questions 24 - 26', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p>Some researchers say that a marked rise in temperature impacted on mammoths by changing the type of.</p>
<p>{vegetation} available.</p>
<p>Fisher concluded that many of the mammoth tusks he looked at displayed signs of {human hunting}</p>
<p>Not long after Lyuba’s death, the Mammuthus primigenius group she belonged to was replaced by another group that came from {North America}.</p>', '', 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. …marked rise in temperature impacted on mammoths by changing the type of {vegetation} available.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…sharp rise in temperature, which dramatically altered the <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"73\">vegetation</strong>.” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. Fisher concluded that many of the mammoth tusks he looked at displayed signs of {human hunting}.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…to Fisher the tusks often revealed telltale evidence of <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"71\">human hunting</strong>.” (Đoạn D)</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. …the Mammuthus primigenius group she belonged to was replaced by another group that came from {North America}.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…another population migrating to Siberia from <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"60\">North America</strong> would take their place.” (Đoạn F)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('bab55498-5ea0-4e01-801c-87a62255a6ea', 'd2f9aafb-e221-4fd7-84f6-3f357187a22c', 'matrix', ' Questions 14–17', NULL, '<p>Look at the following findings (Questions 14-17) and the list of researchers below.</p>
<p>Match each finding with the correct researcher <strong>A</strong>, <strong>B</strong> or <strong>C</strong></p>
<p>NB You may use any letter more than once</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "the physiological mechanism which controls the body’s sleep patterns", "correctCategoryLetter": "B"}, {"itemText": "an observation that some creatures may have no need for sleep", "correctCategoryLetter": "A"}, {"itemText": "data indicating the dangers of extended periods of sleeplessness", "correctCategoryLetter": "B"}, {"itemText": "an animal behaviour which could serve as a basis for modifying human sleep pattern", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Jerome Siegel", "categoryLetter": "A"}, {"categoryText": "Clifford Saper", "categoryLetter": "B"}, {"categoryText": "Verner Bingman", "categoryLetter": "C"}]}', '[{"content": "<h3 data-path-to-node=\"6\">14. The physiological mechanism which controls the body’s sleep patterns.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>B (Clifford Saper)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “Neuroscientist <strong>Clifford Saper</strong> of the Harvard Medical School has located a small area at the base of the brain called the ventrolateral preoptic nucleus that sends chemical signals to other parts of the brain during sleep to slow those brain parts down and <strong>determines the best sleep budget for the animal</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Clifford Saper là người đã xác định được vùng nhỏ ở đáy não (ventrolateral preoptic nucleus) chịu trách nhiệm gửi tín hiệu hóa học để <strong>kiểm soát và xác định</strong> (<em>controls and determines</em>) kiểu ngủ của cơ thể.</p>\n</li>\n</ul>\n<div class=\"attachment-container search-images\">\n<div class=\"image-container ng-star-inserted\" data-full-size-image-uri=\"https://encrypted-tbn1.gstatic.com/licensed-image?q=tbn:ANd9GcSjh6ULyHuhDZXiFY-NoFBs5yye9fum1tgzxWXG9lsZgB0emd1JuD3o1tt8RHGuB9e3F1Hd7WViwHIaq_pG0m6QhquOYMSVxPX25C8ryD0kxHuHiHg\"></div>\n</div>\n<h3 data-path-to-node=\"10\">15. An observation that some creatures may have no need for sleep.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>A (Jerome Siegel)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “According to <strong>Siegel</strong>, the results of his orca study fundamentally change our view of sleep. ‘…here we have a creature which grows one of the largest brains in the animal kingdom, and yet it is doing this <strong>without sleep</strong>.’”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Jerome Siegel đã quan sát thấy cá orca mẹ và con <strong>không ngủ</strong> (<em>without sleep</em>) trong tháng đầu tiên sau khi sinh, đặt ra nghi vấn về tính cần thiết tuyệt đối của giấc ngủ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">16. Data indicating the dangers of extended periods of sleeplessness.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>B (Clifford Saper)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) <strong>Saper</strong>, tuy không đồng ý với việc giảm ngủ, đã cảnh báo: “The effect of 20 hours of wakefulness on driving is the equivalent of two shots of whiskey… <strong>Sleep deprivation is unfortunately a major cause of death in the US</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Clifford Saper cung cấp dữ liệu về <strong>nguy cơ</strong> (<em>dangers</em>) mất ngủ kéo dài, đặc biệt là mối liên hệ giữa thiếu ngủ và tai nạn giao thông gây tử vong.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">17. An animal behaviour which could serve as a basis for modifying human sleep pattern.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>C (Verner Bingman)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F &amp; G) <strong>Verner Bingman</strong> đang nghiên cứu hành vi ngủ ngắn (<em>micro naps</em>) của chim hét Swainson di cư và hy vọng “develop techniques or drugs that could <strong>recreate a similar brain pattern in humans</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Verner Bingman tin rằng hành vi ngủ của loài chim này có thể dùng làm <strong>cơ sở</strong> (<em>basis</em>) để điều chỉnh kiểu ngủ của con người, cho phép con người ngủ ít hơn mà vẫn duy trì hiệu quả.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('66477a4d-5942-455a-b7ae-6c0ec4ccf8b3', 'e06f9fa7-4d38-4e89-90b9-ed2dd66bf6af', 'matching', 'Questions 15-20', '', '<p>What is the main theme of each of the following musicals?</p>
<p>Choose <strong>SIX</strong> answers from the box and write the correct letter, A-H, next to questions 15-20.<br> </p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Musicals</strong></p>\n<p> </p>\n<p>The Climb {B managing to achieve success}</p>\n<p> </p>\n<p>The Voyagers {A living in a different century}</p>\n<p> </p>\n<p>Joey Brown {H handling conflict}</p>\n<p> </p>\n<p>Main Street {E experiencing disappointment}</p>\n<p> </p>\n<p>Millie and Mike {D growing up}</p>\n<p> </p>\n<p>Windswept {F living in a magical place}</p>", "answerOptions": [{"optionText": "A living in a different century"}, {"optionText": "B managing to achieve success"}, {"optionText": "C ageing slowly"}, {"optionText": "D growing up"}, {"optionText": "E experiencing disappointment"}, {"optionText": "F living in a magical place"}, {"optionText": "G overcoming poverty"}, {"optionText": "H handling conflict"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('a4faad47-3ead-4737-bd8a-70ad3d7fdb03', '06056d9c-039c-4b17-b58d-01c7fc26f102', 'fillup', 'Questions 14-16', '<p>Label the diagram below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p><img decoding="async" src="data:image/png;base64," /></p>
<p><span class="fill-history-correct">{chain}</span></p>
<p><span class="fill-history-correct">{gear}</span></p>
<p><span class="fill-history-correct">{motor}</span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">14.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>chain</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “The traditional lifting mechanism is a long length of <strong>chain</strong> running up the hill under the track.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Cơ chế nâng truyền thống là một đoạn <strong>dây xích</strong> (<em>chain</em>) chạy dọc theo đồi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">15.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>gear</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “The chain is fastened in a loop, which is wound around a <strong>gear</strong> at the top of the hill and another one at the bottom of the hill.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Dây xích được quấn quanh một <strong>bánh răng</strong> (<em>gear</em>) ở cả đỉnh và đáy đồi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">16.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>motor</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “The gear at the bottom of the hill is turned by a <strong>motor</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Bánh răng ở phía dưới được vận hành bằng một <strong>động cơ</strong> (<em>motor</em>).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('8be3a833-2742-4595-aa65-b4a38dd2759a', '97c9c63c-ba86-4d8a-9621-d77946b037ab', 'radio', 'Questions 27-30', '', '<p>Choose the correct letter <strong>A</strong>,<strong>B</strong>, <strong>C </strong>or <strong>D</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": " who is aware of being set apart from other people."}, {"option_text": "whose brain structure is unlike that of other people."}, {"option_text": "who can perform extremely well in early childhood."}, {"option_text": "whose essential skills are more varied than those of ordinary people."}], "question": "In the first paragraph, the writer suggests that a musician who is ‘talented’ is someone"}, {"correct": 2, "options": [{"option_text": "Which part of the brain is linked to a particular musical skill,"}, {"option_text": " Which type of musical skill leads to the greatest change in the brain"}, {"option_text": "Whether a feature of the brain is a cause or an effect of a musical skill"}, {"option_text": "Whether the acquisition of a musical skill is easier for some people than others"}], "question": "According to the winter, what is unclear about the findings of Gottfried Schlaug?"}, {"correct": 0, "options": [{"option_text": "Changes may occur in the brain following violin practice."}, {"option_text": "Left-handed violinists have a different brain structure from other people."}, {"option_text": "A violinist’s hand size is not due to practice but to genetic factors."}, {"option_text": "Violinists are born with brains that have a particular structure."}], "question": "According to the writer, what has been established by studies of violin players?"}, {"correct": 0, "options": [{"option_text": "talent may have little to do with expertise."}, {"option_text": "practice may actually prevent the development of talent."}, {"option_text": " talent may not be recognised by teachers."}, {"option_text": "expertise may be related to quality of instruction. "}], "question": "According to the writer, findings on the amount of practice done by expert musicians suggest that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. In the first paragraph, the writer suggests that a musician who is ‘talented’ is someone — {C} who can perform extremely well in early childhood.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The emphasis on <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"28\">early identification</strong> means that to investigate it, we study the <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"92\">development of skills in children</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Định nghĩa về tài năng trong bài nhấn mạnh vào việc nhận diện sớm ở trẻ em trước khi đạt trình độ xuất sắc, tức là có biểu hiện vượt trội ngay từ nhỏ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. According to the writer, what is unclear about the findings of Gottfried Schlaug? — {C} Whether a feature of the brain is a cause or an effect of a musical skill.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…it’s <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">not clear if it starts out larger</strong> in people who eventually acquire AP, or if the <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"101\">acquisition of AP makes the planum increase in size</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu thấy vùng <em data-path-to-node=\"6,1,0\" data-index-in-node=\"33\">planum temporale</em> lớn hơn ở người có cao độ tuyệt đối (AP), nhưng không rõ đó là do bẩm sinh (nguyên nhân – cause) hay do luyện tập mà thành (kết quả – effect).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. According to the writer, what has been established by studies of violin players? — {A} Changes may occur in the brain following violin practice.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the region of the brain… <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"42\">increases in size as a result of practice</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu khẳng định vùng não điều khiển tay trái của người chơi violin to lên nhờ quá trình luyện tập.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. According to the writer, findings on the amount of practice done by expert musicians suggest that — {A} talent may have little to do with expertise.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…students who achieved the highest performance ratings had practiced the most, <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"93\">irrespective of which ‘talent’ group</strong> they had been assigned to…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả cho thấy những người giỏi nhất là những người tập nhiều nhất, bất kể ban đầu họ được đánh giá là có “tài năng” hay không. Điều này ngụ ý tài năng ít có mối liên hệ với trình độ chuyên gia so với nỗ lực.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d09269c2-63b2-4029-8ad0-f56b431e41ee', '97c9c63c-ba86-4d8a-9621-d77946b037ab', 'radio', 'Question 31-36', '', '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, <strong>NO </strong>if the statement contradicts the claims of the writer, <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Anders Ericsson''s work with cognitive psychology has influenced other researchers."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Different areas of expertise seem to have one specific thing in common."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": " In order to be useful, practice must be carried out regularly every day."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Anyone who practices for long enough can reach the level of a world-class expert."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Occasionally, someone can become an expert at global level with fewer than 10,000 hours’ practice."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Existing knowledge of learning and cognitive skills supports the importance of practice."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">31. Anders Ericsson’s work… has influenced other researchers. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nhắc đến lý thuyết và cách tiếp cận của Ericsson, nhưng <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"76\">không đề cập</strong> đến việc ông có ảnh hưởng đến các nhà nghiên cứu khác hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. Different areas of expertise seem to have one specific thing in common. — {YES}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…ten thousand hours of practice is required to achieve the level of mastery… in <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"96\">anything</strong>.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Điểm chung duy nhất của mọi lĩnh vực chuyên gia (cờ vua, thể thao, âm nhạc…) chính là con số 10.000 giờ luyện tập.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. In order to be useful, practice must be carried out regularly every day. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…roughly 20 hours a week for ten years.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đưa ra con số trung bình theo tuần, nhưng <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"62\">không bắt buộc</strong> là phải tập luyện đều đặn “mọi ngày” (every day).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Anyone who practices for long enough can reach the level of a world-class expert. — {NO}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…this does not address why <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"41\">some people do not seem to get anywhere when they practice</strong>…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả thừa nhận có những người tập mãi mà không đi đến đâu, nên việc nói “bất cứ ai” (anyone) tập đủ lâu cũng thành chuyên gia là sai so với quan điểm bài viết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. Occasionally, someone can become an expert… with fewer than 10,000 hours’ practice. — {NO}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “But <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"16\">no-one has yet found a case</strong> in which true world-class expertise was accomplished in less time.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chưa có trường hợp nào được tìm thấy mà thành chuyên gia thế giới với ít thời gian hơn 10.000 giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">36. Existing knowledge of learning and cognitive skills supports the importance of practice. — {YES}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The ten-thousand-hour theory is <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"44\">consistent with what we know about how the brain learns</strong>.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý thuyết này nhất quán (consistent) với những hiểu biết hiện tại về cách não bộ học tập.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c4230120-ffbe-487d-a8c6-234320c1289d', '06056d9c-039c-4b17-b58d-01c7fc26f102', 'fillup', 'Questions 17–21', '<div class="quests-inner-desc">
<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>History of roller coasters</strong></p>
<p>Modern roller coasters are descended from 16th-century Russian slides with a surface of {ice} .</p>
<p>People climbed to the top, and travelled down in sleds. In France, because of the higher temperatures, the wooden surface on the slides was {waxed} and {wheels} were attached to the cars to ease the descent.</p>
<p>The first US roller coaster was used for transporting {coal} down a mountainside in carts. Initially, these were pulled by mules but in time power was produced by {steam engines}</p>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"5\">17. Modern roller coasters are descended from 16th-century Russian slides with a surface of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>ice</strong>.</h3>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>ice</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “Their direct ancestors were ice slides, popular in Russia in the 16th and 17th centuries. They consisted of a long, steep, wooden slide covered in <strong>ice</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Tổ tiên trực tiếp của tàu lượn siêu tốc là các máng trượt Nga có bề mặt được bao phủ bằng <strong>băng</strong> (<em>ice</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">18. In France, because of the higher temperatures; the wooden surface on the slides was <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>waxed</strong>…</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>waxed</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “For most of the year, the warmer climate would melt the ice, so the French started building <strong>waxed slides</strong> instead.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Do khí hậu ấm hơn, người Pháp đã phải thay máng trượt bằng băng bằng máng trượt bằng gỗ được <strong>đánh bóng</strong> (<em>waxed</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">19. …and <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>wheels</strong> were attached to the cars to ease the descent.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>wheels</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “To help the sleds move down these slides, they added <strong>wheels</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Để giúp xe trượt di chuyển dễ dàng hơn trên máng trượt đã được đánh bóng, họ đã thêm <strong>bánh xe</strong> (<em>wheels</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">20. The first US roller coaster was used for transporting <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>coal</strong> down a mountainside in carts.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>coal</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “The first American roller coaster was built in the mountains of Pennsylvania… originally to provide an easy way to send <strong>coal</strong> to the railway 29 km down to mountain.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Tàu lượn siêu tốc đầu tiên ở Mỹ ban đầu được dùng để vận chuyển <strong>than đá</strong> (<em>coal</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">21. Initially, these were pulled by mules but in time power was produced by <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>steam engines</strong>.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>steam engines</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “They were eventually replaced with <strong>steam engines</strong>, to make the system more efficient.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Ban đầu dùng la (<em>mules</em>), sau đó chúng được thay thế bằng <strong>động cơ hơi nước</strong> (<em>steam engines</em>) để hệ thống hoạt động hiệu quả hơn.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('bcdbeced-ac4c-4b5c-a791-5668258ceafd', '6d63f38f-87b7-4ae6-8a4a-56e7dacb7927', 'radio', 'Questions 11–12', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. 5.30 a.m"}, {"option_text": "B. 6.30 a.m"}, {"option_text": "C. 7.30 a.m"}], "question": "Joan normally gets up at"}, {"correct": 1, "options": [{"option_text": "A. clean the horses."}, {"option_text": "B. organise her son."}, {"option_text": "C. do farm work."}], "question": "Joan’s first task of the day is to"}]', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a radio talk on horse riding for disabled people. First you have some time to look at questions 11 to 14 on page three. Now listen carefully and answer questions 11 to fourteen.</p>\n<p><strong>Radio Host:</strong> This week our slot is ‘A life in the day of Joan Gilbert’, local organiser for Riding for the Disabled. Joan, would you like to tell us about this?</p>\n<p><strong>Joan:</strong> Well, I always have the very best intentions of starting the day at 5:30 to give the horses a really good muck out. But reality intervenes and I finally wake at about <strong><span style=\"background-color: #f1c40f;\">(Question 11) 6:30 a.m</span>.</strong> That probably still sounds very early to you, but for a farm worker, which is what my son is at the moment, that’s cutting things pretty fine.</p>\n<p>Once I’ve managed to get<span style=\"background-color: #f1c40f;\"> <strong>(Question 12) him safely on his way</strong></span> at about 7:00 am, I can start turning my attention to the other important tasks of the day. For about five years, we’ve been taking overseas students from the International Centre at our local college, and I have to give them a proper breakfast. Most of our students used to be from the Middle East, but they’re no longer coming, so we tend to have Malaysian girls, and they like to have a cooked breakfast much more than any Europeans we’ve had, including me, and I don’t have anything these days.</p>\n<p>After cooking, I finally get round to the poor horses. It’s only after this that I can start thinking about what I regard as my most important task—work for Riding for the Disabled.</p>\n<p>I’ve been involved with this organisation on and off for over 20 years, but I’ve only recently taken on the job of <strong>chairperson</strong>. Most of the work seems more secretarial, but that’s how charities get organized. In our immediate district, we have had as many as 30 riders, but currently we’ve only got <span style=\"background-color: #f1c40f;\"><strong>(Question 13) 22</strong> </span>riders. The number of helpers who have volunteered is actually <span style=\"background-color: #f1c40f;\"><strong>(Question 13) 40</strong></span>, but we can rely on <span style=\"background-color: #f1c40f;\"><strong>(Question 14) 25</strong></span> to come regularly to help in the different groups. We now have four separate groups, which cater for disabled children and adults from six to 40 years old.</p>\n<hr>\n<p><strong>Narrator:</strong> Before you hear the rest of the talk, you have some time to look at questions 15 to 20 on page four. Now listen and answer questions 15 to twenty.</p>\n<p><strong>Joan:</strong> As I say, I feel that although I no longer have any proper full time paid employment, I do have a full and busy life. I’m a housewife which I don’t mind, because I don’t really object to doing things like washing and cooking. Then there’s my own horses, which I adore, even the revolting stuff like cleaning out the stables.</p>\n<p>The official RDA stuff is a mixed bag really. I don’t have major problems with all the letter writing and <span style=\"background-color: #f1c40f;\"><strong>(Question 15) correspondence (B)</strong></span> which it entails, but like lots of shy people, I find the <span style=\"background-color: #f1c40f;\"><strong>(Question 16) fundraising (C)</strong></span> horrendous. Other regular RDA duties such as<span style=\"background-color: #f1c40f;\"> <strong>(Question 17) ringing round the riders (A)</strong></span> to fix times etcetera is one of the pleasantest aspects of the work. After all, that’s why I’m involved with charity work, the contact with people. My working day ends with the least enjoyable job of all—sorting the <span style=\"background-color: #f1c40f;\"><strong>(Question 18) accounts (C)</strong>.</span></p>\n<p>I got involved with RDA because I’ve always loved horses and I can see disabled people gaining so much. I know all the medical evidence that shows that it does wonders for muscle building and so on, which is important. But from talking to the riders, they say it is the confidence they gain and also the opportunity to be part of a new and exciting environment which gives them the greatest benefit.</p>\n<p>In terms of the RDA organization itself, I feel it works very well, but we’re always striving to make it better. I wish for example, our helpers and the organizers in the various centres could really rationalize the<span style=\"background-color: #f1c40f;\"> <strong>(Question 19) fundraising efforts (B)</strong></span>, which sometimes are very inefficient. And it also saddens me how unaware some of the stables can be about the <span style=\"background-color: #f1c40f;\"><strong>(Question 20) difficulties faced by people who are disabled (E)</strong>.</span></p>\n<p>Anyway, I feel very privileged to work with our riders and to see such tangible benefits. It sends me to sleep with a feeling that though the day has been hard it has been worthwhile.</p>\n<p><strong>Narrator:</strong> That is the end of Section 2. You now have half a minute to check your answers to part two.</p>"}]', 0);
INSERT INTO public.questions VALUES ('d6f9c259-1181-49e2-9840-9711a3d12e13', '6d63f38f-87b7-4ae6-8a4a-56e7dacb7927', 'fillup', 'Questions 13–14', '<p>Complete the summary below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER </strong>for each answer.</p>
<p>Joan’s official title in Riding for the Disabled (RDA) is chairperson. In her local district there are at present twenty-two riders and {40} helpers on the volunteer list, out of whom {25} come regularly.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a radio talk on horse riding for disabled people. First you have some time to look at questions 11 to 14 on page three. Now listen carefully and answer questions 11 to fourteen.</p>\n<p><strong>Radio Host:</strong> This week our slot is ‘A life in the day of Joan Gilbert’, local organiser for Riding for the Disabled. Joan, would you like to tell us about this?</p>\n<p><strong>Joan:</strong> Well, I always have the very best intentions of starting the day at 5:30 to give the horses a really good muck out. But reality intervenes and I finally wake at about <strong>(Question 11) 6:30 a.m.</strong> That probably still sounds very early to you, but for a farm worker, which is what my son is at the moment, that’s cutting things pretty fine.</p>\n<p>Once I’ve managed to get <strong>(Question 12) him safely on his way</strong> at about 7:00 am, I can start turning my attention to the other important tasks of the day. For about five years, we’ve been taking overseas students from the International Centre at our local college, and I have to give them a proper breakfast. Most of our students used to be from the Middle East, but they’re no longer coming, so we tend to have Malaysian girls, and they like to have a cooked breakfast much more than any Europeans we’ve had, including me, and I don’t have anything these days.</p>\n<p>After cooking, I finally get round to the poor horses. It’s only after this that I can start thinking about what I regard as my most important task—work for Riding for the Disabled.</p>\n<p>I’ve been involved with this organisation on and off for over 20 years, but I’ve only recently taken on the job of <strong>chairperson</strong>. Most of the work seems more secretarial, but that’s how charities get organized. In our immediate district, we have had as many as 30 riders, but currently we’ve only got <strong>(Question 13) 22</strong> riders. The number of helpers who have volunteered is actually <strong>(Question 13) 40</strong>, but we can rely on <strong>(Question 14) 25</strong> to come regularly to help in the different groups. We now have four separate groups, which cater for disabled children and adults from six to 40 years old.</p>\n<hr>\n<p><strong>Narrator:</strong> Before you hear the rest of the talk, you have some time to look at questions 15 to 20 on page four. Now listen and answer questions 15 to twenty.</p>\n<p><strong>Joan:</strong> As I say, I feel that although I no longer have any proper full time paid employment, I do have a full and busy life. I’m a housewife which I don’t mind, because I don’t really object to doing things like washing and cooking. Then there’s my own horses, which I adore, even the revolting stuff like cleaning out the stables.</p>\n<p>The official RDA stuff is a mixed bag really. I don’t have major problems with all the letter writing and <strong>(Question 15) correspondence (B)</strong> which it entails, but like lots of shy people, I find the <strong>(Question 16) fundraising (C)</strong> horrendous. Other regular RDA duties such as <strong>(Question 17) ringing round the riders (A)</strong> to fix times etcetera is one of the pleasantest aspects of the work. After all, that’s why I’m involved with charity work, the contact with people. My working day ends with the least enjoyable job of all—sorting the <strong>(Question 18) accounts (C)</strong>.</p>\n<p>I got involved with RDA because I’ve always loved horses and I can see disabled people gaining so much. I know all the medical evidence that shows that it does wonders for muscle building and so on, which is important. But from talking to the riders, they say it is the confidence they gain and also the opportunity to be part of a new and exciting environment which gives them the greatest benefit.</p>\n<p>In terms of the RDA organization itself, I feel it works very well, but we’re always striving to make it better. I wish for example, our helpers and the organizers in the various centres could really rationalize the <strong>(Question 19) fundraising efforts (B)</strong>, which sometimes are very inefficient. And it also saddens me how unaware some of the stables can be about the <strong>(Question 20) difficulties faced by people who are disabled (E)</strong>.</p>\n<p>Anyway, I feel very privileged to work with our riders and to see such tangible benefits. It sends me to sleep with a feeling that though the day has been hard it has been worthwhile.</p>\n<p><strong>Narrator:</strong> That is the end of Section 2. You now have half a minute to check your answers to part two.</p>"}]', 1);
INSERT INTO public.questions VALUES ('d23cd344-d79e-4254-bf68-1387465ed96d', '06056d9c-039c-4b17-b58d-01c7fc26f102', 'radio', 'Questions 22–26', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The earliest modifications to the basic slide were made in France."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Roller coasters continued to increase in popularity throughout the 1920s and 1930s."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "New roller coaster technology was introduced in the 1970s in response to public demand."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Roller coasters were less popular for most of the 1980s than in the 1970s and 1990s."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The design of roller-coaster rides became more varied in the 1990s."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"26\">22. The earliest modifications to the basic slide were made in France.</h3>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “It seems that the idea was then imported into France. For most of the year, the warmer climate would melt the ice, so the French started building waxed slides instead. <strong>To help the sleds move down these slides, they added wheels</strong>, and in 1817, for the first time, a train was attached to the track.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Việc người Pháp thêm <strong>bánh xe</strong> (<em>wheels</em>) và gắn tàu hỏa vào đường ray là những <strong>sự sửa đổi</strong> (<em>modifications</em>) đầu tiên được thực hiện sau khi ý tưởng được nhập khẩu từ Nga.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"28\">23. Roller coasters continued to increase in popularity throughout the 1920s and 1930s.</h3>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “By the 1920s, roller coasters were in full swing… <strong>Following the Great Depression, a decline in roller coaster production began in the early 1930s</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong>Giải thích:</strong> Sau Đại suy thoái, một sự <strong>suy giảm</strong> (<em>decline</em>) trong sản xuất tàu lượn siêu tốc đã bắt đầu vào đầu những năm 1930, mâu thuẫn với việc tiếp tục <strong>gia tăng</strong> (<em>increase in popularity</em>) trong suốt những năm 1930.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"30\">24. New roller coaster technology was introduced in the 1970s in response to public demand.</h3>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “…a second roller-coaster boom in the 1970s and the beginning of the 1980s revitalized the amusement park industry, and <strong>introduced a slew of innovative tubular steel coasters</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong>Giải thích:</strong> Bài đọc xác nhận công nghệ mới (tàu lượn thép ống) đã được giới thiệu trong thời kỳ bùng nổ thứ hai vào những năm 1970, nhưng <strong>không nói rõ</strong> liệu sự đổi mới này có phải là <strong>phản ứng trực tiếp trước nhu cầu công chúng</strong> (<em>in response to public demand</em>) hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"32\">25. Roller coasters were less popular for most of the 1980s than in the 1970s and 1990s.</h3>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J-K) Có sự bùng nổ vào <strong>những năm 1970</strong> và đầu 1980 (Đoạn J). Sau đó, điều này “was followed by a <strong>decline in interest for the rest of the decade</strong>” (tức là phần lớn những năm <strong>1980</strong> còn lại) (Đoạn K). Sau đó, “since the <strong>early 1990s</strong> the amusement-park industry has experienced another coaster boom.” (Đoạn K).</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong>Giải thích:</strong> Mức độ phổ biến <strong>suy giảm</strong> (<em>decline in interest</em>) trong phần lớn những năm 1980, nằm giữa hai giai đoạn <strong>bùng nổ</strong> (<em>boom</em>) vào cuối thập niên 70/đầu 80 và đầu thập niên 90.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"34\">26. The design of roller-coaster rides became more varied in the 1990s.</h3>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong>Dẫn chứng:</strong> (Đoạn K) “since the early 1990s the amusement-park industry has experienced another coaster boom of sorts. New launching techniques and other technological developments have <strong>opened up a world of options for designers</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong>Giải thích:</strong> Sự phát triển công nghệ đã <strong>mở ra một thế giới các lựa chọn</strong> (<em>opened up a world of options</em>) cho các nhà thiết kế, điều này đồng nghĩa với việc thiết kế tàu lượn trở nên <strong>đa dạng hơn</strong> (<em>more varied</em>) trong những năm 1990.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('cd784fc5-9ef3-43bd-a267-51607206ff8d', '97c9c63c-ba86-4d8a-9621-d77946b037ab', 'matching', 'Question 37-40', '', '<p>Complete the summary using the list of words, <strong>A-J</strong> below</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong>Mozart</strong></span></p>\n<p>The case of Mozart could be quoted as evidence against the 10,000-hour-practice theory. However, the writer points out that the young Mozart received a lot of {tuition} from his father, and that the symphony he wrote at the age of {eight} was not {popular} and may be of only academic interest. The case therefore supports the view that expertise is not solely the result of {inherited} characteristics.</p>", "answerOptions": [{"optionText": "popular"}, {"optionText": "artistic"}, {"optionText": "completed"}, {"optionText": "eight"}, {"optionText": "tuition"}, {"optionText": "encouragement"}, {"optionText": "inherited"}, {"optionText": "four "}, {"optionText": "practice"}, {"optionText": "two"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. Mozart received a lot of {tuition} from his father.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…Mozart had an <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"29\">expert teacher</strong> in his father…” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> <em data-path-to-node=\"28,1,0\" data-index-in-node=\"12\">Tuition</em> (sự giảng dạy) tương ứng với việc có một người thầy giỏi dạy dỗ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. …the symphony he wrote at the age of {eight}…</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Mozart did not write it until he was <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"49\">eight</strong>…” (Đoạn cuối)</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. …was not {popular} and may be of only academic interest.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…this early work <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"31\">received little acclaim and was not performed very often</strong>.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Little acclaim” (ít được hoan nghênh) đồng nghĩa với việc nó không hề phổ biến hay nổi tiếng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. …expertise is not solely the result of {inherited} characteristics.</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…inborn traits may not be the only cause.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Inherited characteristics” (đặc điểm di truyền) tương ứng với “inborn traits” (phẩm chất bẩm sinh).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('89bbc174-8837-4979-9eba-c4a3e764b9a0', '15c31f20-895e-4493-a9d3-344c2ee4c757', 'matrix', 'Questions 14–17', NULL, '<p>Reading Passage 2 has nine paragraphs, A-I.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter, A-I, in boxes 14-17.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "the suggestion that people may need to adapt to a different quality of meat", "correctCategoryLetter": "E"}, {"itemText": "a description of the way animals fed in the past", "correctCategoryLetter": "D"}, {"itemText": "a prediction in regard to human demand for meat", "correctCategoryLetter": "H"}, {"itemText": "the potential consequences of a meat-free", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p data-path-to-node=\"3\">14. The suggestion that people may need to adapt to a different quality of meat</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án: E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Cuối đoạn E) “…it would require a <strong>major adjustment in food preferences</strong>; people would have to get used to chicken, for example, <strong>with less fat</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Đoạn E đề cập rằng nếu chúng ta nuôi gia súc bằng thức ăn thừa, con người sẽ phải điều chỉnh sở thích ăn uống (<em>adjustment in food preferences</em>), cụ thể là phải làm quen với loại thịt có chất lượng khác (ví dụ: thịt gà <strong>ít mỡ hơn</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">15. A description of the way animals were fed in the past</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án: D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “<strong>For most of human history</strong>, livestock <strong>grazed on land</strong> that wasn’t suitable for ploughing, and in doing so they <strong>converted inedible grass</strong> into edible meat and milk.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Cụm từ “For most of human history” chỉ về <strong>quá khứ</strong> (<em>in the past</em>). Đoạn văn mô tả cách chăn nuôi truyền thống là cho gia súc gặm cỏ trên những vùng đất không thể trồng trọt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">16. A prediction in regard to human demand for meat</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án: H</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “The United Nations’ best guess is that <strong>by 2050, the world will need to more than double its production of meat</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Đây là một <strong>dự đoán</strong> (<em>prediction</em>) về tương lai (năm 2050), khẳng định rằng nhu cầu và sản lượng thịt của con người sẽ tăng gấp đôi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">17. The potential consequences of a meat-free world</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án: F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “<strong>Another downside to a meat-free world</strong> would be the <strong>disappearance of animal by-products</strong>… replace the 11 million tonnes of leather and 2 million tonnes of wool…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Đoạn F thảo luận về các <strong>hệ quả tiềm tàng</strong> (<em>potential consequences</em>) nếu thế giới không ăn thịt, bao gồm sự biến mất của các phụ phẩm như da và len, cũng như tác động tiêu cực đến thu nhập của người nghèo.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('03ecbb9b-22dc-4fae-b280-e7976b54f326', '15c31f20-895e-4493-a9d3-344c2ee4c757', 'fillup', 'Questions 18–22', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>How does agriculture damage the environment?</strong></p>
<p>Agriculture causes significant harm to the environment in a number of ways, including the frequent use of {irrigation} in modern farming and the cutting down of trees. It is also responsible for the production of many greenhouse gases, more so than {transport} is. However, it is livestock farming in particular that is most harmful, because cows, chickens and sheep, for example, are given vast quantities of grain which could be consumed by people instead. A meat-free diet would mean that actually less {land} could be used for crops. Far less chemical pollution, specifically in the form of {nitrogen} would also be released into the environment, especially if consumers cut out dairy and egg products as well as meat. In the US, there is clear evidence that considerable {erosion} is caused by the demand for grazing land, although there is no information on this from other countries.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\">18. …including the frequent use of {irrigation} in modern farming…</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>irrigation</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Vị trí:</strong> <strong>Đoạn B (Dòng 1-2)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Dẫn chứng:</strong> “Take for example the felled forests and the <strong>common use of irrigation systems</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,3,0\"><strong>Giải thích:</strong> Bài đọc nêu hai ví dụ về tác hại của nông nghiệp: phá rừng và việc sử dụng phổ biến các hệ thống <strong>tưới tiêu</strong> (<em>irrigation</em>). Từ “frequent use” trong tóm tắt đồng nghĩa với “common use” trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">19. It is also responsible for the production of many greenhouse gases, more so than {transport} is.</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>transport</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Vị trí:</strong> <strong>Đoạn B (Dòng 3-4)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Dẫn chứng:</strong> “…agriculture creates more greenhouse gases than all methods of <strong>transport</strong> put together.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong>Giải thích:</strong> Tác giả so sánh lượng khí thải nhà kính từ nông nghiệp với tất cả các phương thức <strong>giao thông vận tải</strong> (<em>transport</em>), và khẳng định nông nghiệp gây ra nhiều khí thải hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">20. A meat-free diet would mean that actually less {land} could be used for crops.</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>land</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Vị trí:</strong> <strong>Đoạn B (2 dòng cuối)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Dẫn chứng:</strong> “…if we switched to a vegan diet… the <strong>land</strong> currently required for crops would drop by an estimated 21 per cent…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,0\"><strong>Giải thích:</strong> Nếu thế giới ngừng ăn thịt, diện tích <strong>đất</strong> (<em>land</em>) cần thiết để trồng trọt sẽ giảm đi đáng kể (khoảng 21%) vì không còn phải trồng ngũ cốc để nuôi gia súc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">21. Far less chemical pollution, specifically in the form of {nitrogen} would also be released…</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>nitrogen</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Vị trí:</strong> <strong>Đoạn C (Dòng 1-2)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Dẫn chứng:</strong> “One environmental impact… would be that of the <strong>nitrogen</strong> emitted from agricultural processes, which spreads into both waterways and land.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,3,0\"><strong>Giải thích:</strong> Bài đọc đề cập đến một loại ô nhiễm hóa học cụ thể là khí <strong>nitơ</strong> (<em>nitrogen</em>) phát thải từ các quá trình nông nghiệp. Lượng ô nhiễm này sẽ giảm đi nếu giảm chăn nuôi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\">22. In the US, there is clear evidence that considerable {erosion} is caused by the demand for grazing land…</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>erosion</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Vị trí:</strong> <strong>Đoạn C (Dòng 5-6)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Dẫn chứng:</strong> “…in the US at least, livestock account for 55% of <strong>erosion</strong>, mostly from forests being cut down to make way for grazing land.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,3,0\"><strong>Giải thích:</strong> Tại Mỹ, việc chăn nuôi gia súc chiếm tới 55% nguyên nhân gây ra sự <strong>xói mòn</strong> (<em>erosion</em>), chủ yếu do việc phá rừng để lấy đất chăn thả.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2fff3f0b-5064-4f00-b6e2-2ab8f6ec9506', '6c445955-24cb-4b09-a2cf-7fa6cedaf0e1', 'radio', 'Questions 7–13', NULL, '<p><span style="font-family: arial, helvetica, sans-serif;"><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">Choose </span><strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">TRUE</span></strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;"> if the statement agrees with the information given in the text, choose </span><strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">FALSE</span></strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;"> if the statement contradicts the information, or choose </span><strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;">NOT GIVEN</span></strong><span style="font-size: 12pt; color: black; border: 1pt none windowtext; padding: 0cm; background: white;"> if there is no information on this.</span></span></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Bisque dolls appear less realistic than dolls made of china."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "French dolls tended to cost more than German bisque dolls."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The first rag dolls were made in the 1850s."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Only dolls made of cotton or linen are classified as cloth dolls. "}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Dolls made of celluloid tended to lose their colour."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Composition dolls lasted longer than the plastic dolls that were made in the 1940s."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Doll collectors prefer a doll to be dressed in its original clothing."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>7. Bisque dolls appear less realistic than dolls made of china.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “Bisque, which is porcelain fired twice with colour added to it after the first firing, <strong>looked more like skin than china did</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Bisque trông giống da người hơn (more like skin) so với china, tức là <strong>thực tế hơn</strong>, mâu thuẫn với nhận định “less realistic” (kém thực tế hơn).</p>\n</li>\n</ul>\n<p>8. French dolls tended to cost more than German bisque dolls.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “Although the French dolls were <strong>unrivalled in their artistry</strong>, German bisque dolls became quite popular because <strong>they were not as expensive</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong>Giải thích:</strong> Nếu búp bê Đức (bisque dolls) phổ biến vì chúng rẻ hơn (not as expensive), điều đó có nghĩa là búp bê Pháp (French dolls) <strong>đắt hơn</strong> (cost more).</p>\n</li>\n</ul>\n<p>9. The first rag dolls were made in the 1850s.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “<strong>For many centuries, rag dolls were made by mothers for their children</strong>… <strong>Commercially produced rag dolls were first introduced in the 1850s</strong> by English and American manufacturers.”</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Búp bê vải (rag dolls) đã tồn tại hàng thế kỷ (made by mothers); chỉ có búp bê vải được <strong>sản xuất thương mại</strong> (Commercially produced) mới bắt đầu vào những năm 1850.</p>\n</li>\n</ul>\n<p>10. Only dolls made of cotton or linen are classified as cloth dolls.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “The term ‘rag doll’ refers generically to dolls made of any fabric. <strong>‘Cloth doll’ refers to a subset of rag dolls made of linen or cotton</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Định nghĩa rõ ràng rằng “cloth doll” là tập hợp con của rag dolls, được làm bằng linen <strong>hoặc</strong> cotton.</p>\n</li>\n</ul>\n<p>11. Dolls made of celluloid tended to lose their colour.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “However, celluloid fell out of favour because of its extreme flammability and <strong>propensity to fade in bright light</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong>Giải thích:</strong> “Propensity to fade” (khuynh hướng phai màu) đồng nghĩa với việc mất màu (lose their colour).</p>\n</li>\n</ul>\n<p>12. Composition dolls lasted longer than the plastic dolls that were made in the 1940s.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn K) “Hard plastic dolls were manufactured in the 1940s… They resembled composition dolls, but they were <strong>much more durable</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Búp bê nhựa cứng (plastic dolls) bền hơn (more durable) búp bê composition, mâu thuẫn với nhận định composition dolls bền hơn.</p>\n</li>\n</ul>\n<p>13. Doll collectors prefer a doll to be dressed in its original clothing.</p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Giải thích:</strong> Văn bản mô tả lịch sử các loại búp bê, vật liệu, và sự phổ biến của chúng, nhưng <strong>không có thông tin</strong> về sở thích của nhà sưu tầm đối với quần áo gốc của búp bê.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2b92bb59-a86d-475d-bf20-609ed60544b3', '15c31f20-895e-4493-a9d3-344c2ee4c757', 'matrix', 'Questions 23–26', NULL, '<p>Look at the following statements and the list of people below.</p>
<p>Match each statement with the correct person, A-E.</p>
<p>Choose the correct letter, A-E, in boxes 23-26.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": " It is not possible to say that a vegetarian diet is right for everyone.", "correctCategoryLetter": "C"}, {"itemText": " It may be economically preferable to farm animals in limited space.", "correctCategoryLetter": "E"}, {"itemText": " It does not make sense to give up meat without giving up dairy products too.", "correctCategoryLetter": "D"}, {"itemText": " Some animals can be fed in a way that allows waste to be recycled.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Allison Leach", "categoryLetter": "A"}, {"categoryText": "Tara Garnett", "categoryLetter": "B"}, {"categoryText": "Annette Pinner", "categoryLetter": "C"}, {"categoryText": "Helmut Haberl", "categoryLetter": "D"}, {"categoryText": "Walter Falcon", "categoryLetter": "E"}]}', '[{"content": "<h3 data-path-to-node=\"4\">23. It is not possible to say that a vegetarian diet is right for everyone.</h3>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án: C (Annette Pinner)</strong></li>\n<li><strong>Vị trí:</strong> Đoạn F (Dòng 4-6).</li>\n<li><strong>Dẫn chứng:</strong> “…we do have to be <strong>careful about saying it would be the best solution</strong> if the whole world went vegetarian,’ says <strong>Annette Pinner</strong>…”</li>\n<li><strong>Giải thích:</strong> Annette Pinner (Giám đốc điều hành Hiệp hội Ăn chay Anh) khuyên nên thận trọng khi khẳng định ăn chay là giải pháp tốt nhất cho tất cả mọi người, vì động vật rất quan trọng đối với thu nhập và dinh dưỡng của người nghèo.</li>\n</ul>\n<h3 data-path-to-node=\"6\">24. It may be economically preferable to farm animals in limited space.</h3>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án: E (Walter Falcon)</strong></li>\n<li><strong>Vị trí:</strong> Đoạn I (Dòng 2-4).</li>\n<li><strong>Dẫn chứng:</strong> “‘If you’re going to keep some livestock systems, I think the ones you’ll want to keep are the <strong>intensive ones</strong>,’ he [<strong>Walter Falcon</strong>] says.”</li>\n<li><strong>Giải thích:</strong> Chăn nuôi thâm canh (<em>intensive farming</em>) chính là hình thức nuôi gia súc trong không gian hạn chế (<em>limited space</em>) để tối ưu hóa năng suất. Walter Falcon cho rằng đây là hệ thống nên được duy trì để có chi phí môi trường thấp nhất.</li>\n</ul>\n<h3 data-path-to-node=\"8\">25. It does not make sense to give up meat without giving up dairy products too.</h3>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án: D (Helmut Haberl)</strong></li>\n<li><strong>Vị trí:</strong> Đoạn G (Dòng 3-6).</li>\n<li><strong>Dẫn chứng:</strong> “Dairy cows must calve every year to keep producing milk… while many vegetarians see moral reasons not to kill and eat the males, there is surely <strong>no practical reason to waste so much meat</strong>.”</li>\n<li><strong>Giải thích:</strong> Helmut Haberl lập luận rằng nếu vẫn dùng sữa (<em>dairy</em>) thì vẫn sẽ có những con bê đực được sinh ra. Nếu không ăn thịt chúng thì sẽ rất lãng phí. Do đó, việc bỏ thịt mà vẫn giữ sữa là không thực tế (<em>no practical reason</em>).</li>\n</ul>\n<h3 data-path-to-node=\"10\">26. Some animals can be fed in a way that allows waste to be recycled.</h3>\n<ul data-path-to-node=\"11\">\n<li><strong>Đáp án: B (Tara Garnett)</strong></li>\n<li><strong>Vị trí:</strong> Đoạn E (Dòng 3-5).</li>\n<li><strong>Dẫn chứng:</strong> “<strong>Tara Garnett</strong>… points out the usefulness of these animals. By giving them your <strong>leftovers</strong>, she says, they <strong>deal with your rubbish</strong>, and you get meat.”</li>\n<li><strong>Giải thích:</strong> Tara Garnett giải thích rằng việc cho động vật ăn thức ăn thừa (<em>leftovers</em>) chính là một cách để xử lý rác thải (<em>deal with rubbish/waste</em>), giúp “tái chế” rác thành thực phẩm (thịt).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('e26e7e9d-42a2-4afd-98dc-f1b12a00bdc9', 'f0829761-df4d-4c14-a1be-2d2a5756f670', 'fillup', 'Questions 1–6', '<p data-start="167" data-end="246">Write <strong data-start="201" data-end="229">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p data-section-id="1ai3vh" data-start="253" data-end="276"><span style="font-size: 12pt;"><strong data-start="256" data-end="276">Local food shops</strong></span></p>
<p data-section-id="norpug" data-start="278" data-end="297"><strong data-start="282" data-end="297">Where to go</strong></p>
<ul data-start="298" data-end="342">
<li data-section-id="cxm6o3" data-start="298" data-end="342">
<p data-start="300" data-end="342">Kite Place – near the {harbour}</p>
</li>
</ul>
<p data-section-id="ugpm7q" data-start="344" data-end="363"><strong data-start="348" data-end="363">Fish market</strong></p>
<ul data-start="364" data-end="486">
<li data-section-id="iic26j" data-start="364" data-end="413">
<p data-start="366" data-end="413">cross the {bridge} and turn right</p>
</li>
<li data-section-id="m4d73l" data-start="414" data-end="486">
<p data-start="416" data-end="486">best to go before {3.30} pm, earlier than closing time</p>
</li>
</ul>
<p data-section-id="1wiap0d" data-start="488" data-end="508"><strong data-start="492" data-end="508">Organic shop</strong></p>
<ul data-start="509" data-end="645">
<li data-section-id="1hy9nj2" data-start="509" data-end="542">
<p data-start="511" data-end="542">called ‘{Rose}’</p>
</li>
<li data-section-id="u9u9if" data-start="543" data-end="593">
<p data-start="545" data-end="593">below a restaurant in the large, grey building</p>
</li>
<li data-section-id="1xhasr4" data-start="594" data-end="645">
<p data-start="596" data-end="645">look for the large {sign} outside</p>
</li>
</ul>
<p data-section-id="vsliwz" data-start="647" data-end="666"><strong data-start="651" data-end="666">Supermarket</strong></p>
<ul data-start="667" data-end="718">
<li data-section-id="1obg5bz" data-start="667" data-end="718">
<p data-start="669" data-end="718">take a {purple} minibus, number 289</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<blockquote>\n<p data-start=\"151\" data-end=\"691\"><strong data-start=\"151\" data-end=\"160\">LEON:</strong> Hi Shannon – how are you settling into your new flat?<br data-start=\"214\" data-end=\"217\"><strong data-start=\"217\" data-end=\"229\">SHANNON:</strong> Really well, thanks.<br data-start=\"250\" data-end=\"253\"><strong data-start=\"253\" data-end=\"262\">LEON:</strong> You look like you’re going shopping.<br data-start=\"299\" data-end=\"302\"><strong data-start=\"302\" data-end=\"314\">SHANNON:</strong> Yes, I am. My cousins are coming to stay for a couple of days, and I have to cook for them.<br data-start=\"406\" data-end=\"409\"><strong data-start=\"409\" data-end=\"418\">LEON:</strong> Well, there are plenty of places to buy food in Kite Place – it’s the area by the <span style=\"background-color: #f1c40f;\"><strong>(1) harbour</strong></span>.<br data-start=\"509\" data-end=\"512\"><strong data-start=\"512\" data-end=\"524\">SHANNON:</strong> Oh, OK, I’ll find that on the map. Thanks.<br data-start=\"567\" data-end=\"570\"><strong data-start=\"570\" data-end=\"579\">LEON:</strong> What sort of food do you need to get?<br data-start=\"617\" data-end=\"620\"><strong data-start=\"620\" data-end=\"632\">SHANNON:</strong> Well, neither of them eats meat but they both like fish.</p>\n<p data-start=\"698\" data-end=\"1220\"><strong data-start=\"698\" data-end=\"707\">LEON:</strong> Well, there’s a really good fish market there.<br data-start=\"754\" data-end=\"757\"><strong data-start=\"757\" data-end=\"769\">SHANNON:</strong> Oh great – where is it exactly?<br data-start=\"801\" data-end=\"804\"><strong data-start=\"804\" data-end=\"813\">LEON:</strong> It’s at the far end of Kite Place, so you have to go over the <strong><span style=\"background-color: #f1c40f;\">(2) bridge</span></strong> and then it’s on the right.<br data-start=\"910\" data-end=\"913\"><strong data-start=\"913\" data-end=\"925\">SHANNON:</strong> OK – is it open all day?<br data-start=\"950\" data-end=\"953\"><strong data-start=\"953\" data-end=\"962\">LEON:</strong> It doesn’t close until four, but I’d recommend going earlier than that – it does run out of some things.<br data-start=\"1067\" data-end=\"1070\"><strong data-start=\"1070\" data-end=\"1082\">SHANNON:</strong> Oh, I don’t want that to happen.<br data-start=\"1115\" data-end=\"1118\"><strong data-start=\"1118\" data-end=\"1127\">LEON:</strong> As long as you get there by <strong><span style=\"background-color: #f1c40f;\">(3) 3.30</span></strong>, you should be fine. It’s only 11 now, so plenty of time.</p>\n<p data-start=\"1227\" data-end=\"2338\"><strong data-start=\"1227\" data-end=\"1239\">SHANNON:</strong> Right.<br data-start=\"1246\" data-end=\"1249\"><strong data-start=\"1249\" data-end=\"1258\">LEON:</strong> Do you need to buy vegetables too?<br data-start=\"1293\" data-end=\"1296\"><strong data-start=\"1296\" data-end=\"1308\">SHANNON:</strong> I do, and I want to avoid all the plastic packaging in the supermarket!<br data-start=\"1380\" data-end=\"1383\"><strong data-start=\"1383\" data-end=\"1392\">LEON:</strong> Well, there’s a really nice organic shop there. Now what’s it called … it’s the name of a flower. I know, it’s ‘<span style=\"background-color: #f1c40f;\"><strong>(4) Rose</strong></span>’.<br data-start=\"1511\" data-end=\"1514\"><strong data-start=\"1514\" data-end=\"1526\">SHANNON:</strong> That’s a nice name.<br data-start=\"1546\" data-end=\"1549\"><strong data-start=\"1549\" data-end=\"1558\">LEON:</strong> Yeah – it sells vegetables and quite a lot of other stuff.<br data-start=\"1617\" data-end=\"1620\"><strong data-start=\"1620\" data-end=\"1632\">SHANNON:</strong> And where’s that?<br data-start=\"1650\" data-end=\"1653\"><strong data-start=\"1653\" data-end=\"1662\">LEON:</strong> Well, as you reach the market, you’ll see a big grey building on your left – I think it used to be a warehouse. Anyway, now it’s a restaurant upstairs, but the ground floor has two shops, either side of the entrance and it’s the one on the left.<br data-start=\"1908\" data-end=\"1911\"><strong data-start=\"1911\" data-end=\"1923\" data-is-only-node=\"\">SHANNON:</strong> That’s easy enough.<br data-start=\"1943\" data-end=\"1946\"><strong data-start=\"1946\" data-end=\"1955\">LEON:</strong> You can’t miss it – there’s also a big <strong><span style=\"background-color: #f1c40f;\">(5) sign</span></strong> on the pavement so you can look for that.<br data-start=\"2041\" data-end=\"2044\"><strong data-start=\"2044\" data-end=\"2056\">SHANNON:</strong> Fine! I guess if I need anything else, I’ll have to go to the supermarket.<br data-start=\"2131\" data-end=\"2134\"><strong data-start=\"2134\" data-end=\"2143\">LEON:</strong> Yeah – you should be able to get everything you need, but there’s a minibus that goes to the supermarket if you need it. It’s <span style=\"background-color: #f1c40f;\"><strong>(6) purple</strong></span> and the number is 289.<br data-start=\"2299\" data-end=\"2302\"><strong data-start=\"2302\" data-end=\"2314\">SHANNON:</strong> Thanks, that’s great.</p>\n<p data-start=\"2345\" data-end=\"2959\"><strong data-start=\"2345\" data-end=\"2354\">LEON:</strong> So what do you need to get at the fish market? The salmon is always very good and the shellfish.<br data-start=\"2451\" data-end=\"2454\"><strong data-start=\"2454\" data-end=\"2466\">SHANNON:</strong> I’m going to make a curry, I think, and I need about 12 prawns for that.<br data-start=\"2539\" data-end=\"2542\"><strong data-start=\"2542\" data-end=\"2551\">LEON:</strong> They’ll have plenty of those.<br data-start=\"2581\" data-end=\"2584\"><strong data-start=\"2584\" data-end=\"2596\">SHANNON:</strong> OK.<br data-start=\"2600\" data-end=\"2603\"><strong data-start=\"2603\" data-end=\"2612\">LEON:</strong> Have you ever tried <span style=\"background-color: #f1c40f;\"><strong>(7) samphire</strong></span>?<br data-start=\"2642\" data-end=\"2645\"><strong data-start=\"2645\" data-end=\"2657\">SHANNON:</strong> No – what’s that?<br data-start=\"2675\" data-end=\"2678\"><strong data-start=\"2678\" data-end=\"2687\">LEON:</strong> It’s a type of seaweed. I just ask for a handful and you fry it in butter. It’s delicious!<br data-start=\"2778\" data-end=\"2781\"><strong data-start=\"2781\" data-end=\"2793\">SHANNON:</strong> Oh, I might try that – how do you spell it?<br data-start=\"2837\" data-end=\"2840\"><strong data-start=\"2840\" data-end=\"2849\" data-is-only-node=\"\">LEON:</strong> It’s S-A-M-P-H-I-R-E.<br data-start=\"2871\" data-end=\"2874\"><strong data-start=\"2874\" data-end=\"2886\">SHANNON:</strong> Great – it’s always good to try something different.<br data-start=\"2939\" data-end=\"2942\"><strong data-start=\"2942\" data-end=\"2951\">LEON:</strong> Yeah.</p>\n<p data-start=\"2966\" data-end=\"3647\"><strong data-start=\"2966\" data-end=\"2978\">SHANNON:</strong> I’ll see what beans they have in the organic shop and I think I’ll get something for dessert there.<br data-start=\"3078\" data-end=\"3081\"><strong data-start=\"3081\" data-end=\"3090\">LEON:</strong> How about a mango?<br data-start=\"3109\" data-end=\"3112\"><strong data-start=\"3112\" data-end=\"3124\">SHANNON:</strong> I’m not sure – they’re not always ripe. I’d prefer a <strong><span style=\"background-color: #f1c40f;\">(8) melon</span></strong> – it’s bigger too.<br data-start=\"3202\" data-end=\"3205\"><strong data-start=\"3205\" data-end=\"3214\">LEON:</strong> Good idea. The corner also sells a lot of spices there that you can put in a curry, and things like <span style=\"background-color: #f1c40f;\"><strong>(9) coconut.</strong></span><br data-start=\"3323\" data-end=\"3326\"><strong data-start=\"3326\" data-end=\"3338\">SHANNON:</strong> Oh, that’s very helpful. I’ll have a look.<br data-start=\"3381\" data-end=\"3384\"><strong data-start=\"3384\" data-end=\"3393\">LEON:</strong> No problem.<br data-start=\"3405\" data-end=\"3408\"><strong data-start=\"3408\" data-end=\"3420\">SHANNON:</strong> I know bread doesn’t really go with curry but I always like to have some in case.<br data-start=\"3502\" data-end=\"3505\"><strong data-start=\"3505\" data-end=\"3514\">LEON:</strong> As I said – all the bread is home-made and there’s lots of variety. I like the brown bread myself.<br data-start=\"3613\" data-end=\"3616\"><strong data-start=\"3616\" data-end=\"3628\" data-is-only-node=\"\">SHANNON:</strong> Mm, sounds good.</p>\n<p data-start=\"3654\" data-end=\"3932\"><strong data-start=\"3654\" data-end=\"3663\">LEON:</strong> They sell other things there too.<br data-start=\"3697\" data-end=\"3700\"><strong data-start=\"3700\" data-end=\"3712\">SHANNON:</strong> Like cakes? I love chocolate cake.<br data-start=\"3747\" data-end=\"3750\"><strong data-start=\"3750\" data-end=\"3759\">LEON:</strong> Well – not that, but they have a whole range of tarts and the best are the <span style=\"background-color: #f1c40f;\"><strong>(10) strawberry</strong></span> ones.<br data-start=\"3851\" data-end=\"3854\"><strong data-start=\"3854\" data-end=\"3866\">SHANNON:</strong> Perfect – hopefully I won’t even have to go to the supermarket!</p>\n</blockquote>"}]', 0);
INSERT INTO public.questions VALUES ('f20b7b5f-f3c7-40a4-b535-ab9b79fc1854', '86f1b19c-d59b-4b8e-89b5-6d8216bef9ae', 'radio', 'Questions 21-26', '', '<p>Choose the correct answers</p>
<p><span style="font-size: 12pt;"><strong>Kathy’s dissertation on water pumps</strong></span></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "her results section"}, {"option_text": "her introductory chapter"}, {"option_text": "her review of the literature"}], "question": "What part of Kathy''s dissertation has the tutor just read?"}, {"correct": 1, "options": [{"option_text": "the organisation"}, {"option_text": "the style of writing"}, {"option_text": "the use of resources"}], "question": "What did the tutor like about Kathy''s work?"}, {"correct": 1, "options": [{"option_text": "do some more library research."}, {"option_text": "record more data."}, {"option_text": "narrow down her topic."}], "question": "Kathy and the tutor agree that she needs to"}, {"correct": 2, "options": [{"option_text": "to show how successful he has become"}, {"option_text": "to illustrate how times have changed"}, {"option_text": "to encourage Kathy to do something similar"}], "question": "Why does the tutor give an example from his own experience?"}, {"correct": 2, "options": [{"option_text": "layout"}, {"option_text": "bibliography"}, {"option_text": "appendices"}], "question": "Kathy would like the tutor to advise her on her"}, {"correct": 0, "options": [{"option_text": "try out some software"}, {"option_text": "go to a seminar"}, {"option_text": "design a new type of pump"}], "question": "What is Kathy going to do next？"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('cad22b90-0668-4c86-8514-e3288ba5c1f2', 'ddb76a69-fe13-4a91-9787-34087773f770', 'fillup', 'Questions 24-26', '<p>Complete the summary <span class="citation-3915 citation-end-3915">below.<sup class="superscript" data-turn-source-index="1"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><span class="citation-3914">Choose </span><strong data-path-to-node="16" data-index-in-node="7"><span class="citation-3914">ONE WORD ONLY</span></strong><span class="citation-3914 citation-end-3914"> from the passage for each answer.<sup class="superscript" data-turn-source-index="2"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><span class="citation-3913 citation-end-3913">Write your answers in boxes 24-26 on your answer sheet.<sup class="superscript" data-turn-source-index="3"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p data-path-to-node="18"><strong data-path-to-node="18" data-index-in-node="0"><span class="citation-3912 citation-end-3912"><span style="font-size: 14pt;">The Beginnings of CRSP</span><sup class="superscript" data-turn-source-index="4"><!----></sup></span></strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p><span class="citation-3911">In 1958, a {banker}</span><span class="citation-3911 citation-end-3911"> working for a financial management company telephon<sup class="superscript" data-turn-source-index="5"><!----></sup></span>ed in Chicago to ask how well investments in shares performed in comparison to investments in low-risk assets. Fischer <span class="citation-3909 citation-3910">offered to find out and as a result the University of Chicago’s Center for Research in Security Prices (CRSP) was launched. Compiling the CRSP data was difficult because {computers}</span><span class="citation-3909 citation-3910"> were still being developed and information that had previously been on {paper}</span><span class="citation-3909 citation-3910 citation-end-3910"> needed to b<sup class="superscript" data-turn-source-index="6"><!----></sup></span><span class="citation-3909 citation-end-3909">e put onto magnetic tape.</span></p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. banker — {In 1958, a banker working for a financial management company telephoned…}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“It all began in 1958 with a phone call from Louis Engel, a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"80\">banker</strong> at Merrill Lynch, a US-based financial management company…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ rõ người thực hiện cuộc gọi là Louis Engel, một nhân viên ngân hàng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"93\">banker</strong>) đang làm việc tại một công ty quản lý tài chính.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. computers — {…because computers were still being developed}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Getting the CRSP data together was a tough process in what were then the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"94\">early days of computers</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “early days of computers” (những ngày đầu của máy tính) tương ứng với việc máy tính (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"101\">computers</strong>) vẫn đang trong quá trình phát triển (being developed).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. paper — {…information that had previously been on paper needed to be put onto magnetic tape.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…pieces of information… were transferred from <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"71\">paper</strong> in the exchange’s archive to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"106\">magnetic tape</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để đưa dữ liệu vào máy tính thời đó, các nhà nghiên cứu phải chuyển thông tin vốn đang nằm trên giấy tờ (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"117\">paper</strong>) trong kho lưu trữ sang dạng băng từ (magnetic tape).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('cb6abc84-4ee7-40d4-af54-0f1f186e9443', 'd2f9aafb-e221-4fd7-84f6-3f357187a22c', 'fillup', 'Questions 18–23', '<p>Complete the sentences below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p>Movement and wakefulness in young orcas assist them in maintaining {body temperature} .</p>
<p>New orca mothers need to be awake in order to protect their young from {sharks} .</p>
<p>Sleep deprivation experiments on {rats | laboratory rats} have shown that animals die without adequate sleep.</p>
<p>Scientists have not yet worked out why almost all animals sleep with {closed eyes} .</p>
<p>For humans, sleep is vital for the efficient functioning of the {brain} .</p>
<p>During periods of {migration} Swainson’s thrushes experience severe sleep deprivation.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">18. Movement and wakefulness in young orcas assist them in maintaining <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>body temperature</strong>.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>body temperature</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “The young orcas’ movement and wakefulness help them keep their <strong>body temperature</strong> constant until mass and blubber insulation develop and allow for frequent respiration.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Cá orca con cần di chuyển và thức để duy trì <strong>nhiệt độ cơ thể</strong> (<em>body temperature</em>) ổn định.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">19. New orca mothers need to be awake in order to protect their young from <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>sharks</strong>.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>sharks</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “Meanwhile the mothers of newborn orcas must constantly look out for <strong>sharks</strong>, while teaching the calves to breath.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Cá orca mẹ phải thức để cảnh giác với <strong>cá mập</strong> (<em>sharks</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">20. Sleep deprivation experiments on <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>rats</strong> have shown that animals die without adequate sleep.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>rats</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “Some animals die without proper sleep, and experiments have shown that sleep deprivation can cause death more quickly than food deprivation. Two weeks without sleep can kill laboratory <strong>rats</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Các thí nghiệm thiếu ngủ trên <strong>chuột</strong> (<em>rats</em>) đã chứng minh điều này.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">21. Scientists have not yet worked out why almost all animals sleep with <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>closed eyes</strong>.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>closed eyes</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “However, for unknown reasons, <strong>closed eyes</strong> seem to be a virtually universal prerequisite for sleep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Mặc dù cá heo có thể ngủ bằng nửa bộ não, nhưng việc <strong>nhắm mắt</strong> (<em>closed eyes</em>) dường như là điều kiện tiên quyết cho giấc ngủ ở hầu hết các loài động vật.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">22. For humans, sleep is vital for the efficient functioning of the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>brain</strong>.</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>brain</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “…sleep is no more effective than a comparable period of wakeful resting – except for one critical organ, the <strong>brain</strong>. The human brain apparently cannot do without sleep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Giấc ngủ là cần thiết cho hoạt động hiệu quả của <strong>bộ não</strong> (<em>brain</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"14\">23. During periods of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>migration</strong> Swainson’s thrushes experience severe sleep deprivation.</h3>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án:</strong> <strong>migration</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “…the behavior of the migratory birds Swainson’s thrushes, which for <strong>migration</strong> purposes, go from a normal night’s sleep of 10 to 12 hours down to about 2.5 hours so they can fly at night.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong>Giải thích:</strong> Chim hét Swainson trải qua tình trạng thiếu ngủ nghiêm trọng trong mục đích <strong>di cư</strong> (<em>migration</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2be945f5-e7bc-451f-a834-99b9d1217e75', 'd2f9aafb-e221-4fd7-84f6-3f357187a22c', 'matrix', 'Questions 24–26', NULL, '<p>Reading Passage 2 has 7 paragraphs, <strong>A-G</strong>.</p>
<p>Which paragraph contains the following information?</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "mention of the potential use of chemicals to reduce sleep periods", "correctCategoryLetter": "G"}, {"itemText": "reference to a lack of expert consensus regarding the behaviour of certain types of animal", "correctCategoryLetter": "B"}, {"itemText": "an example of an animal which continues to function normally during its sleep periods", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<h3 data-path-to-node=\"5\">24. mention of the potential use of chemicals to reduce sleep periods.</h3>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>G</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “The trick would be to develop techniques or <strong>drugs</strong> that could recreate a similar brain pattern in humans.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Đoạn G đề cập đến khả năng phát triển các kỹ thuật hoặc <strong>thuốc</strong> (<em>drugs</em>) để tái tạo mô hình não giống như chim hét, cho phép con người giảm thời gian ngủ. <strong>Thuốc</strong> (<em>drugs</em>) chính là hình thức của <strong>hóa chất</strong> (<em>chemicals</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">25. reference to a lack of expert consensus regarding the behaviour of certain types of animal.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>B</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “All mammals and birds appear to need sleep, but <strong>scientists are unsure if reptiles and fish do</strong>. ‘When you come downstairs at three in the morning, the goldfish isn’t lying on the bottom of the bowl, it’s swimming around,’ Siegel says. <strong>But other scientists believe fish do enter a restful dormant state that is at least similar to sleep.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Đoạn B trình bày sự khác biệt trong ý kiến chuyên môn (<em>expert consensus</em>) về việc liệu các loài vật như cá có cần ngủ hay không, khi một số nhà khoa học không chắc chắn (<em>unsure</em>) và những người khác lại tin rằng chúng có trạng thái nghỉ ngơi tương tự.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"11\">26. an example of an animal which continues to function normally during its sleep periods.</h3>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “In dolphin’s <strong>half the brain may rest while the other half stays vigilantly awake, and the animal carries on everyday activities</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Đoạn D cung cấp ví dụ về cá heo (<em>dolphin</em>) – loài động vật có thể ngủ bằng một nửa bộ não trong khi nửa còn lại vẫn tỉnh táo và <strong>tiếp tục các hoạt động hàng ngày</strong> (<em>carries on everyday activities</em> / function normally).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('b9e8382b-0e13-4e66-84b7-6af1f4da4f1d', 'af2b8a94-7dce-4854-b4e6-49b527a0ec0c', 'matrix', ' Questions 14–17', NULL, '<p>Reading Passage 2 has eight paragraphs, <strong>A-H</strong>. Which paragraph contains the following information?</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "fears voiced about the potential threat posed to art by photography", "correctCategoryLetter": "B"}, {"itemText": " the skills of artists being used in photography", "correctCategoryLetter": "F"}, {"itemText": "the attempts of photographers to imitate art", "correctCategoryLetter": "D"}, {"itemText": " the influence of photography on artists and painting", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Câu 14</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The French poet Baudelaire… asserted that if photography is allowed to deputise for art… it will not be long before it has <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"139\">supplanted or corrupted art altogether</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Baudelaire bày tỏ nỗi sợ rằng nhiếp ảnh sẽ thay thế hoặc làm hỏng hoàn toàn nghệ thuật. Điều này khớp với từ khóa “fears” và “potential threat” (mối đe dọa tiềm tàng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Câu 15</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> F</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the increasing involvement of <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"45\">people trained as artists</strong>. They brought with them a <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"97\">concern for form and composition and, in particular, the use of light</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về việc những người có chuyên môn nghệ thuật tham gia vào nhiếp ảnh và sử dụng các kỹ năng về hình khối, bố cục, ánh sáng của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Câu 16</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dữ dẫn:</strong> “…they pointed out that photography… could be worked on and contrived so as to produce pictures which in some ways <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"127\">resembled paintings</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhiếp ảnh gia cố gắng dàn dựng và chỉnh sửa ảnh để chúng trông giống như tranh vẽ (imitate art).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Câu 17</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> G</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It is a truism that <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"32\">photography released painting from its responsibility for literal depiction</strong>, allowing it to become more experimental.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn thảo luận về việc nhiếp ảnh tác động đến hội họa, giúp họa sĩ thoát khỏi việc sao chép thực tế để thử nghiệm những phong cách mới (như trường phái Ấn tượng).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('75be1e69-46c8-4e92-bee6-d0ee890cce4f', 'af2b8a94-7dce-4854-b4e6-49b527a0ec0c', 'fillup', 'Questions 18–22', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the summary below</p>
<p>Write <strong>ONE WORD ONLY </strong>for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>Photographers’ responses to criticism</strong></span></p>
<p>In response to the suggestion that photography could not be considered an art form photographer acted in two ways. Some of them rejected this criticism, certain that they could create pictures similar to {paintings} did this by carefully setting up the different parts of the {composition} before taking the photograph. Other things they did included causing the picture to be rather {blurred} , and some who wanted to try to make the print look like a canvas even {scratched} their photographs. Others were anxious that their work should not be looked upon as some sort of {monochrome} painting and were much more concerned with the fact that the camera seemed to be able to produce a more accurate representation of what they could see around them.</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Câu 18</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án:</strong> paintings</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…produce pictures which in some ways resembled <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"61\">paintings</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một số nhiếp ảnh gia tin rằng họ có thể tạo ra những bức ảnh có phong cách tương đồng với tranh vẽ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Câu 19</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án:</strong> composition</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…careful arrangement of all the elements of the <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"62\">composition</strong>…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Họ đạt được điều này bằng cách sắp xếp tỉ mỉ các thành phần trong bố cục trước khi chụp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Câu 20</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án:</strong> blurred</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…ensured that the image was somewhat <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"51\">blurred</strong>…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một kỹ thuật khác được sử dụng là làm cho hình ảnh hơi mờ đi để giảm bớt tính “kỹ thuật” của camera.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Câu 21</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> scratched</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…<strong data-path-to-node=\"20,1,0\" data-index-in-node=\"15\">scratched</strong> their prints in an effort to imitate something of the appearance of a canvas.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để giả lập bề mặt vải canvas của tranh, họ thậm chí còn cào/làm xước các bản in.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Câu 22</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> monochrome</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…did not want to treat the medium as a kind of <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"61\">monochrome</strong> painting.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những nhiếp ảnh gia ở nhóm thứ hai không muốn coi nhiếp ảnh chỉ là một dạng tranh đơn sắc (đen trắng).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('71c5c803-f1b3-4952-b1fb-3268d718bb35', '86f1b19c-d59b-4b8e-89b5-6d8216bef9ae', 'matching', 'Questions 27-30', '', '<p>How will Kathy benefit from doing each of the following activities?</p>
<p>Choose <strong>FOUR</strong> answers from the box</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Activities</strong></p>\n<p> </p>\n<p>going to Mechanical Engineers'' Society meetings {way to make useful contacts}</p>\n<p> </p>\n<p>visiting different workplaces {effective way of keeping up-to-date}</p>\n<p> </p>\n<p>getting some work experience abroad {broadens practical experience of the field}</p>\n<p> </p>\n<p>attending an international conference {chance to publicise own work}</p>\n<p> </p>", "answerOptions": [{"optionText": "broadens practical experience of the field"}, {"optionText": "chance to publicise own work"}, {"optionText": "effective way of keeping up-to-date"}, {"optionText": "looks good on a CV"}, {"optionText": "provides useful access to resources"}, {"optionText": "way to make useful contacts"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('8a7db97c-8c47-4913-916a-ffafe8d636ee', '376d684b-ef75-4afd-85d9-7ed3d95c3632', 'fillup', 'Questions 31-40', '<p dir="ltr">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p dir="ltr"><span style="font-size: 12pt;"><strong>Food Safety Standards Risk assessment</strong></span></p>
<p dir="ltr"><strong>-Scientists have to consider potential problems with:</strong></p>
<p dir="ltr">· the product’s {ingredients}</p>
<p dir="ltr">· how products are {stored} and distributed</p>
<p dir="ltr">· supermarkets(e.g.changes in {temperature} affecting the condition of frozen</p>
<p dir="ltr"><strong>-Factors affecting food consumption</strong></p>
<p dir="ltr">Legislation</p>
<p dir="ltr"><strong>-Consumer attitudes</strong></p>
<p dir="ltr">·e.g.dislike of additives→growth of the {organic} food market in Australia</p>
<p dir="ltr"><strong>-The food industry</strong></p>
<p dir="ltr">· supermarkets may use price or {image} as their selling strategy</p>
<p dir="ltr"><strong>-The mass media</strong></p>
<p dir="ltr">·now the main source of {information} for many</p>
<p dir="ltr">·negative effect because not objective:</p>
<p dir="ltr" style="padding-left: 40px;">+ concern for {sales}</p>
<p dir="ltr" style="padding-left: 40px;">+ a form of {entertainment} which can mislead the public</p>
<p dir="ltr">· few programmes deal with food safety or {nutrition}</p>
<p dir="ltr"><strong>-Personal opinion</strong></p>
<p dir="ltr">Importance of education: as with benefits of exercise,many children can influence their {parents}</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('1778e018-6794-4e4a-98c5-580edab586b1', '2884e25c-b2c0-4eb9-8a86-4107b43432aa', 'matrix', 'Questions 14–18', NULL, '<p>The reading passage has seven paragraphs, <strong>A-G.</strong></p>
<p>Which paragraph contains the following information?</p>
<p>Write the correct letter, <strong>A-G,</strong> in boxes 14-19 on your answer sheet.</p>
<p><strong>NB You may use any letter more than once.</strong></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a weakness in some of Goya''s paintings", "correctCategoryLetter": "G"}, {"itemText": "a reason that might explain why some artists did not enjoy painting portraits", "correctCategoryLetter": "E"}, {"itemText": "a genre Goya did not paint", "correctCategoryLetter": "A"}, {"itemText": "description of a reaction to a promotion", "correctCategoryLetter": "D"}, {"itemText": " a summary of the historical significance of Goya''s works", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"3\">14. A weakness in some of Goya’s paintings</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>G</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> “While <strong>not all his portraits are successful (some have a doll-like stiffness)</strong>, this is what Goya at his best could do…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Tác giả thừa nhận một <strong>điểm yếu</strong> (<em>weakness</em>) trong một số tác phẩm của Goya là sự cứng nhắc như búp bê (<em>doll-like stiffness</em>), cho thấy không phải bức chân dung nào của ông cũng thành công.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">15. A reason that might explain why some artists did not enjoy painting portraits</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> “…unlike Gainsborough, for example, he did not resent portraiture as an <strong>economically necessary chore that ate away at the time</strong> he could devote to higher art.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Đoạn E đưa ra lý do tại sao một số nghệ sĩ (như Gainsborough) không thích vẽ chân dung: họ coi đó là một <strong>công việc nhàm chán vì mục đích kinh tế</strong> (<em>economically necessary chore</em>) làm tiêu tốn thời gian dành cho nghệ thuật cao siêu hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">16. A genre Goya did not paint</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> “…there are <strong>no pure landscapes in Goya’s work</strong>, in that everything he ever painted deals with people.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Đoạn A khẳng định Goya <strong>không vẽ phong cảnh thuần túy</strong> (<em>no pure landscapes</em>). Mọi tác phẩm của ông đều tập trung vào con người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">17. Description of a reaction to a promotion</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> “Не immediately spent some of his 15,000-reales salary on a <strong>two-wheeled gig</strong>… which he <strong>promptly crashed on his first outing</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Sau khi được bổ nhiệm làm phó giám đốc hội họa (thăng chức – <em>promotion</em>), Goya đã phản ứng bằng cách dùng lương mua ngay một chiếc xe ngựa hai bánh và nhanh chóng làm hỏng nó trong lần đầu cầm lái.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\">18. A summary of the historical significance of Goya’s works</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> “In the work of no other great portraitist are a <strong>nation’s people, history, traumas, folk traditions, and superstitions so comprehensively and relentlessly captured</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Đoạn A tóm tắt <strong>tầm quan trọng lịch sử</strong> (<em>historical significance</em>) của Goya, khẳng định tác phẩm của ông đã ghi lại một cách toàn diện lịch sử, con người và những biến động của đất nước Tây Ban Nha.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\">19. (Câu hỏi bổ sung dựa trên Logic bảng Matrix) – A description of a technique used by Goya</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> “When it came to clothing he allowed himself extraordinary freedom… sketched in <strong>thick impasto</strong>… from a distance, they coalesce into silks, braiding, and gauze.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Đoạn E mô tả chi tiết kỹ thuật vẽ của Goya, đặc biệt là cách ông xử lý trang phục bằng các lớp sơn dày (<em>impasto</em>) để tạo hiệu ứng từ xa.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('8a62ec32-9761-45b7-9fc7-80ada83ed585', '2884e25c-b2c0-4eb9-8a86-4107b43432aa', 'checkbox', 'Questions 19–20', NULL, '<p>Choose <strong>TWO </strong>correct answers</p>
<p>Which <strong>TWO </strong>statements are true about Goya’s tapestry cartoons?</p>
', 'multiple-select', 'null', '[{"option": "They featured lively civilians and labourers that he observed.", "correct": true}, {"option": "Individuals were portrayed without faces.", "correct": false}, {"option": "They were used to develop techniques for his future works.", "correct": true}, {"option": "People''s social standings were a secondary focus.", "correct": false}, {"option": "He avoided painting political controversies.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\">19. They featured lively civilians and labourers that he observed.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Vị trí:</strong> <strong>Đoạn B (Dòng 3-5)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Dẫn chứng:</strong> “…they do show types – the <strong>majos and majas</strong> who gave Madrid its street swagger, <strong>peasants</strong> and rich men, courting couples, singers, hunters, children…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong>Giải thích:</strong> * Tác giả liệt kê một loạt các nhân vật dân dã như <strong>majos/majas</strong> (thanh niên đường phố Madrid) và <strong>peasants</strong> (nông dân).</p>\n<ul data-path-to-node=\"5,3,1\">\n<li>\n<p data-path-to-node=\"5,3,1,0,0\">Cụm từ “street swagger” (phong thái đường phố) và việc liệt kê các ngành nghề cho thấy đây là những <strong>dân thường và người lao động sinh động</strong> (<em>lively civilians and labourers</em>) mà Goya đã trực tiếp <strong>quan sát</strong> được khi sống ở Madrid.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"6\">20. They were used to develop techniques for his future works.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>C</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Vị trí:</strong> <strong>Đoạn B (2 dòng cuối)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Dẫn chứng:</strong> “But in them, Goya <strong>practised poses and groupings and a way of handling light</strong> on and around figures that was to be <strong>invaluable</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,3,0\"><strong>Giải thích:</strong> * Đoạn văn khẳng định Goya đã <strong>thực hành</strong> (<em>practised</em>) các kỹ thuật về tạo dáng, sắp xếp bố cục nhóm và xử lý ánh sáng thông qua các bức vẽ thảm này.</p>\n<ul data-path-to-node=\"7,3,1\">\n<li>\n<p data-path-to-node=\"7,3,1,0,0\">Từ <strong>“invaluable”</strong> (vô giá) nhấn mạnh rằng những kỹ năng này là nền tảng cực kỳ quan trọng, giúp ích cho sự nghiệp vẽ chân dung rực rỡ sau này của ông (<strong>future works</strong>).</p>\n</li>\n</ul>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('64be45e6-3c08-4dd4-90bf-2f767a80ae50', '2884e25c-b2c0-4eb9-8a86-4107b43432aa', 'checkbox', 'Questions 21–22', NULL, '<p>Choose <strong>TWO </strong>correct answers</p>
<p>Which <strong>TWO </strong>statements are true about Goya’s portraits?</p>
', 'multiple_choice_many', 'null', '[{"option": "His depiction of royalty was typical of the time.", "correct": false}, {"option": "He was meticulous about the details when painting clothes.", "correct": false}, {"option": "He generally avoided using the same pose.", "correct": true}, {"option": "He paid very close attention to the background in his paintings.", "correct": true}, {"option": "He did not believe in using the works of other artists as inspiration.", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('762fed3d-2b6e-4940-9ea9-9afa6a2c0dcf', 'ede127b0-4a6e-4ef5-bc49-41b3eecbd716', 'radio', 'Questions 11–14', NULL, '<p>Choose the correct letter, A, B or C.</p>
<p><span style="font-size: 12pt;"><strong>Information for fire wardens</strong></span></p>', 'multiple-choice', '[{"correct": 1, "options": [{"content": "A. employees did badly in the last annual fire drill."}, {"content": "B. there have been changes in the building layout."}, {"content": "C. new staff have joined the company."}], "question": "The company is having this meeting about fire procedures because"}, {"correct": 2, "options": [{"content": "A. the sprinkler system."}, {"content": "B. the fire extinguishers."}, {"content": "C. the alarm system."}], "question": "There has been a recent upgrade to"}, {"correct": 2, "options": [{"content": "A. were unable to read fire notices."}, {"content": "B. left fire doors open."}, {"content": "C. were unwilling to start the fire alarm."}], "question": "During the minor fire in January, some staff working in the factory"}, {"correct": 2, "options": [{"content": "A. refused to leave personal items behind."}, {"content": "B. moved too slowly during the evacuation."}, {"content": "C. did not move far away enough from the building."}], "question": "In the fire in January, the problem with office staff was that they"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 2: FIRE PROCEDURES AT WORK</strong></p>\n<p id=\"p-rc_8764aa6cd6260079-30\" data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong> <span class=\"citation-699 citation-end-699\">Hello and thanks to everyone for being on time. The meeting will be fairly short and we''ll only be looking at fire procedures. I had a similar meeting with the senior fire officers earlier today, but you''re all here because you''v<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>e <span class=\"citation-698 citation-end-698\">volunteered to act as fire wardens for your own particular department.<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-31\" data-path-to-node=\"4\"><span class=\"citation-697 citation-end-697\">And for some of you, this will be your first time in the role, although you''ll probably have taken part in several fire drills since you''ve been he<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span>re. <strong data-path-to-node=\"4\" data-index-in-node=\"151\"><span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\">(Q11) </span></span><span class=\"citation-695 citation-696\"><span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\">But now the construction work is finished and we have a couple of new corridors and stairways, we need the meeting to update everyone</span></span>.</span></strong><span class=\"citation-695 citation-696 citation-end-696\"><sup class=\"superscript\" data-turn-source-index=\"4\"><!----></sup></span><span class=\"citation-695 citation-end-695\"><sup class=\"superscript\" data-turn-source-index=\"5\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-32\" data-path-to-node=\"5\"><span class=\"citation-693 citation-694 citation-end-694\">And before I forget, you might have noticed a bit of upgrading last week. The handheld fire extinguishers, the standard ones on the wall, the report<sup class=\"superscript\" data-turn-source-index=\"6\"><!----></sup></span><span class=\"citation-693 citation-end-693\"> says they''re all working well, as is the overhead sprinkler system.<sup class=\"superscript\" data-turn-source-index=\"7\"><!----></sup></span> <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"217\">(Q12) <span class=\"citation-690 citation-691 citation-692\">But the old alarm system has been replaced and should be a lot more reliable.</span></strong></span><span class=\"citation-690 citation-691 citation-692 citation-end-692\"><sup class=\"superscript\" data-turn-source-index=\"8\"><!----></sup></span><span class=\"citation-690 citation-691 citation-end-691\"><sup class=\"superscript\" data-turn-source-index=\"9\"><!----></sup></span><span class=\"citation-690 citation-end-690\"><sup class=\"superscript\" data-turn-source-index=\"10\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-33\" data-path-to-node=\"6\"><span class=\"citation-687 citation-688 citation-689 citation-end-689\">Anyway, as fire wardens, you have a number of responsibilities. Okay, those wardens responsible for the factory buildings, you''ll remember we had a minor fir<sup class=\"superscript\" data-turn-source-index=\"11\"><!----></sup></span><span class=\"citation-687 citation-688 citation-end-688\">e back in January. Luckily the fire doors around the room stopped most of the smoke from getting out, but the alarm should have been pressed<sup class=\"superscript\" data-turn-source-index=\"12\"><!----></sup></span><span class=\"citation-687 citation-end-687\"> a lot earli<sup class=\"superscript\" data-turn-source-index=\"13\"><!----></sup></span>er. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"313\">(Q13) <span class=\"citation-685 citation-686\">From what I understand, staff felt somewhat reluctant to activate it themselves and were looking for someone senior</span></strong></span><span class=\"citation-685 citation-686 citation-end-686\">, so please ensure that everyone knows it''s their responsibility to take action immediately. Can you also make sure that if anyone new has been hired sinc<sup class=\"superscript\" data-turn-source-index=\"14\"><!----></sup></span><span class=\"citation-685 citation-end-685\">e then, that they''ve read the fire notices.<sup class=\"superscript\" data-turn-source-index=\"15\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-34\" data-path-to-node=\"7\"><span class=\"citation-684 citation-end-684\">And wardens for office departments, <sup class=\"superscript\" data-turn-source-index=\"16\"><!----></sup></span>you will also have to have a word with your staff. When the fire alarm went off in January in that minor fire, people got out of the office building pretty quickly. That was fine, but <strong data-path-to-node=\"7\" data-index-in-node=\"220\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q14) once they were out, they stood right in front of the doors, so if the fire crews had needed to access the offices, they would have been prevented</span>.</strong> Good to see that everyone had left their bags and stuff behind though.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<hr data-path-to-node=\"8\">\n<h3 data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">FIRE SAFETY ASPECTS (Questions 15–20)</strong></h3>\n<p id=\"p-rc_8764aa6cd6260079-35\" data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Manager:</strong> <span class=\"citation-683 citation-end-683\">Okay, next on the agenda, there''s a few aspects of fire safety that we need to go through with all you wardens.<sup class=\"superscript\" data-turn-source-index=\"17\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-36\" data-path-to-node=\"11\"><span class=\"citation-682 citation-end-682\">Firstly, we want to make sure that when we have the next fire drill, there''s nothing blocking the way in the escape routes—no obstacles I mea<sup class=\"superscript\" data-turn-source-index=\"18\"><!----></sup></span>n. <strong data-path-to-node=\"11\" data-index-in-node=\"144\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q15) So please have a look at that as soon as possible</span>.</strong> We want to be able to get outside very quickly.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-37\" data-path-to-node=\"12\"><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">(Q16) <span class=\"citation-680 citation-681\">One thing that should definitely be on your to-do list is making sure no one''s locked the fire doors and that it''s easy enough to get through them.</span></strong></span><span class=\"citation-680 citation-681 citation-end-681\"><sup class=\"superscript\" data-turn-source-index=\"19\"><!----></sup></span><span class=\"citation-680 citation-end-680\"><sup class=\"superscript\" data-turn-source-index=\"20\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-38\" data-path-to-node=\"13\"><span class=\"citation-678 citation-679 citation-end-679\">Now you might remember that last year we had a fire officer come and<sup class=\"superscript\" data-turn-source-index=\"21\"><!----></sup></span><span class=\"citation-678 citation-end-678\"> visit and show us what to do if we see a colleague starting to suffer from the effects of smoke inhalation. Well,<sup class=\"superscript\" data-turn-source-index=\"22\"><!----></sup></span> <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"183\">(Q17) the same officer is coming back to lead another session.</strong></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-39\" data-path-to-node=\"14\">Another issue is how to handle the fire extinguishers. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"55\">(Q18) <span class=\"citation-677\">Someone from the local fire department is booked in to teach people how to do that.</span></strong></span><span class=\"citation-677\"> I think it would be a good idea if fire wardens </span><span class=\"citation-676 citation-677 citation-end-677\">and department staff attended those sessions.<sup class=\"superscript\" data-turn-source-index=\"23\"><!----></sup></span><span class=\"citation-676 citation-end-676\"><sup class=\"superscript\" data-turn-source-index=\"24\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_8764aa6cd6260079-40\" data-path-to-node=\"15\"><span class=\"citation-674 citation-675 citation-end-675\">Let''s see what else is on the list... Oh yes, the evacuation points: the<sup class=\"superscript\" data-turn-source-index=\"25\"><!----></sup></span> <span class=\"citation-673 citation-674 citation-end-674\">green area behind the main car park, the pavement on Hunter Street, and the unused area behind the factory car park. Fi<sup class=\"superscript\" data-turn-source-index=\"26\"><!----></sup></span><span class=\"citation-673 citation-end-673\">re wardens need to make sure all staff are familiar with these locations for evacuati<sup class=\"superscript\" data-turn-source-index=\"27\"><!----></sup></span>on. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"281\">(Q19) So please send out emails directly after the meeting.</strong></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"16\">And the last point is to do with flammable liquids. I believe there have been a few concerns about where they were being stored in the warehouse, but <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"150\">(Q20) that''s been resolved now.</strong></span> However, if anyone has anything else to report, do let me know.</p>"}]', 0);
INSERT INTO public.questions VALUES ('6dd63bb8-87c4-4838-891d-1f931f7686c9', '0fe88398-e380-44ce-9420-98b7d4b9252f', 'radio', 'Questions 27–32', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The writer changed her mind about spending time in Tasmania."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Andrew Bain believes that the effect MONA had on Hobart was immediate."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Other factors have contributed as much as MONA to Hobart’s transformation."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Tourism Industry Council of Tasmania works closely with the director of MONA."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Many local residents are writing to The Mercury expressing concern about tourists’ length of stay in Hobart."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Tourists now regard MONA as a starting point for longer trips in Tasmania."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">27. The writer changed her mind about spending time in Tasmania.</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"16\">A</strong>, dòng 1-3: &#8220;As an eighteen-year-old&#8230; moving to the ‘mainland’ could not happen soon enough. Now, ten years later, I <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"136\">look forward to going home</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lúc 18 tuổi, tác giả chỉ muốn rời đi thật nhanh. Nhưng 10 năm sau, cô lại mong ngóng được trở về. Điều này khẳng định cô đã thay đổi suy nghĩ.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">28. Andrew Bain believes that the effect MONA had on Hobart was immediate.</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"16\">B</strong>, dòng 2-4: &#8220;Andrew Bain&#8230; wrote, ‘In a <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"58\">virtual blink</strong>, Hobart’s cultural landscape has been transformed&#8230;’&#8221;</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ &#8220;in a virtual blink&#8221; (trong chớp mắt) đồng nghĩa với &#8220;immediate&#8221; (ngay lập tức). Andrew Bain tin rằng sự thay đổi diễn ra rất nhanh chóng sau khi MONA mở cửa.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">29. Other factors have contributed as much as MONA to Hobart’s transformation.</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"16\">B</strong>, dòng cuối: &#8220;MONA is said to have been <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"57\">solely instrumental</strong> in the reinvention of Hobart as a cultural hub.&#8221;</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ &#8220;solely&#8221; (duy nhất/độc nhất) khẳng định chỉ có MONA là nhân tố chính gây ra sự thay đổi này. Câu hỏi nói rằng &#8220;các yếu tố khác cũng đóng góp nhiều như MONA&#8221; là sai so với bài đọc.</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">30. The Tourism Industry Council of Tasmania works closely with the director of MONA.</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"16\">C</strong> và <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"21\">D</strong> có nhắc đến Luke Martin (Giám đốc điều hành Hội đồng Công nghiệp Du lịch) bàn về sự phổ biến của MONA và các kế hoạch điều tra.</li>\n<li><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói hội đồng này đang nghiên cứu các gói du lịch liên quan đến MONA, nhưng <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"95\">không có thông tin</strong> nào nói rằng họ &#8220;làm việc chặt chẽ&#8221; (<em data-path-to-node=\"14,2,0\" data-index-in-node=\"151\">works closely</em>) với giám đốc của bảo tàng.</li>\n</ul>\n<p><strong data-path-to-node=\"15\" data-index-in-node=\"0\">31. Many local residents are writing to The Mercury expressing concern about tourists’ length of stay in Hobart.</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"16\">C</strong>, dòng 4-6: &#8220;As reported in Hobart’s local paper, The Mercury, there is concern about how long people are staying in Tasmania.&#8221;</li>\n<li><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài báo <em data-path-to-node=\"16,2,0\" data-index-in-node=\"20\">The Mercury</em> có báo cáo về sự lo ngại về thời gian lưu trú của du khách, nhưng bài đọc <strong data-path-to-node=\"16,2,0\" data-index-in-node=\"106\">không nói rõ</strong> là do &#8220;nhiều người dân địa phương viết thư&#8221; (<em data-path-to-node=\"16,2,0\" data-index-in-node=\"164\">local residents are writing</em>) gửi đến tòa soạn hay do phóng viên/chuyên gia tự phân tích.</li>\n</ul>\n<p><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. Tourists now regard MONA as a starting point for longer trips in Tasmania.</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></li>\n<li><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"16\">C</strong>, dòng 6-9: &#8220;&#8230;people are making <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"51\">short stays in Hobart only to visit the gallery</strong>. The next challenge&#8230; is how to entice holiday makers to stay longer, and to venture further afield.&#8221;</li>\n<li><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thực tế hiện tại là du khách chỉ đến Hobart ngắn ngày để xem bảo tàng rồi về, chứ họ <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"97\">chưa</strong> coi đây là điểm bắt đầu cho những chuyến đi dài hơn khắp Tasmania. Đây vẫn đang là một &#8220;thách thức&#8221; (<em data-path-to-node=\"18,2,0\" data-index-in-node=\"203\">challenge</em>) cho tương lai.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('67a57411-31e4-427b-9375-9ec9bfd415e5', 'c09ee800-0d6b-47ee-bfa4-c4e3bd5263b3', 'matrix', 'Questions 14–18', '', '<p><span class="citation-24856">Write the correct letter, </span><strong data-path-to-node="3" data-index-in-node="121"><span class="citation-24856">A–F</span></strong><span class="citation-24856 citation-end-24856">, in boxes 14–18 on your answer sheet.<sup class="superscript" data-turn-source-index="1"><!----></sup></span></p>
<p><strong data-path-to-node="3" data-index-in-node="163"><span class="citation-24855">NB</span></strong> <span class="citation-24855 citation-end-24855">You may use any letter more than once.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "reference to two chemical compounds which impact on performance", "correctCategoryLetter": "D"}, {"itemText": "examples of strategies for minimising the effects of stress", "correctCategoryLetter": "F"}, {"itemText": "how a sportsperson accounted for their own experience of stress", "correctCategoryLetter": "A"}, {"itemText": "study results indicating links between stress responses and performance", "correctCategoryLetter": "C"}, {"itemText": "mention of people who can influence how athletes perceive their stress responses", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">14. reference to two chemical compounds which impact on performance — {D}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">\"Our challenge and threat responses... affect the production of <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"75\">adrenaline and cortisol</strong> – also known as ''stress hormones''.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Chemical compounds\" (các hợp chất hóa học) ở đây chính là Adrenaline và Cortisol. Đoạn D giải thích chi tiết cách hai chất này làm giãn hoặc co mạch máu, từ đó ảnh hưởng trực tiếp đến kết quả thi đấu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">15. examples of strategies for minimising the effects of stress — {F}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">\"Positive stress responses can be promoted through the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"66\">language</strong>... psychological skills, such as <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"108\">visualisation</strong>... Recreating <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"136\">competitive pressure during training</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F liệt kê một loạt các ví dụ về chiến lược (strategies) như: dùng ngôn ngữ tích cực, kỹ thuật hình dung và đấu tập có tính điểm để giảm thiểu tác động của stress.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">16. how a sportsperson accounted for their own experience of stress — {A}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">\"...Emma Raducanu... began having difficulty regulating her breathing... which she later <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"100\">attributed to ''the accumulation of the excitement and the buzz''</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Accounted for\" (giải thích cho/quy cho) tương ứng với \"attributed to\". Emma Raducanu (một sportsperson) đã tự giải thích về trải nghiệm gặp sự cố của mình là do sự tích tụ của phấn khích và áp lực.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">17. study results indicating links between stress responses and performance — {C}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">\"<strong data-path-to-node=\"14,0,0\" data-index-in-node=\"12\">Research shows</strong> that the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"36\">challenge states lead to good performance</strong>, while <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"85\">threat states lead to poorer performance</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C trích dẫn kết quả nghiên cứu (study results) chỉ ra mối liên hệ (links) trực tiếp giữa hai trạng thái stress và kết quả thi đấu (tốt hay tệ).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">18. mention of people who can influence how athletes perceive their stress responses — {F}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">\"...through the language that they and others – such as <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"67\">coaches or parents</strong> – use. <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"93\">Psychologists</strong> can also help athletes change how they see their physiological responses...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người có thể ảnh hưởng đến nhận thức của vận động viên được nhắc tên cụ thể là huấn luyện viên (coaches), phụ huynh (parents) và các nhà tâm lý học (psychologists).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c9963a8b-95a0-486f-9b6e-64593fac63a0', '2884e25c-b2c0-4eb9-8a86-4107b43432aa', 'fillup', 'Questions 23–26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Goya’s Artistic Duality</strong></span></p>
<p style="text-align: left;">Francisco Goya, in embracing the simplicity and truth in his art, masterfully navigated the delicate balance between idealism and reality. Among the many royal portraits of his career, his most significant {commission} was from Charles IV, in which he abandoned conventional majesty to faithfully reveal the monarch, whose depiction was later likened to a {butcher} . His subsequent royal paintings, including the 1815 unflattering portrait of Ferdinand VII, show that he was able to depict truth without jeopardizing his position.</p>
<p>However, Goya’s private portraiture revealed a different narrative, as exemplified by his 1820 double portrait with Dr. Arrieta, in which an ailing Goya is seen in the care of the good {doctor} . It serves as a testament to Goya’s pinnacle ability to portray humanity in both its finest and darkest moments, all while refraining from passing judgment; in the latter scenario, individuals may have to be dependent on the {kindness} of their fellow men.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\">23. …his most significant {commission} was from Charles IV…</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>{commission}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Vị trí:</strong> <strong>Đoạn F (Dòng 2)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Dẫn chứng:</strong> “In the most important <strong>commission</strong> of his career, for example, the portrait of Charles IV and the royal family of 1800…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,3,0\"><strong>Giải thích:</strong> Bài đọc đề cập đến việc vẽ chân dung gia đình Charles IV là một “commission” (bản hợp đồng/nhiệm vụ đặt hàng) quan trọng nhất trong sự nghiệp của Goya. Trong tóm tắt, từ “most significant” thay thế cho “most important”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">24. …whose depiction was later likened to a {butcher}.</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>{butcher}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Vị trí:</strong> <strong>Đoạn F (Dòng 5)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Dẫn chứng:</strong> “…a motley grouping (a French visitor had likened Charles and his queen Maria Luisa to a <strong>butcher</strong> and his wife) in fancy clothes.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong>Giải thích:</strong> Goya vẽ gia đình hoàng gia một cách thực tế đến mức một vị khách người Pháp đã so sánh vua Charles IV và hoàng hậu giống như một gã <strong>đồ tể</strong> (<em>butcher</em>) mặc quần áo sang trọng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">25. …in which an ailing Goya is seen in the care of the good {doctor}.</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>{doctor}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Vị trí:</strong> <strong>Đoạn G (Dòng 3-4)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Dẫn chứng:</strong> “…showing Goya with Dr Arrieta… the 73-year-old painter in the throes of a debilitating illness being tended by his <strong>doctor</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,0\"><strong>Giải thích:</strong> Trong bức chân dung kép năm 1820, Goya đang trong cơn bạo bệnh và được chăm sóc bởi người <strong>bác sĩ</strong> (<em>doctor</em>) của mình (Tiến sĩ Arrieta). Từ “doctor” xuất hiện trực tiếp trong văn bản để chỉ vai trò của Arrieta.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">26. …individuals may have to be dependent on the {kindness} of their fellow men.</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>{kindness}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Vị trí:</strong> <strong>Đoạn G (Dòng 6)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Dẫn chứng:</strong> “If Ferdinand represents human malignity and Goya its frailty, then Arrieta stands for man’s innate <strong>kindness</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,3,0\"><strong>Giải thích:</strong> Tác giả đối lập sự độc ác của vua Ferdinand với lòng tốt bẩm sinh của con người được thể hiện qua bác sĩ Arrieta. Trong tóm tắt, ý nói rằng khi con người yếu đuối/bệnh tật, họ phải phụ thuộc vào <strong>lòng tốt</strong> (<em>kindness</em>) của đồng loại.</p>\n</li>\n</ul>\n"}]', 3);
INSERT INTO public.questions VALUES ('d4c08508-0972-4098-9640-1f87a10600a3', 'fbd31dcd-62aa-40b7-8a5f-5bcd0f0d432d', 'radio', 'Questions 31–36', '', '<p>Choose <strong data-start="1519" data-end="1526">YES</strong> — if the statement agrees with the views of the writer, <strong data-start="1584" data-end="1590">NO</strong> — if the statement contradicts the views of the writer, <strong data-start="1648" data-end="1661">NOT GIVEN</strong> — if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Sydney Bradford relied on recollections of objects he had been told about to help him see after his operation"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People who only start to see as adults can learn to see as other people do in time"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People who have gained their sight as adults find certain activities harder to do than before"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It is evident now that sight involves the eyes and one particular area of the brain"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The mask experiment is particularly useful in training people who are regaining their sight"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People with perfect vision can fail to interpret objects correctly under certain circumstances"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">31. NO — Sydney Bradford relied on recollections of objects he had been told about to help him see after his operation.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">“It was his touch memories that enabled him to perceive them with his eyes.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Bradford dựa vào ký ức về những thứ <em data-path-to-node=\"16,1,0\" data-index-in-node=\"60\">được người khác kể cho nghe</em> (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"89\">had been told about</em>). Ngược lại, bài đọc khẳng định ông hoàn toàn dựa vào ký ức xúc giác — tức là những thứ ông đã tự tay chạm vào trước đó (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"230\">touch memories</strong>). Thông tin sai lệch bản chất nên đáp án là <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"289\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. NOT GIVEN — People who only start to see as adults can learn to see as other people do in time.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"18,0,0\" data-index-in-node=\"26\">“Since his operation, his sight has gradually improved as he learns to see, for example, by understanding how shadows represent depth and tell us about the shape of things.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập rằng thị lực của Mike May (người mù bẩm sinh được phẫu thuật khi lớn) đang tiến triển dần dần khi ông học cách hiểu về bóng tối và chiều sâu. Tuy nhiên, văn bản <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"192\">hoàn toàn không khẳng định hay đảm bảo</strong> liệu những người như ông có thể nhìn được hoàn toàn bình thường giống như bao người khác theo thời gian (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"336\">learn to see as other people do in time</em>) hay không. Do đó đáp án là <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"404\">NOT GIVEN</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">33. YES — People who have gained their sight as adults find certain activities harder to do than before.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"20,0,0\" data-index-in-node=\"26\">“He had been a champion blind skier, but following the operation, he would have to shut his eyes while skiing to block out what he now found was a terrifying sight.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi còn mù, Mike May là một nhà vô địch trượt tuyết. Nhưng sau khi phẫu thuật mở mắt, ông thấy việc trượt tuyết trở nên đáng sợ đến mức phải nhắm mắt lại khi thực hiện. Điều này chứng tỏ việc sáng mắt lại khiến một số hoạt động của ông trở nên khó khăn hơn trước (<strong data-path-to-node=\"20,1,0\" data-index-in-node=\"276\">harder to do than before</strong>). Đáp án là <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"313\">YES</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">34. NO — It is evident now that sight involves the eyes and one particular area of the brain.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"22,0,0\" data-index-in-node=\"26\">“Seeing used to be thought of as taking place only in the eyes, and in quite specialised brain regions; but now it seems that half the brain is occupied with seeing...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định thị giác chỉ liên quan đến mắt và <em data-path-to-node=\"22,1,0\" data-index-in-node=\"65\">một vùng bộ não cụ thể</em> (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"89\">one particular area</em>). Ngược lại, bài đọc viết rằng đó là quan niệm cũ, còn hiện nay khoa học chứng minh có đến <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"200\">nửa bộ não</strong> tham gia vào quá trình nhìn (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"240\">half the brain</em>). Thông tin mâu thuẫn hoàn toàn nên đáp án là <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"301\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. NOT GIVEN — The mask experiment is particularly useful in training people who are regaining their sight.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"24,0,0\" data-index-in-node=\"26\">“...people not seeing a hollow face as hollow is the most revealing experiment on perception.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến thí nghiệm mặt nạ (<em data-path-to-node=\"24,1,0\" data-index-in-node=\"51\">mask experiment</em>) nhằm chứng minh người bình thường nhìn thế giới dựa trên kỳ vọng và định kiến có sẵn, chứ <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"158\">không hề có bất kỳ thông tin nào</strong> nói về việc thí nghiệm này được ứng dụng để huấn luyện người đang phục hồi thị lực. Đáp án là <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"285\">NOT GIVEN</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. YES — People with perfect vision can fail to interpret objects correctly under certain circumstances.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"26,0,0\" data-index-in-node=\"26\">“The unsettling truth from brain science is that even people with no visual impairment see what, at some level, they expect to see, and often miss things as they really are.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"People with perfect vision\" tương ứng với cụm \"people with no visual impairment\" (người không bị tật về mắt). Việc họ nhìn theo kỳ vọng và bỏ lỡ bản chất thật của sự vật (<em data-path-to-node=\"26,1,0\" data-index-in-node=\"184\">miss things as they really are</em>) đồng nghĩa với việc họ diễn giải sai lệch vật thể trong một số hoàn cảnh (<strong data-path-to-node=\"26,1,0\" data-index-in-node=\"290\">fail to interpret objects correctly</strong>). Đáp án là <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"338\">YES</strong>.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('743e24b7-0a62-4721-b106-f4b0edf68411', 'fbd31dcd-62aa-40b7-8a5f-5bcd0f0d432d', 'matching', 'Questions 37–40', '', '<p data-start="21" data-end="82">Complete the summary using the list of words, <strong data-start="67" data-end="74">A–J</strong>, below.</p>
<p data-start="84" data-end="159">Write the correct letter, <strong data-start="110" data-end="117">A–J</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<h2 data-section-id=\"vyunwp\" data-start=\"161\" data-end=\"183\">The mask experiment</h2>\n<p data-start=\"185\" data-end=\"720\">In this experiment, having looked at the front of a simple face-mask, subjects look at the reverse. However, the subjects are convinced that they are still looking at a mask which is {G convex} in shape. They believe that the {F nose} is poking out in the normal manner because that is what they are used to seeing. Attempting to make a {I drawing} of the mask in this orientation leads to the same problem. The subjects fail to see a concave form because of the {J preconception} they have that the features of a face stick out.</p>\n<p data-start=\"722\" data-end=\"868\" data-is-last-node=\"\" data-is-only-node=\"\"> </p>", "answerOptions": [{"optionText": "back"}, {"optionText": "brain"}, {"optionText": "view"}, {"optionText": "round"}, {"optionText": "sight"}, {"optionText": "nose"}, {"optionText": "convex"}, {"optionText": "hollow"}, {"optionText": "drawing"}, {"optionText": "preconception"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">37. G (convex)</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"30,0,0\" data-index-in-node=\"26\">“From the front it is a convex shape with one nose sticking out.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi lật mặt sau lõm của mặt nạ, bộ não của người xem bị đánh lừa và họ tin rằng mình vẫn đang nhìn thấy một hình dạng lồi (<strong data-path-to-node=\"30,1,0\" data-index-in-node=\"135\">convex</strong>) giống như mặt trước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">38. F (nose)</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"32,0,0\" data-index-in-node=\"26\">“From the front it is a convex shape with one nose sticking out.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Poking out\" (nhô ra) đồng nghĩa với \"sticking out\". Du khách bị thuyết phục rằng chiếc mũi (<strong data-path-to-node=\"32,1,0\" data-index-in-node=\"105\">nose</strong>) vẫn đang nhô ra ngoài một cách bình thường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">39. I (drawing)</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"34,0,0\" data-index-in-node=\"26\">“It is almost, if not quite, impossible to sketch the back of a hollow mask to look as it is — hollow.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ khóa \"sketch\" (phác thảo/họa lại) trong bài đọc tương ứng với hành động tạo ra một bản vẽ (<strong data-path-to-node=\"34,1,0\" data-index-in-node=\"106\">drawing</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">40. J (preconception)</strong></p>\n<ul data-path-to-node=\"36\">\n<li>\n<p data-path-to-node=\"36,0,0\"><strong data-path-to-node=\"36,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"36,0,0\" data-index-in-node=\"26\">“...even people with no visual impairment see what, at some level, they expect to see...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"36,1,0\"><strong data-path-to-node=\"36,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sở dĩ người xem không nhìn ra dạng lõm là vì họ bị chi phối bởi một định kiến, một ý niệm có sẵn trong đầu (<strong data-path-to-node=\"36,1,0\" data-index-in-node=\"120\">preconception</strong> / <em data-path-to-node=\"36,1,0\" data-index-in-node=\"136\">expect to see</em>) rằng các bộ phận trên khuôn mặt lúc nào cũng phải lồi ra ngoài.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('55b56186-a7a3-4688-a545-a34071d117b9', 'ede127b0-4a6e-4ef5-bc49-41b3eecbd716', 'matrix', 'Questions 15–20', NULL, '<p>What comment does the speaker make about each of the following aspects of fire safety?<br />
Choose the correct letter, A, B or C, next to questions 15–20.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "ensuring there are no obstacles in fire escape routes ", "correctCategoryLetter": "A"}, {"itemText": "checking that fire doors are easily opened ", "correctCategoryLetter": "A"}, {"itemText": "showing staff how to look after each other ", "correctCategoryLetter": "C"}, {"itemText": "training staff to use fire extinguishers correctly ", "correctCategoryLetter": "B"}, {"itemText": "checking that staff are aware of evacuation points ", "correctCategoryLetter": "A"}, {"itemText": "checking that flammable liquids are properly stored ", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "It should be a priority for fire wardens.", "categoryLetter": "A"}, {"categoryText": "It will be dealt with by an external specialist.", "categoryLetter": "B"}, {"categoryText": "It does not require attention.", "categoryLetter": "C"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('03269b19-f5ec-4ad1-9c9d-9e13136a432c', '6d63f38f-87b7-4ae6-8a4a-56e7dacb7927', 'matrix', 'Questions 15–18', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong></p>
<p>How much does Joan like doing each of the following activities?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "correspondence", "correctCategoryLetter": "B"}, {"itemText": "fund-raising", "correctCategoryLetter": "C"}, {"itemText": "calling riders", "correctCategoryLetter": "A"}, {"itemText": "organising accounts", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "She really likes it.", "categoryLetter": "A"}, {"categoryText": "She doesn’t mind it.", "categoryLetter": "B"}, {"categoryText": "She hates it.", "categoryLetter": "C"}]}', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('23d2db98-ff9f-4007-ae1a-3192abcaeb95', 'd962d32e-8405-4650-8fd8-53875d5fcb5a', 'radio', 'Questions 21–26', '', '<p>Choose the correct answers</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. It’s the final day"}, {"option_text": "B. It will be full very soon"}, {"option_text": "C. They don’t have time later on"}], "question": "Why should they choose selective course immediately?"}, {"correct": 2, "options": [{"option_text": "A. Language course"}, {"option_text": "B. Business study"}, {"option_text": "C. Mathematics"}], "question": "What is the compulsory course for all students?"}, {"correct": 0, "options": [{"option_text": "A. It’s useful"}, {"option_text": "B. It’s convenient to take"}, {"option_text": "C. It involves a lot of work"}], "question": "What does Rick think of the course Information Statistics?"}, {"correct": 0, "options": [{"option_text": "A. consult the students about the teaching quality"}, {"option_text": "B. look online about the related information"}, {"option_text": "C. ask their parents for suggestions"}], "question": "What will they do before choosing the selective courses?"}, {"correct": 2, "options": [{"option_text": "A. surprising"}, {"option_text": "B. confusing"}, {"option_text": "C. valuable"}], "question": "How did they feel about the art design class?"}, {"correct": 0, "options": [{"option_text": "A. how they register the course"}, {"option_text": "B. when the course will take place"}, {"option_text": "C. amount of work to be done online"}], "question": "What does Nina want to make sure about selective courses?C"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: SELECTIVE COURSES</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Rick:</strong> Hey Nina, have you chosen a selective course yet?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Nina:</strong> Not really, Rick. I haven’t made up my mind yet. What about you?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Rick:</strong> Me either. We have to decide as soon as possible though.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Nina:</strong> Why? Today’s not the final day for choosing selective courses, is it?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Rick:</strong> No, but <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"14\">(21) they’ll be booked up very soon. Actually, some courses are already full [B – It will be full very soon]</strong>.</span></p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Nina:</strong> Really? That’s too bad. Well, I was thinking of taking a language course. What do you think?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Rick:</strong> Yes, you can do that. You can choose all courses on the school website<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"77\">(22) except mathematics, since it’s a required course for all students [C – Mathematics]</strong></span></span>. By the way, I think business course is a good choice.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Nina:</strong> Yeah, it’s not bad. I think it’s going to be quite helpful after we graduate.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Rick:</strong> I think so. Guess what? I wanted to choose information statistics.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Nina:</strong> Why?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Rick:</strong> It’s related to our major, so <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"36\">(23) I think it’s very useful for us. I mean, we will have an advantage in job hunting [A – It’s useful]</strong>.</span> But the bad thing is it’s in the morning, so we have to skip other classes in order to take it.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Nina:</strong> That’s not good. We need to find an alternative that is more convenient for us. I know it’s a shame.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Rick:</strong> Nina, I think we need to get to know the courses more before choosing them. Otherwise, we may end up studying something that’s either boring or useless.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Nina:</strong> You are right. Maybe we can look online to see if there’s information about it?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Rick:</strong> We could also ask our parents for advice.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Nina:</strong> I don’t think that’s going to help much. People have all kinds of opinions online; we wouldn’t know which one to listen to. And our parents probably don’t know much about our field. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"18\" data-index-in-node=\"188\">(24) I think the best way is asking the former students who have taken the class themselves [A – Consult students]</strong></span>. They can tell us what they thought about it from their own experience.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Rick:</strong> Oh yes, they know it better than anyone. Just like how much we know the art design class.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Nina:</strong> Yes. Before we took it last year, many people said on the internet that it was quite confusing, but it turned out to be quite easy and helpful, right?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Rick:</strong> Mm-hmm. It didn’t let us down. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"21\" data-index-in-node=\"37\">(25) I definitely value the course. Design is an important skill in today’s world [C – Valuable]</strong>.</span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Nina:</strong> Well, whatever course we want to choose, there are still things I need to figure out.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Rick:</strong> What do you mean? Do you mean things like the time of the courses?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Nina:</strong> Since it’s the first time we can choose selective courses, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"24\" data-index-in-node=\"65\">(26) I need to know how to register [A – How they register]</strong>.</span> I think there will be instruction on our school website for registration. I’ll let you know.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Rick:</strong> You are so considerate, Nina. I think that’s necessary. We need to make sure we can register as soon as we make up our mind.</p>\n<hr data-path-to-node=\"26\">\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Nina:</strong> The courses we studied last semester were quite interesting. Maybe we could get some inspiration from those courses. Do you think so?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Rick:</strong> Well, yeah. Some of them were quite fun for me, such as <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"29\" data-index-in-node=\"62\">(27) Metallurgy [E – Useful material online]</strong>. Though there were quite a lot of terms to remember, but <strong data-path-to-node=\"29\" data-index-in-node=\"164\">there’s also a lot of useful information about it on the internet which made things easier</strong>.</span></p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Nina:</strong> That’s right. I can refer to many things when I was working on the paper. And the professor in <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"30\" data-index-in-node=\"101\">(28) Fluid mechanics [D – Professor’s explanation was clear]</strong> was really patient. <strong data-path-to-node=\"30\" data-index-in-node=\"182\">His explanation was crystal clear, so students had no difficulty understanding it</strong>.</span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Rick:</strong> Yes, that’s true. I was good at this course. What do you think of <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"31\" data-index-in-node=\"72\">(29) Computing [A – Became more engaging]</strong>?</span></p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Nina:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"32\" data-index-in-node=\"6\">I think it was kind of boring in the beginning </strong></span>Do you think so? </p>\n<p><strong>Rick</strong>: That’s exactly how I felt. There were a lot of numbers to deal with. But thankfully, it got more interesting when the course went on.</p>\n<p data-path-to-node=\"33\"><strong>Nina</strong><strong data-path-to-node=\"33\" data-index-in-node=\"0\">:</strong> Right, because later we could relate the theories to real-life examples.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Rick:</strong> Exactly! Another course that I think was really practical is <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"33\" data-index-in-node=\"133\">(30) Energy economy [C – Involved lot of practical work]</strong>.</span></p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Nina:</strong> Oh yes, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"34\" data-index-in-node=\"14\">there were a lot of practical works in the course</strong></span>. What we learned can come in handy in our future jobs.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Rick:</strong> We should make the decision based on our own experience and preference. Anyway, we really need to hurry up. I’m sure we can reach a conclusion today.</p>"}]', 0);
INSERT INTO public.questions VALUES ('4e18ad65-a844-439c-afe9-55b80cbac81b', 'a2a298b7-d8c1-4d89-bbcd-872dc7bb5b9c', 'checkbox', 'Questions 21 and 22', '', '<p>What do the speakers agree are the two reasons why children play outdoors less now than in the past?</p>
<p>Choose <strong>TWO </strong>letters, A-E.</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": " A. Concerns about traffic"}, {"correct": false, "option_text": " B. Limited outdoor play facilities"}, {"correct": false, "option_text": " C. Increased time spent online"}, {"correct": false, "option_text": " D. Preference for indoor play"}, {"correct": true, "option_text": " E. Reduction in free time"}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: CHILDREN''S OUTDOOR PLAY RESEARCH</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Dr Chang:</strong> Right Robbie, tell me how the research for your assignment about children''s outdoor play is going.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Ravi:</strong> Yes, well, I''ve been reading about why children spend less time playing outside now than 20 or 30 years ago.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Dr Chang:</strong> So, is it just because of the amount of online time that children have now, which obviously happens indoors?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Ravi:</strong> Well, if that was the case, there''d be a correlation between high internet use and low levels of outdoor play. And it''s nothing to do with whether there are adequate facilities outside—playgrounds, for example—as any open space will do. <strong data-path-to-node=\"6\" data-index-in-node=\"243\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q21/22) There''s perhaps no single more important factor than parental worries about the dangers of vehicles on the streets</span>.</strong></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Dr Chang:</strong> But it could also be that children today prefer playing indoors to outdoors.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Ravi:</strong> Well, a study in Tokyo suggests it''s the other way around. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"65\">(Q21/22) But children are spending more time in structured activities and out-of-school clubs than before, and this has a knock-on effect on</strong></span></p>\n<p data-path-to-node=\"8\"><strong>Dr Chang:</strong><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong> W</strong><strong data-path-to-node=\"8\" data-index-in-node=\"65\">hat''s left for outdoor play.</strong></span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ravi:</strong> Right.</p>\n<p data-path-to-node=\"9\"><strong>Dr Chang: </strong>Your premise is that outdoor play is good. What exactly do you want to focus on in your assignment?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ravi:</strong> Well, not so much on things that apply to exercise in general, like children''s muscles getting stronger because they run around, and not on what seems, for instance, self-evident—that outdoor play helps children to concentrate on things other than lessons.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Dr Chang: </strong>Sure.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ravi: </strong> <strong data-path-to-node=\"10\" data-index-in-node=\"269\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23/24) I''d like to investigate some of the more unexpected benefits like to children''s digestion. This is because fresh air tends to stimulate hunger</span>.</strong>Perhaps leaving to one side the question of whether climbing trees helps educate children about the natural world?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Dr Chang:</strong> No, not really relevant. <strong data-path-to-node=\"12\" data-index-in-node=\"31\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23/24) What sort of decisions do outdoor games and activities force children to make?</span></strong></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Ravi:</strong> <strong data-path-to-node=\"12\" data-index-in-node=\"31\"><span style=\"text-decoration: underline; background-color: #f1c40f;\"> Well, for example, how they decide how dangerous something might be, and I''d like to outline the main findings on that</span>.</strong></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Dr Chang:</strong> Okay. And as you''re arguing that there''s been a shift in play patterns over the last generation or so, how are you going to substantiate this?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Ravi:</strong> Yes, surveys have compared parents'' recollections of their childhood play 30 years ago with what their children do now. And the nature of what children do when they are playing outdoors has changed.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Dr Chang:</strong> How exactly?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Ravi:</strong> Well, surprisingly, it''s not so much how often children play outside or preferences for large or small groups, <strong data-path-to-node=\"16\" data-index-in-node=\"117\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q25/26) but the fact that the play sessions don''t go on for as long</span>.</strong> And games involving one child running after another who tries to get away—these are still as popular as ever. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"297\">(Q25/26) But one thing that has declined is improvised games, and I''d like to examine why this might be.</strong></span></p>\n<p data-path-to-node=\"16\"><strong>Dr. Chang: </strong>Interesting. And what about safety?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"7\" data-index-in-node=\"2770\">Ravi:</strong> Well, from my reading, serious accidents are still rare. More kids hurt themselves falling out of bed than out of trees!</p>\n<hr data-path-to-node=\"17\">\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">FUTURE IMPLICATIONS (Questions 27–30)</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Ravi:</strong> I think the decline of outdoor play is a problem which should worry parents. I mean, perhaps the children themselves don''t miss it, they may be happy to spend lots of time indoors. <strong data-path-to-node=\"19\" data-index-in-node=\"187\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q27) But the links between inactivity and physical problems when they''re adults are so well established that I think kids should be encouraged to spend more time outdoors</span></strong><strong> </strong>with their brothers and sisters and friends.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Dr Chang:</strong> What about schools?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Ravi:</strong> Well, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"12\">(Q28) what I think they should do differently regarding outdoor play—and it wouldn''t actually require a great deal of expenditure—is base their policy on different outcomes, like developing children''s confidence, not just thinking about exam results</strong></span>, although I don''t know how it would go down with the parents.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Dr Chang:</strong> And do children get more contact with nature in rural areas?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Ravi:</strong> There''s research on this by Smith and Barker. Intuitively you''d expect children in rural areas to spend more time out in the open, but <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"141\">(Q29) in fact, they are generally told to keep off agricultural land, plus there are difficulties with supervision outside towns and cities.</strong></span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Dr Chang:</strong> Right. And Smith and Barker''s paper was published in</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Ravi: </strong>2001</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Dr Chang: </strong>Not the most up to date but still valid to use. But you''ll need to stipulate very precisely that their focus was, if I remember correctly, just on rural areas. <strong data-path-to-node=\"24\" data-index-in-node=\"228\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q30) So, you''d need to consider how far their restricted findings might be applicable to urban areas as well</span>.</strong></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Ravi: </strong>Okay.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Dr Chang: R</strong>ight. So now, I''d suggest you produce an overview of what you''re going to cover.</p>"}]', 0);
INSERT INTO public.questions VALUES ('34d08582-fa4e-470a-907f-b5f7f80a3330', 'f0829761-df4d-4c14-a1be-2d2a5756f670', 'fillup', 'Questions 7–10', '<p>Complete the table below.</p>
