', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('dc17970b-fa27-4ef0-8cff-1746288c7baa', '8980edf4-2b69-4169-aade-705346dd1e9a', 'checkbox', 'Questions 17–18', '', '<div class="quests-inner-desc">
