INSERT INTO public.questions VALUES ('16add6b3-2921-469c-a9d9-af3d6bde768b', '6d63f38f-87b7-4ae6-8a4a-56e7dacb7927', 'checkbox', 'Questions 19-20', '', '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>19-20 Joan says the <strong>TWO </strong>ways the RDA needs to improve are by</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. giving special training."}, {"correct": true, "option_text": "B. making fund-raising more effective."}, {"correct": false, "option_text": "C. opening more RDA centres."}, {"correct": false, "option_text": "D. providing more helpers."}, {"correct": true, "option_text": "E. recognising difficulties of disabled riders"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 3);
INSERT INTO public.questions VALUES ('1845d0f4-7e18-4918-b9ca-ad26513a8dc7', '6204f6ae-328d-4a14-bc38-cfde012e66e7', 'radio', 'Questions 36–40', NULL, '<p><span style="font-family: arial, helvetica, sans-serif; font-size: 12pt;">Chosse<strong> YES i</strong>f the statement agrees with the claims of the writer <strong>NO </strong>if the statement contradicts the claims of the writer <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this</span></p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The tone of the content we post on social media tends to reflect the nature of the posts in our feeds."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Phones have a greater impact on our stress levels than other electronic media devices."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The more we read about a stressful public event on social media, the less able we are to take the information in."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Stress created by social media posts can lead us to take unnecessary precautions."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Our tendency to be affected by other people’s moods can be used in a positive way."}]', NULL, NULL, NULL, NULL, 2);
INSERT INTO public.questions VALUES ('187841a3-6133-44f4-b14a-0a00a896cee4', 'd0b39873-2502-43e0-a956-ce29ec9162d5', 'radio', ' Questions 27-30', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 2, "options": [{"content": "Some present studies on children’s mother tongues are misleading."}, {"content": "A culturally rich education programme benefits some children more than others."}, {"content": "Bilingual children can make a valuable contribution to the wealth of a country."}, {"content": "The law on mother tongue use at school should be strengthened."}], "question": "What point is the writer making in the second paragraph?"}, {"correct": 0, "options": [{"content": "to lend weight to his argument"}, {"content": "to contradict some research"}, {"content": "to introduce a new concept"}, {"content": "to update current thinking"}], "question": "Why does the writer refer to something that Goethe said?"}, {"correct": 1, "options": [{"content": "they can teach older family members what they learn at school."}, {"content": "they go on to do much better throughout their time at school."}, {"content": "they can read stories about their cultural background."}, {"content": "they develop stronger relationships with their family than with their peers."}], "question": "The writer believes that when young children have a firm grasp of their mother"}, {"correct": 3, "options": [{"content": "They worry that children will be slow to learn to read in either language."}, {"content": "They think that children will confuse words in the two languages."}, {"content": "They believe that the programmes will make children less interested in their lessons."}, {"content": "They fear that the programmes will use up valuable time in the school day."}], "question": "Why are some people suspicious about mother tongue-based teaching programmes?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\">27. What is the writer making in the second paragraph?</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>Bilingual children can make a valuable contribution to the wealth of a country.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “…and the cultural, linguistic and <strong>economic resources of the nation are maximized</strong>. To waste the resources of the nation by discouraging children from developing their mother tongues is quite simply unintelligent from the point of view of national self-interest.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Tác giả lập luận rằng việc phát triển tiếng mẹ đẻ của trẻ em sẽ <strong>tối đa hóa các nguồn lực kinh tế</strong> (<em>“economic resources are maximized”</em>) của quốc gia, tức là trẻ em song ngữ có thể đóng góp vào sự giàu có của đất nước.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">28. Why does the writer refer to something that Goethe said?</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>to lend weight to his argument.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “More than 150 research studies conducted during the past 35 years <strong>strongly support what Goethe</strong>… once said: that the person who knows only one language does not truly know that language.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Tác giả sử dụng câu nói của nhà triết học nổi tiếng Goethe để <strong>củng cố lập luận</strong> (<em>“strongly support”</em>) của mình về lợi ích của việc biết nhiều ngôn ngữ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"9\">29. The writer believes that when young children have a firm grasp of their mother</h3>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>they go on to do much better throughout their time at school.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “Children who come to school with a <strong>solid foundation in their mother tongue</strong> develop <strong>stronger literacy abilities in the school language</strong>… Children come to school well-prepared to learn the school language and <strong>succeed educationally</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Nền tảng vững chắc trong tiếng mẹ đẻ giúp trẻ phát triển khả năng đọc viết tốt hơn và thành công hơn trong giáo dục (<em>“succeed educationally”</em>), tức là học tốt hơn trong suốt thời gian đi học.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">30. Why are some people suspicious about mother tongue-based teaching programmes?</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>They fear that the programmes will use up valuable time in the school day.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Some educators and parents are suspicious of mother tongue-based teaching programs because <strong>they worry that they take time away from the majority language</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Mối lo ngại chính là các chương trình này sẽ <strong>chiếm mất thời gian</strong> (<em>“take time away”</em>) đáng lẽ phải dùng cho việc học ngôn ngữ đa số.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('54c0876a-aa79-4a62-a3de-93fa61df6b1b', 'd0b39873-2502-43e0-a956-ce29ec9162d5', 'matching', 'Questions 31-35', NULL, '<p>Complete the summary using the list of words, A-J, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>Bilingual children</strong></p>\r\n<p>It has often been noted that bilingual children acquire the {I ability} to converse in the majority language remarkably quickly. The fact that the mother tongue can disappear at a similar {D rate} is less well understood. This phenomenon depends to a certain extent on the proportion of people with the same linguistic background that have settled in a particular {J area}. If this is limited, children are likely to lose the active use of their mother tongue, and thus no longer employ it even with {F family} although they may still understand it. It follows that teenage children in these circumstances experience a sense of {C dislocation} in relation to all aspects of their lives.</p>", "answerOptions": [{"optionText": "A teachers"}, {"optionText": "B school"}, {"optionText": "C dislocation"}, {"optionText": "D rate"}, {"optionText": "E time"}, {"optionText": "F family"}, {"optionText": "G communication"}, {"optionText": "H type"}, {"optionText": "I ability"}, {"optionText": "J area"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"18\">31. It has often been noted that bilingual children acquire the  <strong>I. ability</strong> to converse in the majority language remarkably quickly.</h3>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>I (ability)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “Many people marvel at how quickly bilingual children seem to ‘pick up’ conversational skills in the majority language at school…”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong>Giải thích:</strong> Trẻ song ngữ tiếp thu <strong>khả năng</strong> (<em>ability</em>) giao tiếp bằng ngôn ngữ đa số rất nhanh.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"21\">32. The fact that the mother tongue can disappear at a similar  <strong>D. rate</strong> is less well understood.</h3>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>D (rate)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The <strong>extent and rapidity of language loss</strong> will vary according to the concentration of families from a particular linguistic group…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong>Giải thích:</strong> Sự mất mát ngôn ngữ diễn ra với <strong>tốc độ</strong> (<em>rate</em>) đáng lo ngại, nhưng ít được nhận thức rõ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"24\">33. This phenomenon depends to a certain extent on the proportion of people with the same linguistic background that have settled in a particular  <strong>J. area</strong>.</h3>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>J (area)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The extent and rapidity of language loss will vary according to the <strong>concentration of families from a particular linguistic group in the neighborhood</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong>Giải thích:</strong> Sự mất mát ngôn ngữ phụ thuộc vào sự tập trung của cộng đồng ngôn ngữ trong một <strong>khu vực</strong> (<em>area</em> / <em>neighborhood</em>) cụ thể.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"27\">34. If this is limited, children are likely to lose the active use of their mother tongue, and thus no longer employ it even with  <strong>F. family</strong> although they may still understand it.</h3>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong>Đáp án:</strong> <strong>F (family)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “…they will use the majority language in speaking with their peers and siblings and in responding to their <strong>parents</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong>Giải thích:</strong> Nếu cộng đồng bị phân tán, trẻ em sẽ dùng ngôn ngữ đa số ngay cả khi nói chuyện với bố mẹ (<em>parents</em> / <strong>family</strong>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"30\">35. It follows that teenage children in these circumstances experience a sense of  <strong>C. dislocation</strong> in relation to all aspects of their lives.</h3>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án:</strong> <strong>C (dislocation)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “By the time children become adolescents, the linguistic division between parents and children has become an emotional chasm. <strong>Pupils frequently become alienated from the cultures of both home and school</strong>, with predictable results.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong>Giải thích:</strong> Sự phân chia ngôn ngữ dẫn đến sự xa lánh (<em>alienated</em>) khỏi cả văn hóa gia đình và trường học, gây ra cảm giác lạc lõng (<em>dislocation</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('ca12eabb-dd66-4b64-887b-291578b54c8b', 'ca34beee-e3ed-45f0-9bd3-2bead96da2f6', 'matching', 'Questions 11–16', '', '<p data-start="104" data-end="177">What information is given about each of the following festival workshops?</p>
<p data-start="179" data-end="278">Choose <strong data-start="186" data-end="201">SIX answers</strong> from the box and write the correct letter, <strong data-start="245" data-end="252">A–H</strong>, next to Questions 11–16.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-start=\"646\" data-end=\"678\"><span style=\"font-size: 12pt;\"><strong>Festival workshop</strong></span></p>\n<p data-start=\"646\" data-end=\"678\"> </p>\n<p data-start=\"646\" data-end=\"678\">Superheroes {is aimed at children with a disability}</p>\n<p data-start=\"646\" data-end=\"678\"> </p>\n<p data-start=\"683\" data-end=\"714\">Just do it {involves a drama activity}</p>\n<p data-start=\"683\" data-end=\"714\"> </p>\n<p data-start=\"719\" data-end=\"751\">Count on me {is aimed at a specific age group}</p>\n<p data-start=\"719\" data-end=\"751\"> </p>\n<p data-start=\"756\" data-end=\"785\">Speak up {explores an unhappy feeling}</p>\n<p data-start=\"756\" data-end=\"785\"> </p>\n<p data-start=\"790\" data-end=\"823\">Jump for joy {will be led by a prize-winning author}</p>\n<p data-start=\"790\" data-end=\"823\"> </p>\n<p data-start=\"828\" data-end=\"866\">Sticks and stones {raises awareness of a particular culture}</p>", "answerOptions": [{"optionText": "involves painting and drawing"}, {"optionText": "will be led by a prize-winning author"}, {"optionText": "is aimed at children with a disability"}, {"optionText": "involves a drama activity"}, {"optionText": "focuses on new relationships"}, {"optionText": "is aimed at a specific age group"}, {"optionText": "explores an unhappy feeling"}, {"optionText": "raises awareness of a particular culture"}], "matchingItems": []}', 'null', '[{"content": "<p data-start=\"168\" data-end=\"361\"><strong data-start=\"168\" data-end=\"182\">PRESENTER:</strong> The children’s book festival is coming up again soon and here to tell us all about it is the festival’s organiser, Jenny Morgan. So tell us what we can expect this year, Jenny.</p>\n<p data-start=\"363\" data-end=\"2165\"><strong data-start=\"363\" data-end=\"373\">JENNY:</strong> Well, as usual we’ve got five days of action-packed exciting events for children, with writers coming from all over the country getting involved. Just to give you an idea of what’s on offer in the workshops, first of all, there’s a very special event called Superheroes. <span style=\"background-color: #f1c40f;\"><strong>(11) This is a chance for deaf children to share their reading experiences</strong></span> with author Madeline Gordon, who is herself hearing impaired. ‘Just do it’ is a practical workshop led by the well-known illustrator Mark Keane. He’ll take participants on a magical journey to faraway lands with <strong><span style=\"background-color: #f1c40f;\">(12) an opportunity for aspiring artists to do some role play</span></strong>. ‘Count on me’ is an inspiring and entertaining look at the issues of friendship <strong><span style=\"background-color: #f1c40f;\">(13) for 13–14-year-olds.</span></strong> It looks at some of the friendships described in popular books and asks participants to compare these with their own experiences. ‘Speak up’ is part of a series of workshops on the subject of mental health. This is a creative writing workshop <strong><span style=\"background-color: #f1c40f;\">(14) encouraging children to describe situations where young people experience loneliness</span></strong>. A recent survey revealed that children can be lonely even when they’re at home with their families. ‘Jump for joy’, as many of you will know, is the heart-warming, best-selling story by Nina Karan about a young girl’s trip to visit her relatives in India. <strong><span style=\"background-color: #f1c40f;\">(15) It recently received the gold medal at the Waterford Awards. Nina will get children to celebrate</span></strong> the word ‘joy’ by writing a poem. ‘Sticks and stones’ is the beautifully illustrated picture book for young readers about a community who organise an African-Caribbean festival <strong><span style=\"background-color: #f1c40f;\">(16) to help local children learn about their Jamaican roots</span></strong>. This will be a musical event where children will have the chance to play steel drums. This is bound to be very popular, so please book as soon as possible.</p>\n<p data-start=\"2167\" data-end=\"2318\"><strong data-start=\"2167\" data-end=\"2181\">PRESENTER:</strong> Thanks Jenny. That all sounds really interesting. I’m just wondering if you have a favourite book you could recommend for our readers?</p>\n<p data-start=\"2320\" data-end=\"3062\"><strong data-start=\"2320\" data-end=\"2330\">JENNY:</strong> It’s hard to choose, but <em data-start=\"2356\" data-end=\"2375\">Alive and Kicking</em> is definitely worth mentioning. You won’t have heard of the writer as it’s her first book – which is really impressive. It’s basically the teenage diary of a boy from Somalia who comes to live in the UK. <strong><span style=\"background-color: #f1c40f;\">(17) It deals with the serious issue of immigration</span></strong> and all the challenges the boy has to face at school and with the language barrier, etc. Usually, books like this are quite sad, but <span style=\"background-color: #f1c40f;\"><strong>(18) this one actually made me cry with laughter.</strong></span> On each page, there are simple but hilarious black and white stick drawings of the boy with his friends and teachers. At the end of each diary entry, there are new English words the boy learns each day, which may help develop some children’s vocabulary.</p>\n<p data-start=\"3064\" data-end=\"3197\"><strong data-start=\"3064\" data-end=\"3078\">PRESENTER:</strong> I think my kids would enjoy that. What about any advice for parents on how to encourage their children to read more?</p>\n<p data-start=\"3199\" data-end=\"4069\"><strong data-start=\"3199\" data-end=\"3209\">JENNY:</strong> Well, this is something I get asked about a lot. There are so many distractions for kids these days that it can be hard to find time for reading. One thing I’d say is to make time to sit down with your child and share books with them. A lot of parents give up reading aloud to their children as soon as they learn to read independently, but this is a mistake. It’s good to read more advanced books to them as it helps to develop their vocabulary. If you don’t have time for this, then <strong><span style=\"background-color: #f1c40f;\">(19) let them listen to audiobooks.</span></strong> Often, they’ll want to read books they’ve listened to for themselves. I think it’s a good idea to make a mental note of the type of books your child is reading – often they just read the same genre all the time, which can get a bit boring. You can <span style=\"background-color: #f1c40f;\"><strong>(20) introduce new authors and genres to them. Librarians should be able to help you with this.</strong></span></p>\n<p data-start=\"4071\" data-end=\"4130\"><strong data-start=\"4071\" data-end=\"4085\">PRESENTER:</strong> Well Jenny, I think that’s really useful …</p>"}]', 0);
INSERT INTO public.questions VALUES ('40806911-c5e6-43b2-bb5c-2ee4282062d1', 'ca34beee-e3ed-45f0-9bd3-2bead96da2f6', 'checkbox', 'Questions 17 and 18', '', '<p data-start="901" data-end="929">Choose <strong data-start="908" data-end="928">TWO letters, A–E</strong>.</p>
<p data-start="931" data-end="1008">Which <strong>TWO</strong> reasons does the speaker give for recommending <em data-start="988" data-end="1007">Alive and Kicking</em>?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. It will appeal to both boys and girls."}, {"correct": false, "option_text": "B. The author is well known."}, {"correct": false, "option_text": "C. It has colourful illustrations."}, {"correct": true, "option_text": "D. It is funny."}, {"correct": true, "option_text": "E. It deals with an important topic."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('72a1edd0-7743-4009-90ed-5e36ea430751', 'ee2dab1d-1d3f-4bfa-82f3-c036e621b93d', 'matching', 'Questions 7-10', NULL, '<p>Complete each sentence with the correct ending, A-E, below.</p>
<p>Write the correct letter,<strong> A-E</strong> in boxes 7-10 on your answer sheet.</p>
', 'matching_features', NULL, NULL, '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A. reflects an adolescent’s emerging self-perception."}, {"optionText": "B. cannot solve a problem without an example."}, {"optionText": "C. is designed to become more challenging."}, {"optionText": "D. formulates a personal set of moral beliefs and values."}, {"optionText": "E. varies according to the individual."}], "matchingItems": [{"questionPart": "Havighurst proposed a set of tasks which", "correctAnswer": "A. reflects an adolescent’s emerging self-perception.", "sectionContent": null}, {"questionPart": " A course of study at high school", "correctAnswer": "C. is designed to become more challenging.", "sectionContent": null}, {"questionPart": "The speed of development of thinking ability during adolescence", "correctAnswer": "E. varies according to the individual.", "sectionContent": null}, {"questionPart": "Adolescence is a time when the young person", "correctAnswer": "D. formulates a personal set of moral beliefs and values.", "sectionContent": null}]}', '{"layoutType": "standard", "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"3\">7. Havighurst proposed a set of tasks which <strong>A. reflects an adolescent’s emerging self-perception.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “Each of the Havighurst tasks can also be seen as elements of the <strong>overall sense of self</strong> that adolescents carry with them…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Giáo sư Havighurst cho rằng mỗi nhiệm vụ phát triển là một phần của cảm nhận tổng thể về bản thân (<em>sense of self</em>). Cụm từ “<strong>emerging self-perception</strong>” (nhận thức về bản thân đang hình thành) trong đáp án A đồng nghĩa với “sense of self” trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">8. A course of study at high school <strong>C. is designed to become more challenging.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>C</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “School curricula are frequently dominated by the inclusion of <strong>more abstract, demanding material</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Bài đọc nêu rõ chương trình học ở trường trung học (<em>school curricula</em>) thường bao gồm những tài liệu <strong>đòi hỏi cao hơn và trừu tượng hơn</strong> (<em>more abstract, demanding</em>). Điều này khớp với ý <strong>trở nên thách thức hơn</strong> (<em>more challenging</em>) ở đáp án C.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">9. The speed of development of thinking ability during adolescence <strong>E. varies according to the individual.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “…not all adolescents make the intellectual transition <strong>at the same rate</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Cụm từ “<strong>not at the same rate</strong>” (không cùng tốc độ/tỷ lệ) có nghĩa là mỗi người có một tốc độ phát triển khác nhau. Đáp án E “<strong>varies according to the individual</strong>” (thay đổi tùy theo từng cá nhân) là cách diễn đạt tương đương hoàn hảo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">10. Adolescence is a time when the young person <strong>D. formulates a personal set of moral beliefs and values.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “…they also <strong>adopt an integrated set of values and morals</strong>… the adolescent restructures those beliefs into a <strong>personal ideology</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Ở tuổi vị thành niên, trẻ em không còn chỉ tuân theo quy tắc của cha mẹ mà tự hình thành/xây dựng (<em>restructures/formulates</em>) một hệ thống tư tưởng và giá trị đạo đức cá nhân (<em>personal ideology/moral beliefs and values</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('ad354d1e-25a3-4a43-a5aa-2152e674c72a', 'd0b39873-2502-43e0-a956-ce29ec9162d5', 'radio', 'Questions 36-40', NULL, '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Less than half the children who attend kindergarten in Toronto have English as their mother tongue."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Research proves that learning the host country language at school can have an adverse effect on a child’s mother tongue."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Foyer programme is to be adopted by the French education system."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Bilingual children are taught to tell the time earlier than monolingual children."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": " Bilingual children can eventually apply reading comprehension strategies acquired in one language when reading in the other."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"36\">36. Less than half the children who attend kindergarten in Toronto have English as their mother tongue.</h3>\n<ul data-path-to-node=\"37\">\n<li>\n<p data-path-to-node=\"37,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"37,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “…in the city of Toronto in Canada, <strong>58% of kindergarten pupils come from homes where English is not the language of communication</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"37,2,0\"><strong>Giải thích:</strong> 58% trẻ em không nói tiếng Anh là tiếng mẹ đẻ, nghĩa là <strong>nhiều hơn một nửa</strong> (less than half là sai), do đó phát biểu “Less than half…” là SAI so với thông tin thực tế. Tuy nhiên, trong ma trận trả lời, nếu câu này được đánh dấu <strong>YES</strong> (đồng ý với phát biểu) thì có thể có lỗi trong đáp án gốc, nhưng nếu xét theo nội dung, <strong>58% không phải tiếng Anh</strong> là đúng, suy ra <strong>ít hơn 50%</strong> (42%) có tiếng Anh là tiếng mẹ đẻ. Ta dựa theo nội dung, 58% không phải tiếng Anh, tức là ít hơn 50% có tiếng Anh là tiếng mẹ đẻ, nên câu này <strong>HỢP LÝ</strong> (YES).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"39\">37. Research proves that learning the host country language at school can have an adverse effect on a child’s mother tongue.</h3>\n<ul data-path-to-node=\"40\">\n<li>\n<p data-path-to-node=\"40,0,0\"><strong>Đáp án:</strong> <strong>NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"40,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “One of the most strongly established findings of educational research… is that well-implemented bilingual programs can promote literacy and subject-matter knowledge in a minority language <strong>without any negative effects on children’s development in the majority language</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"40,2,0\"><strong>Giải thích:</strong> Nghiên cứu chứng minh rằng các chương trình song ngữ <strong>không có tác động tiêu cực</strong> (<em>without any negative effects</em>) đến sự phát triển ngôn ngữ đa số. (Mặc dù đoạn 7 nói trẻ em có thể mất khả năng chủ động sử dụng tiếng mẹ đẻ, nhưng nghiên cứu về chương trình song ngữ trong đoạn 5 lại không chỉ ra tác dụng bất lợi. Ta dựa vào kết quả nghiên cứu trong đoạn 5).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"42\">38. The Foyer programme is to be adopted by the French education system.</h3>\n<ul data-path-to-node=\"43\">\n<li>\n<p data-path-to-node=\"43,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"43,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Within Europe, the Foyer program in Belgium, which develops children’s speaking and literacy abilities in three languages… <strong>most clearly illustrates the benefits</strong> of bilingual and trilingual education.”</p>\n</li>\n<li>\n<p data-path-to-node=\"43,2,0\"><strong>Giải thích:</strong> Chương trình Foyer được sử dụng như một <strong>ví dụ</strong> minh họa lợi ích, nhưng <strong>không có thông tin</strong> về việc hệ thống giáo dục Pháp có kế hoạch áp dụng nó hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"45\">39. Bilingual children are taught to tell the time earlier than monolingual children.</h3>\n<ul data-path-to-node=\"46\">\n<li>\n<p data-path-to-node=\"46,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"46,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “Pupils who know how to tell the time in their mother tongue understand the concept of telling time. In order to tell time in the majority language <strong>they do not need to re-learn the concept</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"46,2,0\"><strong>Giải thích:</strong> Bài đọc nói rằng trẻ em song ngữ không cần học lại khái niệm (concept) khi chuyển sang ngôn ngữ thứ hai, nhưng <strong>không so sánh</strong> chúng được dạy học sớm hơn hay muộn hơn trẻ đơn ngữ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"48\">40. Bilingual children can eventually apply reading comprehension strategies acquired in one language when reading in the other.</h3>\n<ul data-path-to-node=\"49\">\n<li>\n<p data-path-to-node=\"49,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"49,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “<strong>Children’s knowledge and skills transfer across languages from the mother tongue to the school language.</strong>” và (Đoạn 6) “…there is <strong>transfer across languages in other skills, such as knowing how to distinguish the main idea from the supporting details of a written passage or story</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"49,2,0\"><strong>Giải thích:</strong> Kiến thức và kỹ năng <strong>chuyển giao qua các ngôn ngữ</strong> (<em>transfer across languages</em>), bao gồm cả các kỹ năng nhận biết ý chính (<em>distinguish the main idea</em>) trong văn bản (<em>written passage</em>).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('d79b30b4-d3b4-4524-8d9b-a51cdb811871', '0d6f900e-11c0-401a-84e2-dc0ce5633373', 'fillup', 'Questions 7-10', '<p>The diagram below gives information about fish fins and their purposes.</p>
<p>Complete the diagram with <strong>NO MORE THAN THREE WORDS</strong> from the passage for each blank</p>
<p><img src="data:image/png;base64," width="563" height="355" loading="lazy"></p>
<p><em>Write your answers in boxes <strong>7-10</strong> on your answer sheet.</em></p>
<p>{forward thrust }</p>
<p>{rolling and yawing }</p>
<p>{Pectoral and pelvic }</p>
<p>{slows and stops }</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">7. forward thrust — {Tail fin contributes to forward thrust}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"21\">The tail fin</strong>, in its final lash may <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"57\">contribute as much as 40 per cent of the forward thrust</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sơ đồ chỉ vào vây đuôi (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"36\">Tail fin</em>) và hỏi về công dụng của nó. Bài đọc chỉ rõ cú quẫy đuôi cuối cùng của vây đuôi có thể đóng góp tới 40% lực đẩy về phía trước (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"172\">forward thrust</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">8. rolling and yawing — {Median fins control rolling and yawing movements}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">The median fins</strong>, that is, the dorsal, anal and ventral fins, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"82\">control the rolling and yawing movements of the fish</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sơ đồ chỉ vào nhóm vây giữa (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"41\">Median fins</em> bao gồm vây lưng, vây hậu môn, vây bụng) và hỏi chức năng. Bài đọc khẳng định nhóm vây này kiểm soát các chuyển động lắc lư cuộn tròn và lệch hướng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"202\">rolling and yawing</strong> movements) của cá bằng cách tăng diện tích bề mặt thẳng đứng đối lưu với nước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">9. Pectoral and pelvic — {Pectoral and pelvic fins act as hydroplanes}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">The paired fins, pectoral and pelvic act as hydroplanes</strong> and control the pitch of the fish...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sơ đồ hỏi tên của các cặp vây (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"43\">paired fins</em>) đóng vai trò như những chiếc cánh ngầm (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">hydroplanes</em>). Bài đọc gọi tên trực tiếp hai cặp vây này là vây ngực và vây chậu (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"177\">Pectoral and pelvic</strong>). Do đề bài cho phép điền tối đa 3 từ (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"236\">NO MORE THAN THREE WORDS</em>) nên việc điền cả cụm tên nối bằng chữ <em data-path-to-node=\"9,1,0\" data-index-in-node=\"300\">and</em> là hoàn toàn chuẩn xác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">10. slows and stops — {Fins are the means by which the fish slows and stops}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The paired fins are also the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"50\">means by which the fish slows down and stops</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sơ đồ hỏi về chức năng bổ sung của cặp vây ngực/chậu nằm ở phía trước. Bài đọc viết chúng là phương tiện giúp cá giảm tốc độ và dừng lại. Từ cần điền là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"165\">slows and stops</strong> (bỏ bớt trạng từ <em data-path-to-node=\"11,1,0\" data-index-in-node=\"198\">down</em> từ cụm <em data-path-to-node=\"11,1,0\" data-index-in-node=\"210\">slows down</em> trong bài đọc để khớp hoàn hảo với cấu trúc ngữ pháp và giới hạn từ của sơ đồ).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('9b493ba5-6291-4bda-8ffb-cd31fceb0440', '0d6f900e-11c0-401a-84e2-dc0ce5633373', 'fillup', 'Questions 11-13', '<p>Complete the summary below using <strong>NO MORE THAN THREE WORDS</strong> from the passage for each blank.</p>
<p>Write your answers in boxes <strong>11-13</strong> on your answer sheet.</p>
<p>Two types of muscles are involved in fish swimming. The majority of a fish’s body comprises the {white muscle} , and the red muscle is found only at the roots of the fins and in a strip along the centre of each flank. For most of its routine movements, the fish uses a lot of its {fats and glycogen} saved in body, and white muscle is mostly used for short-term, fast swimming, such as escaping from {predator}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">11. white muscle — {The majority of a fish’s body comprises the white muscle}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“The <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"25\">bulk of a fish’s body is composed of the so-called white muscle</strong>, while the much smaller areas at the roots of the fins...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"The majority of a fish''s body\" (phần lớn cơ thể cá) đồng nghĩa với cụm \"The bulk of a fish''s body\". Cụm từ \"comprises\" (bao gồm/cấu thành bởi) tương ứng với \"is composed of\". Loại cơ chiếm phần lớn cơ thể cá chính là cơ trắng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"247\">white muscle</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">12. fats and glycogen — {the fish uses a lot of its fats and glycogen saved in body}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“The red muscle receives a good supply of blood and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"72\">contains ampler quantities of fat and glycogen, the storage form of glucose, which is used for most day-to-day swimming movements</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Routine movements\" (các chuyển động thường nhật/hàng ngày) đồng nghĩa với \"day-to-day swimming movements\". \"Saved in body\" (được lưu trữ/tích trữ trong cơ thể) tương ứng với từ \"storage form / contains\". Chất dinh dưỡng được tích trữ dùng cho hoạt động này là chất béo và glycogen (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"295\">fat and glycogen</strong>).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><em data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Lưu ý ngữ pháp:</em> Để câu tóm tắt chuẩn chỉnh hơn, ta có thể viết dạng số nhiều là <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"80\">fats and glycogen</strong> để hòa hợp với danh từ số nhiều ở ngữ cảnh chung, hệ thống vẫn quét đúng từ khóa gốc trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">13. predator — {...such as escaping from predator}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p id=\"p-rc_ff8530834883f9fc-42\" data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<span class=\"citation-559\">However, this huge auxiliary power pack carried by a fish is of crucial significance </span><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"106\"><span class=\"citation-559 citation-end-559\">if the life of the fish is threatened-by a predator, for instance-because it enables the fish to swim rapidly away from dang<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>er</strong>.”</em></p>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Escaping from\" (trốn thoát khỏi) đồng nghĩa với cụm từ \"swim rapidly away from danger\" (bơi thật nhanh thoát khỏi nguy hiểm). Tình huống nguy hiểm đe dọa mạng sống của cá được bài đọc đưa ra ví dụ (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"211\">for instance / such as</em>) chính là từ một kẻ săn mồi (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"263\">predator</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('df6afaf3-a5f3-4237-86cc-60fa7693cc54', '5d02f9c5-10ef-46d4-995f-7e62ba1356db', 'radio', 'Questions 1-6', '<p></p>', '<p>Choose&nbsp;<strong>TRUE&nbsp;</strong>if&nbsp;the&nbsp;statement&nbsp;agrees&nbsp;with&nbsp;the&nbsp;information&nbsp;<strong>FALSE&nbsp;</strong>if&nbsp;the&nbsp;statement&nbsp;contradicts&nbsp;the&nbsp;information&nbsp;<strong>NOT&nbsp;GIVEN&nbsp;</strong>if&nbsp;there&nbsp;is&nbsp;no&nbsp;information&nbsp;on&nbsp;this</p>', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "There are other parrots that share the kakapo’s inability to fly."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Adult kakapo produce chicks every year."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Adult male kakapo bring food back to nesting females"}, {"correct": 2, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The Polynesian rat was a greater threat to the kakapo than Polynesian settlers."}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Kakapo were transferred from Rakiura Island to other locations because they were at risk from feral cats."}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "One Recovery Plan initiative that helped increase the kakapo population size was caring for struggling young birds"}]', NULL, NULL, NULL, NULL, 0);
INSERT INTO public.questions VALUES ('2f743fd4-1219-4ec7-8aa4-62cf9e2472dd', '5971a32d-d158-4282-a451-dd15a92e581b', 'radio', 'Questions 11–16', '', '<p data-start="135" data-end="176">Choose the correct letter, <strong data-start="162" data-end="175">A, B or C</strong>.</p>
<p data-start="178" data-end="349"> </p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A it lasts longer in the ground"}, {"option_text": "B it is practised by more people"}, {"option_text": "C it can be repaired more easily."}], "question": "Heather says pottery differs from other art forms because"}, {"correct": 1, "options": [{"option_text": "Heather reminds her visitors that they should"}, {"option_text": "B the marks that are on it."}, {"option_text": "C the basic shape of it."}], "question": "Archaeologists sometimes identify the use of ancient pottery from"}, {"correct": 2, "options": [{"option_text": "A create an item that looks very old."}, {"option_text": "B find something that they are good at."}, {"option_text": "C make something that will outlive them."}], "question": "Some people join Heather’s pottery class because they want to"}, {"correct": 0, "options": [{"option_text": "A its calming effect"}, {"option_text": "B its messy nature"}, {"option_text": "C its physical benefits"}], "question": "What does Heather value most about being a potter?"}, {"correct": 1, "options": [{"option_text": "A bring friends to join courses."}, {"option_text": "B have never made a pot before."}, {"option_text": "C try to learn techniques too quickly."}], "question": "Most of the visitors to Edelman Pottery"}, {"correct": 2, "options": [{"option_text": "A put on their aprons."}, {"option_text": "B change their clothes."}, {"option_text": "C take off their jewellery."}], "question": "Heather reminds her visitors that they should"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">IELTS LISTENING SCRIPT: PART 2 – EDELMAN POTTERY</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Hello and welcome.</strong> My name’s Heather McCallum and I’m one of the potters who work here at Edelman Pottery. Before we go into the workshop, I just want to say a bit about the craft of pottery. Then we’ll have a look at the equipment, and you can try making a pot of your own.</p>\n<p data-path-to-node=\"4\">Like many people, I’m sure you know that pottery as an art form is tens of thousands of years old, and we know this because it stands the test of time.<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"4\" data-index-in-node=\"152\">Things like baskets and pictures don’t survive in the earth in the same way that pots d</strong><strong>o. (Q11)</strong></span> And even if ancient pots are found in small pieces, they still provide a lot of information about the past.</p>\n<p data-path-to-node=\"5\">There’s no doubt that pottery has given archaeologists a fascinating insight into how ancient humans lived. The shape of an artefact may have been lost, but archaeologists can tell whether the pots were for, say, storage or cooking <span style=\"background-color: #f3db7b;\"><strong>by examining the impressions on the clay, the scratches from tools; (Q12)</strong></span> and the clay itself can reveal where the pots came from.</p>\n<p data-path-to-node=\"6\">When I ask people why they want to take a pottery class with me, they sometimes talk about these things. Like our ancestors, <strong><span style=\"background-color: #f3db7b;\">they hope that something they create will also last longer than they do, (Q13)</span></strong> that their work – whether it is good or not – might say something about humanity many years after their death.</p>\n<p data-path-to-node=\"7\">Of course, you will all have your own reasons for coming here. As far as I’m concerned,<strong> <span style=\"background-color: #f3db7b;\">what I love most is the concentration you need to make a good pot. That focus takes you away from the stresses of everyday life. (Q14)</span></strong> If you’re elderly, it’s also good exercise for hands and wrists and helps with arthritis and, of course, it’s a fun activity for children because it’s so messy!</p>\n<p data-path-to-node=\"8\">Here at Edelman Pottery, we show you some of the basic pottery techniques so that you can use these to create whatever you wish – a gift for a friend, perhaps. <span style=\"background-color: #f3db7b;\"><strong>Like nearly everyone who comes here, I’m sure this is the first time you will have tried the art, (Q15)</strong></span> so we’ll keep things simple today.</p>\n<p data-path-to-node=\"9\">Now, before we move on, can I just say a word about what you’re wearing. As we said in our email,<strong> <span style=\"background-color: #f3db7b;\">please remove any watches, necklaces, etc. (Q16)</span></strong> and put them somewhere safe. If you have long hair, do tie it back now. We’ll provide aprons later, but I trust your clothes are old but comfortable – not your favourite T-shirt or jeans!</p>\n<hr data-path-to-node=\"10\">\n<p data-path-to-node=\"11\">So now we’re in the workshop. Have a look around – there’s a lot going on. To make pottery that will last, you need a potter’s wheel, a kiln – which is basically a very hot oven where you fire the pottery – and some tools.</p>\n<p data-path-to-node=\"12\">So first, the kiln. If you look over in the far corner, you’ll see one of ours. Since their invention, kilns have changed very little, though in the past 20 years, a lot of progress has been made in temperature control. Basically,<strong> <span style=\"background-color: #f3db7b;\">a kiln removes the water from clay at temperatures of around a thousand degrees Celsius. (Q17/18) </span></strong>This allows anything you’ve made to set permanently in shape. It’s a pretty ugly, heavy object that’s hard to keep in a house or flat so most people don’t have one. You may think, ‘Can’t I use my own oven?’ Well, that’s possible but domestic ovens don’t really get hot enough and eventually the clay will crack and fall apart. <strong><span style=\"background-color: #f3db7b;\">Some people fire pottery in a fire pit outside (Q17/18) </span></strong>– but bear in mind that can be dangerous. You also need to know about safety procedures for kilns as they release toxic compounds into the air.</p>\n<p data-path-to-node=\"13\">Every potter needs a potter’s wheel. This machine is used to shape the clay into an object with circular walls or sides – such as a bowl. Its invention revolutionised the pottery industry, allowing multiple items to be produced in a day.</p>\n<p data-path-to-node=\"14\">Lastly, there are a number of different tools that potters use, depending on what they want to make. When you start, your hands can make all kinds of shapes and curves without relying on a sculpting tool. However<span style=\"background-color: #f3db7b;\"><strong>, there are some basic tools that you will need to handle the clay on the wheel. (Q19/20)</strong></span> Some look very strange and have even odder names that you may find hard to remember. Rather than go through them all now, I’ll just name a few tools as we go along.<strong> <span style=\"background-color: #f3db7b;\">We can provide these (Q19/20) </span></strong>and I wouldn’t recommend spending money on them yet.</p>\n<p data-path-to-node=\"15\">So let’s try making a pot of your own…</p>"}]', 0);
INSERT INTO public.questions VALUES ('3b1a5a45-2bf3-4bce-8642-7ca5ad9496e9', 'd31276a3-8a0c-4b27-9e55-e0da2be3c559', 'fillup', 'Questions 7–13', '<p data-path-to-node="4">Complete the notes below.</p>
<p data-path-to-node="4">Choose <strong>ONE WORD ONLY AND/OR A NUMBER</strong> from the passage for each answer. </p>
<h3 style="text-align: center;" data-path-to-node="5">The Project of Arles-Rhône 3</h3>
<p data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0">Timeline and Conservation challenges</strong></p>
<ul data-path-to-node="7">
<li>
<p data-path-to-node="7,0,0">The ship had to be taken out of the river by the end of {2011} because of a cultural event in 2013.</p>
</li>
<li>
<p data-path-to-node="7,1,0">The wood was very soft because its cells were full of {water} after 2,000 years.</p>
</li>
<li>
<p data-path-to-node="7,2,0">The team used a special chemical to replace this liquid and then used a freeze-drying method to save the wood.</p>
</li>
</ul>
<p data-path-to-node="8"><strong data-path-to-node="8" data-index-in-node="0">The sinking of the boat</strong></p>
<ul data-path-to-node="9">
<li>
<p data-path-to-node="9,0,0">When the boat sank, it was carrying a heavy load of 33 tons of {stone}</p>
</li>
<li>
<p data-path-to-node="9,1,0">Experts believe a sudden {flood} caused the boat to sink while it was tied at the quay.</p>
</li>
<li>
<p data-path-to-node="9,2,0">Right after the accident, the ship was buried and protected by a thin layer of {clay} .</p>
</li>
</ul>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">What was found on the boat</strong></p>
<ul data-path-to-node="11">
<li>
<p data-path-to-node="11,0,0">Archaeologists found many personal items such as plates and tools used by the {crew}. .</p>
</li>
<li>
<p data-path-to-node="11,1,0">A silver coin for good luck was also discovered between the wood planks.</p>
</li>
<li>
<p data-path-to-node="11,2,0">Now, the ship is on display in a new part of the local {museum} .</p>
</li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Câu 7: {2011}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“That meant the barge needed to be extracted by the end of the diving season in <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"91\">2011</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để kịp cho sự kiện thủ đô văn hóa năm 2013, các nhà khảo cổ có “deadline” phải đưa con tàu lên mặt nước vào cuối mùa lặn năm 2011.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Câu 8: {water}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“…although the wood of the boat had suffered no microbial decay, <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"78\">water</strong> had filled its cells, leaving the whole structure soft and spongy.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Gỗ không bị mục bởi vi khuẩn nhưng sau 2.000 năm, <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"62\">nước</strong> đã ngấm và lấp đầy các tế bào gỗ, khiến nó trở nên mềm và xốp như bọt biển.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Câu 9: {stone}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“When Arles-Rhône 3 sank, it was carrying 33 tons of <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"64\">stone</strong> for building work.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con số “33 tons” là dấu hiệu nhận biết (key marker). Vật phẩm mà con tàu đang chở khi bị chìm chính là <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"115\">đá</strong> xây dựng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Câu 10: {flood}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“A flash <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">flood</strong> had probably swamped it.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “swamped” (nhấn chìm/ngập nước) đồng nghĩa với việc gây ra vụ chìm tàu. Nguyên nhân là do một trận <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"114\">lũ</strong> quét đột ngột.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Câu 11: {clay}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“…the barge would have been covered in a coating of fine <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"70\">clay</strong> no more than 20 cm thick.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngay sau khi lũ rút, con tàu bị bao phủ bởi một lớp <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"64\">đất sét</strong> mịn. Lớp màng này đóng vai trò như một “chiếc hộp bảo quản” tự nhiên khỏi oxy và vi khuẩn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Câu 12: {crew}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">“This was where the archaeologists discovered the personal effects that the <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"87\">crew</strong> had left on the boat…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Personal effects” (đồ dùng cá nhân) như bát đĩa, dụng cụ nấu ăn tìm thấy trên tàu được xác định là của <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"116\">thủy thủ đoàn</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Câu 13: {museum}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"11\">“Suddenly nine million euros became available to build a new wing on the <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"84\">museum</strong> and put a Roman barge into it.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi được trục vớt và phục chế, con tàu được đưa vào trưng bày tại một khu vực mới (new wing) của <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"113\">bảo tàng</strong> địa phương.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('dbeff8dc-d49b-4c3e-8806-4014fb507f07', 'ca34beee-e3ed-45f0-9bd3-2bead96da2f6', 'checkbox', 'Questions 19 and 20', '', '<p data-start="1213" data-end="1241">Choose <strong data-start="1220" data-end="1240">TWO letters, A–E</strong>.</p>
<p data-start="1243" data-end="1317">Which <strong>TWO</strong> pieces of advice does the speaker give to parents about reading?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. Encourage children to write down new vocabulary."}, {"correct": true, "option_text": "B. Allow children to listen to audio books."}, {"correct": true, "option_text": "C. Get recommendations from librarians."}, {"correct": false, "option_text": "D. Give children a choice about what they read."}, {"correct": false, "option_text": "E. Only read aloud to children until they can read independently."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('811fb4d2-a28d-476b-a809-060daa062486', '48f287f8-b916-47dc-87b1-cc4beee3f084', 'matrix', 'Questions 27–30', '', '<p data-start="71" data-end="122">Which paragraph contains the following information?</p>
<p data-start="124" data-end="199">Write the correct letter, <strong data-start="150" data-end="157">A–H</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "a comparison between people''s preferences towards language and art", "correctCategoryLetter": "F"}, {"itemText": "why people may have misunderstood how a certain animal moves", "correctCategoryLetter": "H"}, {"itemText": "a contrast between the techniques used in two pictures", "correctCategoryLetter": "G"}, {"itemText": "a possible negative effect of using the term ‘art’", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. F — a comparison between people''s preferences towards language and art</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Just as some of us would rather people use few words and gestures and leave something to be guessed, so some of us would rather look at paintings or sculptures which are open to interpretation.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F đưa ra một phép so sánh tương đồng (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"55\">Just as..., so...</em>): cũng giống như một số người thích người khác sử dụng ít ngôn từ/cử chỉ (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"147\">few words and gestures</em> - ngôn ngữ) để tự đoán, thì một số người cũng thích ngắm nhìn những bức tranh hoặc bức tượng mở ra nhiều cách hiểu (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"286\">open to interpretation</em> - nghệ thuật).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. H — why people may have misunderstood how a certain animal moves</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“For generations, paintings showed horses galloping with outstretched legs in full flight through the air, and we came to believe that this was indeed how they moved.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn H giải thích lý do vì sao mọi người bị hiểu lầm về cách loài ngựa di chuyển: đó là do trong nhiều thế hệ, các bức tranh luôn vẽ ngựa phi nước đại với đôi chân duỗi thẳng trên không, khiến người xem tin rằng đó là cách chúng chuyển động ngoài đời thực cho đến khi nhiếp ảnh ra đời chứng minh điều ngược lại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. G — a contrast between the techniques used in two pictures</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“But who would say that Rembrandt''s drawing of an elephant is necessarily less good because it shows fewer details? Indeed Rembrandt gave us the feel of the elephant''s wrinkly skin with just a few lines of his chalk.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn G tạo ra một sự tương phản rõ rệt giữa hai kỹ thuật vẽ: một bên là Dürer với bức vẽ con thỏ rừng cực kỳ tỉ mỉ, ghi lại từng chi tiết nhỏ nhất (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"160\">every tiny detail is carefully recorded</em>), và một bên là Rembrandt vẽ con voi bằng kỹ thuật tối giản, ít chi tiết hơn nhưng vẫn tạo ra cảm giác chân thực chỉ bằng vài đường phấn (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"338\">just a few lines of his chalk</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. A — a possible negative effect of using the term ‘art’</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“You may crush an artist by telling him that what he has just done may be quite good in its own way, only it is not true art.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A chỉ ra một tác động tiêu cực (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"49\">negative effect</em>) khi chúng ta sử dụng từ \"nghệ thuật\" (viết hoa chữ cái đầu thành một nỗi ám ảnh) là bạn có thể hủy hoại, đè bẹp một người nghệ sĩ (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"197\">crush an artist</em>) bằng cách phán xét rằng tác phẩm của họ không phải là nghệ thuật chân chính (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"291\">not true art</em>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7125c6b9-5d44-4183-a053-aa580349048e', '883201d5-f7a9-428e-8ab9-5c47c80590c6', 'matrix', 'Questions 14–19', '', '<p>Which section contains the following information?</p>
<p>Write the correct letter,<strong> A–G</strong>, in boxes 14–19 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "research in which two substances that tasted alike had different effects on the subjects", "correctCategoryLetter": "E"}, {"itemText": "an instance where controlling emotions while viewing something upsetting led to a lack of perseverance in other activities", "correctCategoryLetter": "B"}, {"itemText": "an explanation of why it is important to eat something before making a decision at the end of the day", "correctCategoryLetter": "G"}, {"itemText": "a reference to a researcher who was not initially convinced of the effect of glucose", "correctCategoryLetter": "F"}, {"itemText": "an account of research that mirrored an experience the researcher had in his personal life", "correctCategoryLetter": "C"}, {"itemText": "an example of how the location of products in a shop can be used to take advantage of ‘decision fatigue’", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. research in which two substances that tasted alike had different effects — {E}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…lemonade mixed either with <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"42\">sugar or with a diet sweetener</strong>. …the sugarless sweeteners <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"102\">tasted similar</strong> but did not contain the glucose.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thí nghiệm so sánh nước chanh pha đường và chất tạo ngọt ăn kiêng (vị giống nhau) nhưng chỉ có đường mới phục hồi được ý chí.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. controlling emotions while viewing something upsetting led to a lack of perseverance — {B}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “When they tried to <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"31\">resist the urge to cry during a sad movie</strong>, afterwards they <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"90\">gave up more quickly</strong> on tasks requiring self-discipline…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc kìm nén cảm xúc khi xem phim buồn khiến đối tượng nghiên cứu mất đi sự kiên trì (perseverance) trong các bài tập hình học sau đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. an explanation of why it is important to eat something before making a decision — {G}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “If a decision must be made late in the afternoon… they know <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"74\">not to do it on an empty stomach</strong>.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Baumeister khuyên không nên đưa ra quyết định vào cuối ngày khi bụng đói (cần nạp năng lượng/glucose).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. a reference to a researcher who was not initially convinced of the effect of glucose — {F}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"12\">Todd Heatherton</strong>… <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"31\">didn’t see how this process could be caused simply by variations in glucose levels</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Heatherton ban đầu có sự dè dặt (reservations) và không tin rằng chỉ sự thay đổi glucose có thể gây ra hiện tượng này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. an account of research that mirrored an experience the researcher had in his personal life — {C}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"12,0,0\" data-index-in-node=\"12\">Levav recalls</strong>, ‘I couldn’t tell the choices apart anymore…’ Levav <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"80\">put the experience to use in an experiment</strong> conducted at German car dealerships…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Levav đã dùng chính trải nghiệm mệt mỏi khi đi may bộ đồ cưới của mình để thiết kế thí nghiệm mua xe ô tô.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. an example of how the location of products in a shop can be used — {D}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…sweet snacks are featured <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"41\">prominently at cash registers</strong> at most supermarkets.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc đặt đồ ngọt tại quầy thu ngân tận dụng sự suy yếu ý chí của khách hàng sau khi đã mua sắm xong.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e754801e-299d-417c-a0eb-4daa04abe025', 'c9f8e19a-9d15-492a-8c4a-dc825b974dca', 'radio', 'Question 21-26', NULL, '<p>Choose the correct letter A, B or C.</p>
<p><span style="font-size: 12pt;"><strong>Research on the effect of walking on creativity</strong></span></p>
', 'multiple-choice', '[{"correct": 1, "options": [{"content": "A. she has read it too."}, {"content": "B. what she says reminds him of it."}, {"content": "C. he thinks she might like to do similar research."}], "question": "Daniel mentions the research about walking and creativity to Katie because"}, {"correct": 0, "options": [{"content": "A. sitting."}, {"content": "B. running."}, {"content": "C. listening to music."}], "question": "In the experiments, researchers compared participants’ creativity when walking and when"}, {"correct": 1, "options": [{"content": "A. type of control group."}, {"content": "B. pattern of activities."}, {"content": "C. way of selecting participants."}], "question": "Daniel says that in each experiment, there was a different"}, {"correct": 0, "options": [{"content": "A. biased in favour of certain people."}, {"content": "B. a good indicator of creativity."}, {"content": "C. open to personal interpretation."}], "question": "Daniel thinks the experiment with words is"}, {"correct": 2, "options": [{"content": "A. they are doubtful about its aims."}, {"content": "B. they are confused by its methods."}, {"content": "C. they are cautious about its conclusions."}], "question": "What is Katie and Daniel’s attitude to the experiment on focused thinking?"}, {"correct": 1, "options": [{"content": "A. whether other types of exercise affect creativity."}, {"content": "B. the cause of the improvement in creativity."}, {"content": "C. how the results can be applied to creativity in real life."}], "question": "Katie thinks that the best way forward is to consider"}]', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear two psychology students called Katie and Daniel discussing how taking a walk can affect people&#8217;s creativity and physical well being. First you have some time to look at questions 21 to 26 on page five. Now listen carefully and answer questions 21 to 26.</p>\n<p><strong>Katie:</strong> Hi Daniel.</p>\n<p><strong>Daniel:</strong> Katie, you look as if you&#8217;re off somewhere.</p>\n<p><strong>Katie:</strong> Yes, I was just heading out for a walk.</p>\n<p><strong>Daniel:</strong> Hmm, funny. I was just reading an article about some research that&#8217;s been done on the effects of walking on creativity.</p>\n<p><strong>Katie:</strong> Huh? Sounds interesting. I&#8217;ve always found walking helped me think.</p>\n<p><strong>Daniel:</strong> But this article confirms that everybody can benefit.</p>\n<p><strong>Katie:</strong> Oh, tell me more.</p>\n<p><strong>Daniel:</strong> Okay, but I may even do some more research on it at some point, so don&#8217;t pinch my idea! Promise! <em>(haha)</em></p>\n<hr />\n<p><strong>Daniel:</strong> Well, in the experiments, the researchers tested participants&#8217; creativity by comparing how many ideas they thought of while they were walking, compared to while they were doing other activities.</p>\n<p><strong>Katie:</strong> What, like listening to music?</p>\n<p><strong>Daniel:</strong> Nothing like that, but they did analyze the ideas participants came up with when <strong>(Question 22) sitting</strong> both outdoors and inside. What I found surprising was that they didn&#8217;t compare walking to other forms of exercise, like running for example.</p>\n<p><strong>Katie:</strong> Right. So what was the difference between the experiments?</p>\n<p><strong>Daniel:</strong> Well, in each one, the activities were put together in different ways. Several of the experiments specifically focused on the ability of participants to come up with new ideas. Then the final experiment was a control test of sorts.</p>\n<p><strong>Katie:</strong> Oh, right.</p>\n<p><strong>Daniel:</strong> In one experiment, participants had to think of unusual uses for three everyday objects within a time limit. Okay, and then there was an experiment with words.</p>\n<p><strong>Katie:</strong> What did they ask them to do?</p>\n<p><strong>Daniel:</strong> Compare words in unusual ways. For example, the word &#8216;sweet&#8217;. If participants simply said &#8216;sweet as sugar&#8217;, that wasn&#8217;t creative, but an answer like &#8216;sweet as a cat with honey on its paws&#8217; was okay.</p>\n<p><strong>Katie:</strong> I can see why they&#8217;d ask them to do that. Really, I just don&#8217;t see how the experiment is fair.</p>\n<p><strong>Daniel:</strong> Why?</p>\n<p><strong>Katie:</strong> Because the conclusions are based only on the researcher&#8217;s opinion?</p>\n<p><strong>Daniel:</strong> I think it&#8217;s more that anyone who&#8217;d studied language would be at an <strong>(Question 24) advantage</strong>. <em>(hmm)</em></p>\n<hr />\n<p><strong>Daniel:</strong> OK, was there an experiment about focused thinking?</p>\n<p><strong>Katie:</strong> Yeah, there was. It aimed to find out if walking helped focused thinking. Though I wasn&#8217;t sure that I agreed with their findings. They decided that walking doesn&#8217;t help this type of thinking.</p>\n<p><strong>Daniel:</strong> What evidence did they have?</p>\n<p><strong>Katie:</strong> Well, that&#8217;s it. I don&#8217;t think there was enough evidence to support their <strong>(Question 25) conclusions</strong>, even if their methods were sound.</p>\n<p><strong>Daniel:</strong> Well, I&#8217;d certainly hesitate before making such a bold statement. Still, it&#8217;s a first step, isn&#8217;t it?</p>\n<p><strong>Katie:</strong> I suppose. To move forward with this, they&#8217;ll need to test other ways people keep fit, like swimming. That would be useful.</p>\n<p><strong>Daniel:</strong> But personally, I&#8217;d like to know more about the <strong>(Question 26) fundamental reason</strong> for the effect on people&#8217;s creativity. That would be good.</p>\n<p><strong>Katie:</strong> Then it could be applied more widely in work, for example.</p>\n<p><strong>Daniel:</strong> Again, that&#8217;s secondary really.</p>\n<hr />\n<p><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions 27 to 30 on page six. Now listen and answer questions 27 to thirty.</p>\n<p><strong>Daniel:</strong> But how would you test walking if you wanted to assess its physical benefits?</p>\n<p><strong>Katie:</strong> Well, firstly, I&#8217;d like to know more about the benefits of different situations. What about the effect of footwear?</p>\n<p><strong>Daniel:</strong> Hmm, hadn&#8217;t thought of that.</p>\n<p><strong>Katie:</strong> Well, I&#8217;ve read that shoes with <strong>(Question 27) thinner soles</strong> were found to be better for people&#8217;s joints. It even made the skeletal structure <strong>(F) tougher</strong>.</p>\n<p><strong>Daniel:</strong> Interesting. Was that because they lost weight?</p>\n<p><strong>Katie:</strong> Not as far as I&#8217;m aware.</p>\n<hr />\n<p><strong>Daniel:</strong> And then there&#8217;s walking in the mountains.</p>\n<p><strong>Katie:</strong> Walking in the mountains, hmm. I think I&#8217;ve read something about that. Doesn&#8217;t altitude help people regulate their sleep patterns?</p>\n<p><strong>Daniel:</strong> Hmm, it&#8217;s more that it improves your <strong>(Question 28) vision (C)</strong>. It must be those breathtaking views.</p>\n<p><strong>Katie:</strong> Yeah. And what about the effect that walking has for <strong>(Question 29) elderly people</strong>? Better balance by any chance?</p>\n<p><strong>Daniel:</strong> More than that. It had a positive effect by helping them maintain their body clock&#8217;s natural rhythm, both when going to bed and waking up <strong>(E)</strong>.</p>\n<p><strong>Katie:</strong> Right.</p>\n<hr />\n<p><strong>Katie:</strong> And what about the effect of walking <strong>(Question 30) long distances</strong>?</p>\n<p><strong>Daniel:</strong> Well, a person needs to find the balance between their optimum speed and their natural breathing pattern. Once they&#8217;re synchronized, they can just keep on going for much longer periods than they could before <em>(hmm)</em> <strong>(B)</strong>.</p>\n<p><strong>Katie:</strong> I can see how that would work. But anyway, you&#8230;</p>\n<p><strong>Narrator:</strong> That is the end of Section 3. You now have half a minute to check your answers. Now turn to Section 4 on page seven.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('f78b6b43-d6e8-43bc-830b-b96dc7767a6e', 'd514e886-4797-43ef-b5f1-60d8b88f114f', 'radio', 'Questions 21–25', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<p data-section-id="uzie72" data-start="173" data-end="220"><strong data-start="177" data-end="220">Science experiment for Year 12 students</strong></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A worried that they are not making progress"}, {"option_text": "B challenged by their poor behaviour in class"}, {"option_text": "C frustrated at their lack of interest in the subject"}], "question": "How does Clare feel about the students in her Year 12 science class?"}, {"correct": 1, "options": [{"option_text": "A He is concerned that the results might not be meaningful."}, {"option_text": "B He feels some of the data might be difficult to obtain."}, {"option_text": "C He suspects that the conclusions might be upsetting."}], "question": "How does Jake react to Clare’s suggestion about an experiment based on children’s diet?"}, {"correct": 0, "options": [{"option_text": "A Any results may not apply to humans."}, {"option_text": "B It may be complicated to get permission."}, {"option_text": "C Students may not be happy about animal experiments."}], "question": "What problem do they agree may be involved in an experiment involving animals?"}, {"correct": 0, "options": [{"option_text": "A Are mice capable of controlling their food intake?"}, {"option_text": "B Does an increase in sugar lead to health problems?"}, {"option_text": "C How much do supplements of different kinds affect health?"}], "question": "What question do they decide the experiment should address?"}, {"correct": 2, "options": [{"option_text": "A other types of food supplement."}, {"option_text": "B different genetic strains of mice."}, {"option_text": "C varying amounts of exercise."}], "question": "Clare might also consider doing another experiment involving"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('01989adb-2bc2-458b-b825-7c3311719989', '8cc1e3fb-d98f-4633-8df0-fc5a2928c2bb', 'radio', 'Questions 1-6', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The instrument found in Queen Shub-Ad’s tomb is the world’s oldest known version of a harp"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Today’s Afghan panchtar is very similar to an ancient Mesopotamian instrument."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Egyptian singer Har-Mole was an excellent tanbur player."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Cairo Archaeological Museum contains many historic musical instruments."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The instrument carved in stone at Alaca Huyuk is consistent with Dr Michael Kasha’s definition of a guitar"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The different instruments that appeared in medieval literature had the same number of strings."}]', 'null', 'null', 'null', '[{"content": "<p>1. The instrument found in Queen Shub-Ad’s tomb is the world’s oldest known version of a harp.</p>\n<ul data-path-to-node=\"3\">\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “The <strong>earliest stringed instruments currently known</strong> to archaeologists are bowl harps… Around 2500-2000 BC more advanced harps, such as the beautifully carved 11-stringed instrument <strong>found in the tomb of Queen Shub-Ad</strong>… <strong>started to appear</strong>.”</li>\n<li><strong>Giải thích:</strong> Bowl harps là những nhạc cụ dây được biết đến sớm nhất. Cây đàn trong lăng mộ Queen Shub-Ad là một ví dụ về harp <strong>tiên tiến hơn</strong> (more advanced) và <strong>chỉ bắt đầu xuất hiện</strong> khoảng 2500-2000 TCN, trong khi bowl harps đã có từ hàng thiên niên kỷ trước.</li>\n</ul>\n<p>2. Today’s Afghan panchtar is very similar to an ancient Mesopotamian instrument.</p>\n<ul data-path-to-node=\"5\">\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “Archaeologists have also found <strong>many similar relics amongst the ruins of the ancient Mesopotamian civilisation</strong>. <span class=\"citation-9\">Many of these instruments have </span><strong><span class=\"citation-9\">survived into modern times in almost unchanged form</span></strong><span class=\"citation-9\">, for example folk instruments of the region such as the Turkish saz and Afghan </span><strong><span class=\"citation-9\">panchtar</span></strong><span class=\"citation-9 citation-end-9\">.”</span></li>\n<li><strong>Giải thích:</strong> Văn bản khẳng định panchtar ngày nay rất giống (almost unchanged form) với các di vật cổ của Lưỡng Hà (Mesopotamian).</li>\n</ul>\n<p>3. The Egyptian singer Har-Mole was an excellent tanbur player.</p>\n<ul data-path-to-node=\"7\">\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong><span class=\"citation-8\"> (Đoạn C) “At 3,500 years old, the tanbur which belonged to the Egyptian </span><strong><span class=\"citation-8\">singer Har-Mose</span></strong><span class=\"citation-8 citation-end-8\"> is the earliest known example of this instrument.</span></li>\n<li><strong>Giải thích:</strong> Har-Mose được biết đến là ca sĩ, nhưng <strong>không có thông tin</strong> đánh giá khả năng chơi tanbur của ông.</li>\n</ul>\n<p>4. <span class=\"citation-7 citation-end-7\">Cairo Archaeological Museum contains many historic musical instruments.</span></p>\n<ul data-path-to-node=\"9\">\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “It can be seen today at the <strong>Archaeological Museum in Cairo</strong>.”</li>\n<li><strong>Giải thích:</strong> Văn bản chỉ nói chiếc tanbur của Har-Mose được trưng bày ở đó, <strong>không đề cập</strong> đến số lượng nhạc cụ lịch sử nói chung.</li>\n</ul>\n<p>5. The instrument carved in stone at Alaca Huyuk is consistent with Dr Michael Kasha’s definition of a guitar.</p>\n<ul data-path-to-node=\"11\">\n<li><strong>Đáp án: TRUE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “Dr Michael Kasha defines a guitar as having ‘a long, fretted neck, flat wooden soundboard, ribs, and a <strong>flat back, most often with sides that curve inwards</strong>‘… The oldest known visual representation… shows a 3,300-year-old instrument with a long neck and <strong>sides that clearly curve inwards</strong>.”</li>\n<li><strong>Giải thích:</strong> Mô tả về nhạc cụ ở Alaca Huyuk (“long neck and sides that clearly curve inwards”) <strong>phù hợp</strong> (consistent) với phần định nghĩa quan trọng của Kasha.</li>\n</ul>\n<p>6. The different instruments that appeared in medieval literature had the same number of strings.</p>\n<ul data-path-to-node=\"13\">\n<li><strong>Đáp án: FALSE</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “The earliest guitar-like instruments to arrive in Europe had, most often, <strong>four strings</strong>. Many such instruments, and <strong>variations with from three to five strings</strong>, can be seen in mediaeval illustrated manuscripts.”</li>\n<li><strong>Giải thích:</strong> Các nhạc cụ này có số lượng dây khác nhau (từ ba đến năm), mâu thuẫn với việc có cùng số lượng dây.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('5296afa0-4903-4bf2-870e-0870b0d6be63', '9d0a6b49-6729-441c-8630-79b47907f883', 'radio', 'Single Choice ', 'Single Choice Question', NULL, 'multiple_choice_single', '[{"correct": "Hello", "options": [{"option_text": "Hello"}, {"option_text": "Hi"}], "question": "Question 1"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('4da23f17-44d4-4467-9094-17ff17aa9aa3', '9d0a6b49-6729-441c-8630-79b47907f883', 'matrix', 'Questions 14–18', 'The text has five paragraphs, A–E. Which paragraph contains the following information?', NULL, 'other', 'null', 'null', 'null', '{"matrix_items": [{"item_text": "a description of a company that provides financial assistance for employees to continue their learning", "correct_category_letter": "B:B"}, {"item_text": "a mention of worldwide trends in the changing attitudes of businesses and customers", "correct_category_letter": "E:E"}, {"item_text": "details about years of continuous service by employees at one company", "correct_category_letter": "C:C"}, {"item_text": "a reference to the reason why many people-centered workers first start their own businesses", "correct_category_letter": "A:A"}, {"item_text": "a comment about how certain groups are still fighting for respect in the business world", "correct_category_letter": "D:D"}], "matrix_categories": [{"category_text": "A", "category_letter": "A"}, {"category_text": "B", "category_letter": "B"}, {"category_text": "C", "category_letter": "C"}, {"category_text": "D", "category_letter": "D"}, {"category_text": "E", "category_letter": "E"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('a555df56-0944-4d1e-898c-62297ceca210', '883201d5-f7a9-428e-8ab9-5c47c80590c6', 'fillup', 'Questions 20–22', '<p>Complete the summary below.</p>
<p>Choose<strong> ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;" data-path-to-node="8"><span style="font-size: 14pt;"><strong data-path-to-node="8" data-index-in-node="0">The biological price of decision-making</strong></span></p>
<p>Even when people attempt to be {rational}, they experience ‘decision fatigue’ if they make several decisions in a row. They are not aware of how {tired} they are, but it is increasingly more difficult for their brains to make decisions as the day progresses. After making many decisions in one day, the brain seeks {shortcuts} in order to conserve energy. The person may fail to consider the consequences of their decision or not make a decision at all. Avoiding decisions reduces the immediate strain but can cause difficulties later.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Even khi people attempt to be {rational}, they experience ‘decision fatigue’…</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “No matter how <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"26\">rational</strong> people try to be, they can’t make decision after decision without paying a biological price.” (Đoạn A)</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. They are not aware of how {tired} they are…</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “People are <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"23\">not conscious of being tired</strong>, but nevertheless they are low on energy.” (Đoạn A)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. After making many decisions in one day, the brain seeks {shortcuts} in order to conserve energy.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the more choices one makes… eventually it [the brain] looks for <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"81\">shortcuts</strong>…” (Đoạn A)</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b379c016-e600-4fd9-9264-33a4281da628', '8cc1e3fb-d98f-4633-8df0-fc5a2928c2bb', 'fillup', 'Questions 7–13', '<p>Complete the table below.</p>
<p>Write<strong> ONE WORD ONLY </strong>from the passage for each answer.</p>
<p><span style="font-size: 12pt;"><strong>The development of the guitar</strong></span></p>
<table class="MsoNormalTable" style="border-collapse: collapse; border: 1px solid #000000; width: 100%; height: 350.938px;" border="1" cellpadding="0">
<thead>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%; text-align: center;"><strong>Date</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%; text-align: center;"><strong>Type of instrument</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%; text-align: center;"><strong>Notes</strong></td>
</tr>
</thead>
<tbody>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"><strong>13th–19th century</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">Chitarra</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">was a development of an earlier instrument called the {Chartar} • extra strings added in 16th century in Italy</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"><strong>from around the 1850s</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">Classical guitar</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">its shape a result of modifications including a larger {body} introduced by Antonio Torres • changes produced better tone and greater {volume}</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"> </td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">X-braced top guitar</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">first made in {America} in mid-19th century • strings made of {steel} became available around 1900</td>
</tr>
<tr style="height: 70.1875px;">
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.8739%;"><strong>1920s onwards</strong></td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 14.1049%;">Electric guitar</td>
<td style="border: 1px solid #000000; padding: 0.75pt; width: 69.5947%;">in the 1920s, {pickups} added to guitars • a well-known version brought out by {Gibson}</td>
</tr>
</tbody>
</table>
<p data-start="822" data-end="898"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p>7. Chitarra… was a development of an earlier instrument called the <strong>chartar</strong>.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>chartar</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong><span class=\"citation-6\">Dẫn chứng:</span></strong><span class=\"citation-6\"> (Đoạn G) “When the four-stringed Persian </span><strong><span class=\"citation-6\">chartar</span></strong><span class=\"citation-6 citation-end-6\"> arrived in Spain, however, it changed in form and construction…</span> It became known as the <strong>chitarra</strong>.</p>\n</li>\n</ul>\n<p>8. Classical guitar… modifications including a larger <strong>body</strong> introduced by Antonio Torres.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>body</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong><span class=\"citation-5\">Dẫn chứng:</span></strong><span class=\"citation-5\"> (Đoạn H) “…the Spanish guitar maker Antonio Torres </span><strong><span class=\"citation-5\">increased the size of the body</span></strong><span class=\"citation-5 citation-end-5\">…”</span></p>\n</li>\n</ul>\n<p>9. Classical guitar… changes produced better tone and greater <strong>volume</strong>.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án:</strong> <strong>volume</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “His design radically increased the <strong>volume</strong> and improved the tone of the instrument…”</p>\n</li>\n</ul>\n<p>10. X-braced top guitar… first made in <strong>America</strong> in mid-19th century.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>America</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “German immigrants to <strong>America</strong> – among them Christian Fredrich Martin – began making guitars with X-braced tops.”</p>\n</li>\n</ul>\n<p>11. X-braced top guitar… strings made of <strong>steel</strong> became available around 1900.</p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>steel</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn I) “<strong>Steel</strong> strings, which became widely available several decades later in the early 1900s…”</p>\n</li>\n</ul>\n<p>12. Electric guitar… in the 1920s, <strong>pickups</strong> added to guitars.</p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>pickups</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “The electric guitar was born when <strong>pickups</strong> were fitted to Hawaiian and jazz guitars in the late 1920s…”</p>\n</li>\n</ul>\n<p>13. Electric guitar… a well-known version brought out by <strong>Gibson</strong>.<button class=\"button ng-star-inserted\" data-hveid=\"0\" data-ved=\"0CAAQvoAQahgKEwjP3Z24ivKQAxUAAAAAHQAAAAAQ5gE\"></button></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>Gibson</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn J) “…met with little success until 1836, when <strong>Gibson</strong> introduced its famous ES150 model.”</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('0489fbab-4ebf-453e-824d-4d1cc3fabd52', '9d0a6b49-6729-441c-8630-79b47907f883', 'fillup', '', 'Use { } brackets to identify the word(s) you would like to test, e.g. I {play} soccer. You can also specify multiple words using the | key, e.g. I {play | hate | love} soccer. In this case, play, love or hate will all be marked as correct. This option is useful for multiple spellings. However, lower case and upper case letters will be ignored.', 'Complete the summary. Write ONE WORD ONLY from the text for each answer.

Family-friendly practices at Plastic Solutions and the Margaret Mills Corporation

At Plastic Solutions, a bi-weekly update is issued to workers at the same time as their pay. This includes a section dealing with problems such as {gossip} in communal areas of the workplace. The CEO also arranges a regular {seminar} for selected employees for workplace skills which are in great demand. Finally, employees’ families are invited to company open days, when they are allowed to try out the {machines}.

The Margaret Mills Corporation allows employees a degree of flexibility with their children, who can be brought to the office once {school} has finished. Mills likes to reward employees for company performance with a party or even a {trip} for families. There is considerable evidence that these practices are having the desired effect.', 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "gossip"}, {"content": "seminar"}, {"content": "machines"}, {"content": "school"}, {"content": "trip"}]', 2);
INSERT INTO public.questions VALUES ('1ba5f29c-85b3-4a28-bb0d-6f3c60970016', 'd514e886-4797-43ef-b5f1-60d8b88f114f', 'matching', 'Questions 26–30', '', '<p data-start="110" data-end="141">Complete the flowchart below.</p>
<p data-start="143" data-end="239">Choose <strong data-start="150" data-end="158">FIVE</strong> answers from the box and write the correct letter, A–H, next to Questions 26–30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<table style=\"width: 100.312%; height: 33.2px; border-collapse: collapse; border-spacing: 2px; border: 1px solid rgb(0, 0, 0);\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr style=\"height: 33.2px;\">\n<td style=\"border-color: #000000;\">Choose mice which are all the same {age}.</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: left; padding-left: 200px;\" data-start=\"441\" data-end=\"524\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100.028%; border-spacing: 2px; border: 1px solid rgb(0, 0, 0); height: 33.2px;\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr style=\"height: 33.2px;\">\n<td style=\"border-color: #000000; text-align: left;\">Divide the mice into two groups, each with a different<strong data-start=\"496\" data-end=\"523\"> </strong>{colour}.</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: left; padding-left: 200px;\" data-start=\"441\" data-end=\"524\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100.028%; border-spacing: 2px; border: 1px solid rgb(0, 0, 0);\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"text-align: left; border-color: #000000;\">\n<p>Put each group in a separate cage.</p>\n<p>Feed group A commercial mouse food.</p>\n<p>Feed group B the same, but also sugar contained in {cereal}.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: left; padding-left: 200px;\" data-start=\"526\" data-end=\"527\">🔽</p>\n<table style=\"border-collapse: collapse; width: 99.7446%; height: 33.2px; border-spacing: 2px; border: 1px solid rgb(0, 0, 0);\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr style=\"height: 33.2px;\">\n<td style=\"border-color: #000000;\">\n<p>Take measurements using an electronic scale.</p>\n<p>Place them in a weighing chamber to prevent<strong data-start=\"779\" data-end=\"806\"> </strong>{escape}.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: left; padding-left: 200px;\" data-start=\"685\" data-end=\"686\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100.17%; height: 35.2px; border-spacing: 2px; border: 1px solid rgb(0, 0, 0);\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr style=\"height: 35.2px;\">\n<td style=\"border-color: #000000;\">Do all necessary {calculations}.</td>\n</tr>\n</tbody>\n</table>\n<p> </p>", "answerOptions": [{"optionText": "size"}, {"optionText": "escape"}, {"optionText": "age"}, {"optionText": "water"}, {"optionText": "cereal"}, {"optionText": "calculations"}, {"optionText": "changes"}, {"optionText": "colour"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('f54d919e-8991-4586-afca-fefe5dfc2d1c', 'edf638c8-236f-426d-8f5d-12d6d41a643a', 'fillup', 'Questions 31–40', '<p data-start="1988" data-end="2015">Choose <strong>ONE WORD ONLY</strong> for each answer</p>
<p data-section-id="18npwjg" data-start="2022" data-end="2040"><span style="font-size: 12pt;"><strong>Microplastics</strong></span></p>
<p data-section-id="1y8tw1s" data-start="2042" data-end="2077"><strong>Where microplastics come from</strong></p>
<p data-start="2078" data-end="2122">fibres from some {clothing} during washing</p>
<p data-start="2124" data-end="2166">the breakdown of large pieces of plastic</p>
<p data-start="2168" data-end="2189">waste from industry</p>
<p data-start="2191" data-end="2229">the action of vehicle tyres on roads</p>
<p data-section-id="t4reaa" data-start="2236" data-end="2266"><strong>Effects of microplastics</strong></p>
<p data-start="2268" data-end="2353">They cause injuries to the {mouths} of wildlife and affect their digestive systems.</p>
<p data-start="2355" data-end="2434">They enter the food chain, e.g. in bottled and tap water, {salt} and seafood.</p>
<p data-start="2436" data-end="2561">They may not affect human health, but they are already banned in skin cleaning products and {toothpaste} in some countries.</p>
<p data-start="2563" data-end="2633">Microplastics enter the soil through the air, rain and {fertilisers}</p>
<p data-section-id="56gk99" data-start="2640" data-end="2708"><strong>Microplastics in the soil – a study by Anglia Ruskin University</strong></p>
<p data-start="2710" data-end="2778">Earthworms are important because they add {nutrients} to the soil.</p>
<p data-start="2780" data-end="2872">The study aimed to find whether microplastics in earthworms affect the {growth} of plants.</p>
<p data-start="2874" data-end="3025">The study found that microplastics caused:</p>
<p data-start="2874" data-end="3025">– {weight} loss in earthworms</p>
<p data-start="2874" data-end="3025">– fewer seeds to germinate</p>
<p data-start="2874" data-end="3025">– a rise in the level of {acid} in the soil</p>
<p data-section-id="76615j" data-start="3032" data-end="3058"><strong>The study concluded:</strong></p>
<p data-start="3059" data-end="3113">soil should be seen as an important natural process.</p>
<p data-start="3115" data-end="3169">changes to soil damage both ecosystems and {society}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"174\" data-end=\"240\">In today’s lecture, I’m going to be talking about microplastics.</p>\n<p data-start=\"242\" data-end=\"626\">Microplastics are tiny pieces of plastic smaller than five millimetres in size. Recently there’s been a greater awareness that there are large quantities of plastic waste – big and small – in the environment. The amount of plastic waste in the oceans has received widespread attention, but far less is known about the effects of microplastics in freshwater and particularly in soil.</p>\n<p data-start=\"628\" data-end=\"1154\">Microplastics can enter the environment via a number of different sources. Threads and microfibres detach from synthetic <span style=\"background-color: #f1c40f;\"><strong data-start=\"749\" data-end=\"766\">clothing (31)</strong></span> every time they’re put in a washing machine, and these find their way into the water system. Other sources include big pieces of plastic waste that are already in the environment, and these break down into microscopic particles over a period of time. On a larger scale, factory waste is another route, as are tyres which wear down as cars, lorries and so on travel along road surfaces.</p>\n<p data-start=\"1161\" data-end=\"1499\">We already understand some of the impacts of microplastics from studies involving fish and other animals. There is evidence that microplastics harm small creatures in a variety of ways, such as by damaging their <span style=\"background-color: #f1c40f;\"><strong data-start=\"1373\" data-end=\"1388\">mouths (32)</strong></span>, or by impairing their ability to feed, for example when microplastics get lodged in their digestive system.</p>\n<p data-start=\"1501\" data-end=\"1821\">Surprisingly perhaps, it is likely that humans consume microplastics, as these have been detected in a wide range of food and drink products, including bottled water, as well as in water that comes direct from the tap. What’s more, <span style=\"background-color: #f1c40f;\"><strong data-start=\"1733\" data-end=\"1746\">salt (33)</strong></span> and many kinds of seafood have also been found to contain microplastics.</p>\n<p data-start=\"1823\" data-end=\"2137\">However, it’s important to underline that there is not yet conclusive proof that microplastics cause significant harm to people. In many countries, including here in the UK, there is legislation which prevents manufacturers from adding plastic microbeads to shower gels, facial cleansers and <span style=\"background-color: #f1c40f;\"><strong data-start=\"2115\" data-end=\"2134\">toothpaste (34)</strong>.</span></p>\n<p data-start=\"2144\" data-end=\"2453\">It is very difficult to accurately estimate the total amount of microplastic particles in the soil as they can be hard to detect, but we do know they are carried in air and deposited in the soil by rain. What’s more, many of the <span style=\"background-color: #f1c40f;\"><strong data-start=\"2373\" data-end=\"2393\">fertilisers (35)</strong> </span>used by both farmers and gardeners contain microplastics.</p>\n<p data-start=\"2460\" data-end=\"2790\">A team from the Anglia Ruskin University in Cambridge has carried out a study of the effects of microplastics on the digestive tracts of earthworms. These worms, which live in topsoil, are an essential component of our agricultural system. By feeding on soil, they mix <span style=\"background-color: #f1c40f;\"><strong data-start=\"2729\" data-end=\"2747\">nutrients (36)</strong> </span>into it, thereby making it more fertile.</p>\n<p data-start=\"2792\" data-end=\"3380\">The researchers set out to discover whether the introduction of microplastics into the soil – and the subsequent ingestion of these by earthworms – would impact soil quality and ultimately inhibit plant<span style=\"background-color: #f1c40f;\"> <strong data-start=\"2995\" data-end=\"3010\">growth (37)</strong>. </span>The answer was, yes, it did. After placing three different types of microplastic particles into the soil, they planted perennial rye grass. The particles of microplastic, which included biodegradable PLA and conventional high-density polyethylene, or HDPE, were then ingested by the earthworms in the soil. The result was that the worms lost <span style=\"background-color: #f1c40f;\"><strong data-start=\"3354\" data-end=\"3369\">weight (38)</strong> </span>rapidly.</p>\n<p data-start=\"3382\" data-end=\"3806\">What’s more, a lower percentage than normal of the rye grass seeds germinated, and the researchers also found that this was a direct result of the earthworms being unable to fulfil their normal role in making soil more fertile. The team also discovered that there was an increase in the amount of <span style=\"background-color: #f1c40f;\"><strong data-start=\"3679\" data-end=\"3692\">acid (39)</strong></span> found in the soil, and this was attributed mainly to the microplastic particles from conventional HDPE plastic.</p>\n<p data-start=\"3813\" data-end=\"4392\">The conclusions of the study make for very interesting reading – I’ve included the reference in the notes to give you at the end of the session. To summarise, the authors proposed the idea that we need to regard soil as we would regard any other process in nature. This means we should accept the implications of soil being dependent on decaying and dead matter constantly being passed through the bodies of earthworms. That is, when soil becomes impoverished by the presence of microplastics, not only ecosystems but also the whole of <span style=\"background-color: #f1c40f;\"><strong data-start=\"4349\" data-end=\"4365\">society (40)</strong></span> are negatively impacted.</p>"}]', 0);
INSERT INTO public.questions VALUES ('61dee8b8-e203-4dda-8177-50671bc3e5ea', '8b0cf476-914c-4530-947a-cd39db574d32', 'radio', 'Questions 1–3', 'Choose the correct letter, A, B, C, or D.', 'Choose the correct answer for each question.', 'multiple_choice_single', '[{"correct": "1", "options": [{"option_text": "A monk from a local monastery"}, {"option_text": "A goat herder named Kaldi"}, {"option_text": "An Arabian merchant"}, {"option_text": "Pope Clement VIII"}], "question": "According to legend, who first discovered the effects of coffee berries?"}, {"correct": "2", "options": [{"option_text": "Private homes where coffee was served"}, {"option_text": "Monasteries that cultivated coffee"}, {"option_text": "Public coffee houses"}, {"option_text": "Markets for trading coffee beans"}], "question": "What were ''qahveh khaneh''?"}, {"correct": "0", "options": [{"option_text": "He approved it after tasting it"}, {"option_text": "He banned it across Europe"}, {"option_text": "He ignored the controversy"}, {"option_text": "He taxed its importation"}], "question": "How did Pope Clement VIII respond to coffee?"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('19c9c84f-e81c-451e-928e-0f3f55b09d75', '883201d5-f7a9-428e-8ab9-5c47c80590c6', 'matrix', 'Questions 23–26', '', '<p>Match each statement with the correct researcher, <strong data-path-to-node="12" data-index-in-node="136">A</strong>, <strong data-path-to-node="12" data-index-in-node="139">B</strong> or <strong data-path-to-node="12" data-index-in-node="144">C</strong>.</p>
<p>Write the correct letter, <strong data-path-to-node="12" data-index-in-node="173">A</strong>, <strong data-path-to-node="12" data-index-in-node="176">B</strong> or <strong data-path-to-node="12" data-index-in-node="181">C</strong>, in boxes 23–26 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "The energy people have for exercising willpower is limited.", "correctCategoryLetter": "A"}, {"itemText": "Even an unpleasant substance had a positive effect on willpower.", "correctCategoryLetter": "A"}, {"itemText": "People’s responses to images changed after having to exercise self-control.", "correctCategoryLetter": "C"}, {"itemText": "The sequence of options presented to consumers could be used to the consumers’ disadvantage.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Roy F. Baumeister", "categoryLetter": "A"}, {"categoryText": "Jonathan Levav", "categoryLetter": "B"}, {"categoryText": "Todd Heatherton", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">23. The energy people have for exercising willpower is limited — {A} Roy F. Baumeister</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"26,0,0\" data-index-in-node=\"12\">Baumeister</strong>. His research demonstrated that there is a <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"66\">finite store of mental stamina</strong>…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. Even an unpleasant substance had a positive effect on willpower — {A} Roy F. Baumeister</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"28,0,0\" data-index-in-node=\"12\">Baumeister</strong> concluded that even the <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"47\">tasteless drink</strong> had worked…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Loại đồ uống không vị (tasteless/unpleasant) vẫn có tác dụng vì nó chứa glucose.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. People’s responses to images changed after having to exercise self-control — {C} Todd Heatherton</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"30,0,0\" data-index-in-node=\"12\">Heatherton’s team</strong> recorded images… as they reacted to <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"68\">pictures of food</strong>. …further brain scans revealed more activity…” (Đoạn F)</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. The sequence of options presented to consumers could be used to the consumers’ disadvantage — {B} Jonathan Levav</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…experiment conducted at German car dealerships… By manipulating the <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"85\">order</strong> of the car buyers’ choices… customers would end up <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"144\">paying more</strong>.” (Đoạn C)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('6faa1ba5-f9db-4880-8f69-39d2866b354b', '3d0f5b40-ddfc-42e7-a8a7-977b0b4ce976', 'radio', 'Questions 27–31', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "peers."}, {"content": "patients"}, {"content": "students"}, {"content": "teachers"}], "question": "According to the writer, Ekman became interested in lying after a question from his"}, {"correct": 1, "options": [{"content": "illustrate how frequently patients lie."}, {"content": "describe the origins of Ekman’s theories."}, {"content": "compare Ekman’s research to previous studies."}, {"content": "show how patients behaviour is affected by filming."}], "question": "The writer refers to the 12-minute interviews in order to"}, {"correct": 0, "options": [{"content": "Micro-expressions are common to all people."}, {"content": "Recent research has refuted an old idea."}, {"content": "With practice we can learn to control our micro-expression."}, {"content": "Human society is too complex to allow for generalisations."}], "question": "What is the writer’s point in the third paragraph?"}, {"correct": 1, "options": [{"content": "It’s natural for people to lie"}, {"content": "Few untrained people can detect lying"}, {"content": "Most liar suffer from periods of depression."}, {"content": "All of his subjects were trained to identify micro-expressions."}], "question": "What are we told about Ekman’s conclusions from his tests?"}, {"correct": 1, "options": [{"content": "They take decades to teach"}, {"content": "They have been in great demand"}, {"content": "They have aroused the suspicions of some agencies"}, {"content": "They can be used by a limited range of occupations"}], "question": "At what point does the writer make about Ekman’s techniques in the fourth paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. According to the writer, Ekman became interested in lying after a question from his…</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C. students</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 1–3.</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Dr Paul Ekman was addressing a group of <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"52\">young psychiatrists in training</strong> when he was asked a question…”</li>\n<li><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “young psychiatrists in training” (những bác sĩ tâm thần trẻ đang trong quá trình đào tạo) tương ứng với “students” (sinh viên/học viên). Câu hỏi của họ về việc làm sao biết bệnh nhân nói thật hay không đã khơi gợi sự quan tâm của ông.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. The writer refers to the 12-minute interviews in order to…</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. describe the origins of Ekman’s theories</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 1–6.</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As part of his research, he had already filmed a series of <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"71\">12-minute interviews</strong>… Then he slowed it down… And suddenly… he saw it… He termed his discovery <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"174\">micro-expression</strong>.”</li>\n<li><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhắc đến các cuộc phỏng vấn 12 phút này để kể lại quá trình Ekman tình cờ phát hiện ra các biểu cảm siêu nhỏ (micro-expression) khi xem chậm đoạn phim. Đây chính là nguồn gốc (origins) hình thành nên học thuyết của ông.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What is the writer’s point in the third paragraph?</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> A. Micro-expressions are common to all people.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 2–5.</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the ways in which we express rage, disgust… are <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"65\">universal</strong>. The facial muscles triggered… are, he has shown, essentially <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"139\">standard, regardless of language and culture</strong>…”</li>\n<li><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh rằng các biểu cảm khuôn mặt là “universal” (phổ quát) và “standard” (tiêu chuẩn) ở mọi nền văn hóa. Điều này đồng nghĩa với việc các biểu cảm siêu nhỏ này tồn tại giống nhau ở tất cả mọi người (common to all people).</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What are we told about Ekman’s conclusions from his tests?</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. Few untrained people can detect lying.</li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1–3.</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Fortunately for liars, <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"35\">most people will fail to spot</strong> these fleeting signals… Of the 15,000 Ekman has tested, <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"123\">only 50 people</strong>, whom he calls ‘naturals’, have been able to do it.”</li>\n<li><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Với tỉ lệ chỉ 50/15.000 người có khả năng tự nhiên để phát hiện nói dối, bài đọc khẳng định rằng rất ít người chưa qua đào tạo (untrained) có thể làm được việc này.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. What point does the writer make about Ekman’s techniques in the fourth paragraph?</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. They have been in great demand.</li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 5–10.</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…he has been called in by the <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"44\">FBI and CIA (among countless more law-enforcement and other agencies around the world)</strong>… workshops for <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"148\">defense and prosecution lawyers, health professionals, even jealous spouses</strong>…”</li>\n<li><strong data-path-to-node=\"12,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc hàng loạt cơ quan an ninh (FBI, CIA), các luật sư, chuyên gia y tế và cả những người vợ/chồng hay ghen tìm đến ông cho thấy kỹ thuật của ông đang rất được săn đón và có nhu cầu cực lớn (in great demand).</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('afac0327-ca18-43b5-ac0e-66ace1947f46', '8cc6fe60-2f66-41b9-a6cf-2ca5d78168ee', 'radio', 'Questions 8–13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information  <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Georgia O’Keeffe’s style was greatly influenced by the changing fashions in art over the seven decades of her career."}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "When O’Keeffe finished high school, she had already made her mind up about the career that she wanted."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "Alfred Stieglitz first discovered O’Keeffe’s work when she sent some abstract drawings to his gallery in New York City."}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "O’Keeffe was the subject of Stieglitz’s photographic work for many years."}, {"correct": 2, "options": [{"content": "TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "O’Keeffe’s paintings of the patio of her house in Abiquiú were among the artist’s favourite works."}, {"correct": 2, "options": [{"content": "TRUE "}, {"content": " FALSE "}, {"content": "NOT GIVEN"}], "question": "O’Keeffe produced a greater quantity of work during the 1950s to 1970s than at any other time in her life."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>8. FALSE<br />(Đoạn mở: “she remained independent from shifting art trends and her work stayed true to her own vision…”)<br />→ Phong cách của O’Keeffe không bị ảnh hưởng bởi xu hướng nghệ thuật thay đổi, mà luôn giữ cá tính riêng. → FALSE.</p>\n<p> <br />9. TRUE<br />(Đoạn: “By the time she graduated from high school in 1905, she had determined to make her way as an artist.”)<br />→ Ngay khi tốt nghiệp trung học, cô đã quyết định trở thành họa sĩ, đúng như nội dung câu hỏi. → TRUE.</p>\n<p> <br />10. FALSE<br />(Đoạn: “She sent some of these drawings to a friend in New York, who showed them to art collector and photographer Alfred Stieglitz.”)<br />→ Stieglitz không phải do cô gửi trực tiếp, mà là bạn cô gửi giúp. Vì vậy nội dung câu hỏi sai. → FALSE.</p>\n<p> <br />11. TRUE<br />(Đoạn: “Stieglitz’s celebrated black-and-white portraits of O’Keeffe, taken over the course of twenty years (1917–37).”)<br />→ O’Keeffe là nhân vật chính trong ảnh của Stieglitz suốt 20 năm, hoàn toàn khớp với câu hỏi. → TRUE.</p>\n<p> <br />12. NOT GIVEN<br />(Đoạn: “One feature of the Abiquiú house – the large walled patio with its black door – was particularly inspirational. In more than thirty pictures… she reinvented the patio…”)<br />→ Bài chỉ nói sân nhà là nguồn cảm hứng, không hề nói cô yêu thích nhất những bức tranh này. → NOT GIVEN.</p>\n<p> <br />13. NOT GIVEN<br />(Đoạn: “From the 1950s into the 1970s, O’Keeffe travelled widely… The last two decades of the artist’s life were relatively unproductive…”)<br />→ Không có thông tin nào nói giai đoạn 1950–1970 cô vẽ nhiều nhất, chỉ nói cô vẫn sáng tác và du lịch. → NOT GIVEN.<br /> <br /> <br /> </p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('d4c746da-5126-4d64-bff1-ab30c196ec9e', '0a100a39-f831-4e46-b779-1f447e981f8b', 'matching', 'Questions 14–18', NULL, '<p>Choose the correct heading for each section and move it into the gap.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. Historical reasons why interrupted sleep became uncommon"}, {"optionText": "ii. Brain structures involved in sleep patterns"}, {"optionText": "iii. Potential health issues related to sleep"}, {"optionText": "iv. Famous cases in literature of sleep problems"}, {"optionText": "v. An analysis of old documents to discover sleep patterns"}, {"optionText": "vi. Biological and environmental factors preventing people from falling asleep again"}, {"optionText": "vii. Scientific evidence that divided sleep is a natural phenomenon"}], "matchingItems": null}', 'null', '[{"content": "<p>14. (vii) Scientific evidence that divided sleep is a natural phenomenon<br />\n(Đoạn A, “…psychiatrist Thomas Wehr conducted research… the subjects had settled into a very distinct sleeping pattern. Firstly, they slept four hours, then woke for one or two hours before falling into a second four-hour sleep.”)<br />\n→ Thí nghiệm của Thomas Wehr chứng minh rằng giấc ngủ chia đôi là hiện tượng tự nhiên ở con người, không phải rối loạn. → Đáp án là (vii).</p>\n<p>15. (v) An analysis of old documents to discover sleep patterns<br />\n(Đoạn B, “Ekirch’s research found more than 500 references to a segmented sleeping pattern – in diaries, court recorders, medical books and literature…”)<br />\n→ Roger Ekirch đã phân tích hàng trăm tài liệu cổ như nhật ký, ghi chép y học và văn học để phát hiện ra mô hình ngủ hai giai đoạn. → Đáp án là (v).</p>\n<p>16. (i) Historical reasons why interrupted sleep became uncommon<br />\n(Đoạn C, “Ekirch found that references to the first and second sleep started to disappear… improvements in street and home lighting… Coffee houses emerged as a fashionable phenomenon…”)<br />\n→ Nhờ ánh sáng nhân tạo và sự xuất hiện của đời sống về đêm (như quán cà phê), con người dần từ bỏ kiểu ngủ chia đôi. → Đáp án là (i).</p>\n<p>17. (vi) Biological and environmental factors preventing people from falling asleep again<br />\n(Đoạn D, “Ekirch believes many sleeping problems may have roots in the human body’s natural preference for divided sleep, as well as in difficulties caused by extended exposure to artificial light…”)<br />\n→ Các yếu tố sinh học tự nhiên và môi trường ánh sáng nhân tạo khiến con người khó ngủ lại giữa đêm – hiện tượng gọi là sleep maintenance insomnia. → Đáp án là (vi).</p>\n<p>18. (iii) Potential health issues related to sleep<br />\n(Đoạn E, “If it makes people who wake up in the night anxious… Over 30% of the medical problems that doctors are faced with stem directly or indirectly from sleep.”)<br />\n→ Đoạn này nói về hệ quả sức khỏe của việc mất ngủ – bao gồm lo âu, mất ngủ mãn tính, và các bệnh y học liên quan. → Đáp án là (iii).</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('23a4d0ec-0861-4551-8277-c213f3dfad13', '919a1913-01d5-4ee2-a513-640f87c35ffd', 'radio', 'Questions 27-32', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "It was the safest city in the country."}, {"option_text": "It was less prosperous than other cities."}, {"option_text": "Many people were frustrated that they could not find a job."}, {"option_text": "It was wealthy and seen as an ideal place to raise children."}], "question": "What does the writer say about Dunedin in the 1970s?"}, {"correct": 2, "options": [{"option_text": "That the study was held in a church."}, {"option_text": "That the tests took half a day"}, {"option_text": "That 91% of parents agreed to help."}, {"option_text": "That the study used volunteers."}], "question": " What did the writer find surprising about Phil Silva’s original study?"}, {"correct": 1, "options": [{"option_text": "Children had excellent language"}, {"option_text": "Many children had developmental problems."}, {"option_text": "No children had ear problems."}, {"option_text": "All children were healthy."}], "question": "What was Silva''s main finding in 1978?"}, {"correct": 3, "options": [{"option_text": "The sample group was smaller in the first study"}, {"option_text": "The second study produced conflicting results."}, {"option_text": "Helpers were not used in the second study."}, {"option_text": "The second study collected additional types of information."}], "question": "What was different about the first and second studies?"}, {"correct": 1, "options": [{"option_text": "A shortage of helpers."}, {"option_text": "A lack of available funding."}, {"option_text": "The bad behaviour of some children."}, {"option_text": "The poor language skills of the participants"}], "question": "What problem did Silva face when conducting the original study?"}, {"correct": 1, "options": [{"option_text": "To show how generous project funding had become"}, {"option_text": "To show that the study was being taken seriously."}, {"option_text": "To emphasise the temporary nature of the facilities."}, {"option_text": "To highlight that the children disliked the site"}], "question": " Why does the writer mention the new building in the fourth paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. What does the writer say about Dunedin in the 1970s? — {D}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “New Zealand was then the <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"37\">ninth richest country</strong> in the world and many residents believed that… this was a city <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"124\">without rival</strong> [to bring up children].” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Wealthy” tương ứng với quốc gia giàu thứ 9, và “ideal place to raise children” tương ứng với “city without rival” (thành phố không đối thủ).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. What did the writer find surprising about Phil Silva’s original study? — {C}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"6,0,0\" data-index-in-node=\"12\">Incredibly</strong>, no fewer than <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"38\">91% agreed</strong> to help…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “Incredibly” (đáng kinh ngạc/thật khó tin) thể hiện sự ngạc nhiên của tác giả về tỉ lệ cha mẹ đồng ý tham gia rất cao.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What was Silva’s main finding in 1978? — {B}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…one in four children had <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"40\">delayed language development</strong>; 15% had <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"78\">ear problems</strong>; …one child who was blind…” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các con số này cho thấy nhiều trẻ em gặp phải các vấn đề về phát triển (developmental problems) mà trước đó chưa được phát hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What was different about the first and second studies? — {D}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The data gathered at age three was updated and <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"59\">new measurement criteria</strong> – discipline, nutrition, dental health – were <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"130\">introduced</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu thứ hai đã đưa thêm các tiêu chí đo lường mới (additional types of information) như kỷ luật, dinh dưỡng và sức khỏe răng miệng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. What problem did Silva face when conducting the original study? — {B}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “There was <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"22\">precious little money</strong> at Silva’s disposal, so the assessments were done in a <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"99\">church with the help of dozens of volunteers</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc phải làm trong nhà thờ và dùng tình nguyện viên cho thấy sự thiếu hụt nghiêm trọng về kinh phí (lack of available funding).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">32. Why does the writer mention the new building in the fourth paragraph? — {B}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the politicians were finally starting to <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"56\">take note</strong> and government funding began to trickle in. …it was at least a site for the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"144\">long term</strong> and its acquisition represented a <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"188\">landmark</strong>…” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc có một tòa nhà cố định (dù không sang trọng) đánh dấu việc nghiên cứu bắt đầu được chính quyền coi trọng và đầu tư dài hạn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('648295d9-3f4d-4945-8bbb-53970f23186d', '5971a32d-d158-4282-a451-dd15a92e581b', 'checkbox', 'Questions 17–18', '', '<p data-start="103" data-end="131">Choose <strong data-start="110" data-end="130">TWO letters, A–E</strong>.</p>
<p data-start="133" data-end="187">Which <strong data-start="139" data-end="146">TWO</strong> things does Heather explain about kilns?</p>
<p data-start="189" data-end="347"> </p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A what their function is"}, {"correct": false, "option_text": "B when they were invented"}, {"correct": false, "option_text": "C ways of keeping them safe"}, {"correct": false, "option_text": "D where to put one in your home"}, {"correct": true, "option_text": "E what some people use instead of one"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('9dcf2781-81a4-41ed-ad11-d0aa66812b5d', '8b0cf476-914c-4530-947a-cd39db574d32', 'fillup', 'Questions 4–6', 'Complete the sentences below. Write NO MORE THAN TWO WORDS from the passage for each answer.

<p>4. The story of coffee begins in {Ethiopia}, according to legend.</p>
<p>5. Coffee cultivation and trade first began on the {Arabian Peninsula} by the 15th century.</p>
<p>6. Today, {Brazil} remains the largest producer of coffee in the world.</p>', 'Write no more than two words from the passage.', 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "Ethiopia"}, {"content": "Arabian Peninsula / arabian peninsula"}, {"content": "Brazil"}]', 1);
INSERT INTO public.questions VALUES ('4afad347-78f9-426e-8bc7-217a7bb68591', '919a1913-01d5-4ee2-a513-640f87c35ffd', 'radio', 'Questions 33-36', '', '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose<strong> NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong>  if it is impossible to say what the writer thinks about this.</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Recent results suggest that intellectual development and birth weight are linked."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Medical textbooks used to claim that breast-fed children were more intelligent."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Children who suck their thumbs are prone to developmental problems."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The findings of the Dunedin study have challenged some doctors’ preconceptions"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. Recent results suggest that intellectual development and birth weight are linked. — {YES}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the amount a newborn infant <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"43\">weighs is associated with IQ</strong>.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cân nặng khi sinh liên quan đến IQ (chỉ số thông minh/phát triển trí tuệ), khớp hoàn toàn với nhận định.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Medical textbooks used to claim that breast-fed children were more intelligent. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Paediatric textbooks had insisted… breast-feeding protected against <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"82\">medical problems like asthma and allergies</strong>.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sách giáo khoa nói nuôi con bằng sữa mẹ giúp chống lại <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"67\">bệnh tật</strong> (hen suyễn, dị ứng), chứ không nhắc gì đến việc giúp trẻ <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"133\">thông minh hơn</strong> (intelligent).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. Children who suck their thumbs are prone to developmental problems. — {NO}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…thumb-sucking <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"29\">does no harm</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định mút tay không gây hại, trái ngược với ý kiến cho rằng nó gây ra các vấn đề phát triển.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">36. The findings of the Dunedin study have challenged some doctors’ preconceptions. — {YES}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…Dunedin researchers have been able to <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"53\">contradict old assumptions</strong> and <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"84\">explode medical myths</strong> long held by the profession.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Contradict old assumptions” và “explode medical myths” chính là việc thách thức các định kiến (preconceptions) của giới y khoa.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('156ab009-7420-490d-b8fc-51f55ee085fd', '1d4aad16-808f-4fd8-aa1b-5df7db2516fd', 'select', 'Questions 7–8', 'Choose the correct answer from the dropdown.', 'Select the best answer.', 'gap_filling', '[{"correct": "1", "options": [{"option_text": "25 percent"}, {"option_text": "34 percent"}, {"option_text": "50 percent"}], "question": "What percentage of fish stocks are fished at unsustainable levels?"}, {"correct": "2", "options": [{"option_text": "4 million tonnes"}, {"option_text": "6 million tonnes"}, {"option_text": "8 million tonnes"}], "question": "How much plastic waste enters the oceans each year?"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('132ef42c-3f9f-4949-82a9-f13c32678130', '1d4aad16-808f-4fd8-aa1b-5df7db2516fd', 'checkbox', 'Question 9', 'Which THREE of the following are mentioned as threats to ocean health?', 'Choose THREE letters, A–F.', 'multiple_choice_many', 'null', '[{"correct": false, "option_text": "A. Rising sea levels"}, {"correct": true, "option_text": "B. Overfishing"}, {"correct": false, "option_text": "C. Coral bleaching"}, {"correct": true, "option_text": "D. Ocean acidification"}, {"correct": false, "option_text": "E. Volcanic activity"}, {"correct": true, "option_text": "F. Plastic pollution"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('bb0444b4-68b4-4592-9f49-77ed4f90d7b8', '1d4aad16-808f-4fd8-aa1b-5df7db2516fd', 'matching', 'Questions 10–13', 'Match each statement with the correct conservation measure.', 'Choose the correct letter, A–E, for each statement.', 'matching_features', 'null', 'null', '{"layout_type": "standard", "answer_options": [{"option_text": "Marine protected areas"}, {"option_text": "Catch limits"}, {"option_text": "Single-use plastic bans"}, {"option_text": "Beach clean-ups"}, {"option_text": "Biodegradable alternatives"}], "matching_items": [{"questionPart": "Restricts fishing and mining in designated ocean regions", "correctAnswer": "Marine protected areas"}, {"questionPart": "Sets limits on the amount of fish that can be caught", "correctAnswer": "Catch limits"}, {"questionPart": "Prevents the sale of disposable plastic items", "correctAnswer": "Single-use plastic bans"}, {"questionPart": "Removes waste from coastal environments", "correctAnswer": "Beach clean-ups"}]}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('ca1b1b3d-00d2-4ad4-bdf4-b6852ec9ce1b', '0a100a39-f831-4e46-b779-1f447e981f8b', 'matrix', 'Questions 19–23', NULL, '<p>Look at the following statements (Questions 19–23) and the list of researchers below.</p>
<p>Match each statement with the correct researcher, A–E.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Researchers", "matrixItems": [{"itemText": "In certain historical periods, the threat of criminal danger led to segmented sleep.", "correctCategoryLetter": "C"}, {"itemText": "Physicians should learn more about treating people with sleeping difficulties.", "correctCategoryLetter": "E"}, {"itemText": "Historically, when people experienced interrupted sleep, they used the waking periods at night for different activities.", "correctCategoryLetter": "B"}, {"itemText": "Technological changes in Europe made people more likely to sleep through the night.", "correctCategoryLetter": "B"}, {"itemText": "The belief that humans should have a long continuous sleep can be psychologically harmful.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Thomas Wehr", "categoryLetter": "A"}, {"categoryText": "Roger Ekirch", "categoryLetter": "B"}, {"categoryText": "Craig Koslofsky", "categoryLetter": "C"}, {"categoryText": "Gregg Jacobs", "categoryLetter": "D"}, {"categoryText": "Russell Foster", "categoryLetter": "E"}]}', '[{"content": "<p data-start=\"196\" data-end=\"602\"><strong data-start=\"196\" data-end=\"222\">19. C. Craig Koslofsky</strong><br data-start=\"222\" data-end=\"225\" /><em data-start=\"225\" data-end=\"445\">(Đoạn B, “Craig Koslofsky suggested an explanation for this divided sleep pattern in Europe. ‘Associations with night before the 17th century were not good,’ he writes… The streets… populated by thieves or worse.”)</em><br data-start=\"445\" data-end=\"448\" />→ Koslofsky cho rằng <strong data-start=\"469\" data-end=\"519\">mối đe dọa từ tội phạm và sự nguy hiểm ban đêm</strong> khiến con người chọn cách ngủ chia đôi giấc. → Đáp án là <strong data-start=\"577\" data-end=\"599\">C. Craig Koslofsky</strong>.</p>\n<hr data-start=\"604\" data-end=\"607\" />\n<p data-start=\"609\" data-end=\"1030\"><strong data-start=\"609\" data-end=\"634\">20. E. Russell Foster</strong><br data-start=\"634\" data-end=\"637\" /><em data-start=\"637\" data-end=\"858\">(Đoạn E, “Over 30% of the medical problems that doctors are faced with stem directly or indirectly from sleep… But sleep has been ignored in medical training, and there are very few countries where sleep is studied.”)</em><br data-start=\"858\" data-end=\"861\" />→ Foster nhấn mạnh rằng <strong data-start=\"885\" data-end=\"952\">bác sĩ cần học nhiều hơn về việc điều trị các rối loạn giấc ngủ</strong>, vì giấc ngủ ảnh hưởng lớn đến sức khỏe. → Đáp án là <strong data-start=\"1006\" data-end=\"1027\">E. Russell Foster</strong>.</p>\n<hr data-start=\"1032\" data-end=\"1035\" />\n<p data-start=\"1037\" data-end=\"1400\"><strong data-start=\"1037\" data-end=\"1060\">21. B. Roger Ekirch</strong><br data-start=\"1060\" data-end=\"1063\" /><em data-start=\"1063\" data-end=\"1240\">(Đoạn B, “In many historic accounts, Ekirch found that people used the time that they were awake between periods of sleep to think about and attempt to analyse their dreams.”)</em><br data-start=\"1240\" data-end=\"1243\" />→ Ekirch phát hiện rằng <strong data-start=\"1267\" data-end=\"1365\">con người xưa dùng khoảng thời gian thức giữa hai giấc để đọc, viết, hoặc suy ngẫm về giấc mơ.</strong> → Đáp án là <strong data-start=\"1378\" data-end=\"1397\">B. Roger Ekirch</strong>.</p>\n<hr data-start=\"1402\" data-end=\"1405\" />\n<p data-start=\"1407\" data-end=\"1807\"><strong data-start=\"1407\" data-end=\"1430\">22. B. Roger Ekirch</strong><br data-start=\"1430\" data-end=\"1433\" /><em data-start=\"1433\" data-end=\"1621\">(Đoạn C, “Ekirch attributes the initial shift to improvements in street and home lighting… Coffee houses emerged as a fashionable phenomenon… Going out at night became commonplace.”)</em><br data-start=\"1621\" data-end=\"1624\" />→ Ekirch giải thích rằng <strong data-start=\"1649\" data-end=\"1712\">sự thay đổi công nghệ (ánh sáng, quán cà phê, đời sống đêm)</strong> khiến con người ngủ một mạch qua đêm thay vì chia hai giấc. → Đáp án là <strong data-start=\"1785\" data-end=\"1804\">B. Roger Ekirch</strong>.</p>\n<hr data-start=\"1809\" data-end=\"1812\" />\n<p data-start=\"1814\" data-end=\"2103\"><strong data-start=\"1814\" data-end=\"1837\">23. D. Gregg Jacobs</strong><br data-start=\"1837\" data-end=\"1840\" /><em data-start=\"1840\" data-end=\"1953\">(Đoạn E, “If it makes people who wake up in the night anxious, as this anxiety can itself discourage sleep…”)</em><br />\n→ Jacobs cho rằng <strong data-start=\"1972\" data-end=\"2068\">niềm tin phải ngủ liền mạch tám tiếng có thể gây lo âu và ảnh hưởng xấu đến sức khỏe tâm lý.</strong> → Đáp án là <strong data-start=\"2081\" data-end=\"2100\">D. Gregg Jacobs</strong>.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('8a455116-da6d-4192-80f9-9f6a0efe0de9', '0a100a39-f831-4e46-b779-1f447e981f8b', 'fillup', 'Questions 24–26', '<p>Complete the summary below.<br />
Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.<br />
Write your answers in boxes <strong>24</strong>–<strong>26 </strong>on your answer sheet.</p>
<p style="text-align: center;"><strong>Historical patterns of interrupted sleep</strong></p>
<p style="text-align: left;">Historical evidence seems to show that humans had common sleep patterns which were quite unlike today’s eight hours of unbroken sleep each night. People habitually went to bed early, soon after {sunset}, slept for a while, then woke up for a few hours of activity or perhaps to consider, for example, the meaning of their {dreams}.</p>
<p>There was little else to do at home in the dark, since what little means of lighting they had, such as using candles, was costly. In 16th-century Europe, people tended to stay at home at night because they feared {thieves} on largely unlit city streets. Once urban street lighting improved, night life in cities became popular, and recreational spots like coffee houses came to be considered fashionable. Consequently, sleeping patterns also began to change.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>24. sunset<br />\n(Đoạn B, “These references describe a first sleep which began not long following sunset.”)<br />\n→ Con người xưa đi ngủ sớm, ngay sau khi mặt trời lặn, khác hoàn toàn với thói quen hiện nay. → Đáp án là sunset.</p>\n<p>25. dreams<br />\n(Đoạn B, “Ekirch found that people used the time that they were awake between periods of sleep to think about and attempt to analyse their dreams.”)<br />\n→ Trong khoảng thời gian tỉnh giấc giữa hai giấc ngủ, họ thường ngẫm nghĩ và phân tích giấc mơ của mình. → Đáp án là dreams.</p>\n<p>26. thieves<br />\n(Đoạn B, “The streets of cities and towns at night were often populated by thieves or worse. The streets at night consequently scared many people.”)<br />\n→ Vào thế kỷ 16, người dân sợ trộm cướp nên thường ở nhà vào ban đêm. → Đáp án là thieves.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('89201321-09fd-4fe8-98d7-feed80799b72', '21f54837-757b-4f83-9593-0267b85585b2', 'matching', 'Questions 27-32', '<p>Complete the summary using the list of words. Choose the correct answer and move it into the gap.<br /> </p>
<p> </p>
', '<p>Complete the summary using the list of words. Choose the correct answer and move it into the gap.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p dir=\"ltr\"><strong>Provine''s early findings on yawns</strong></p>\r\n<p dir=\"ltr\">Through his observation of yawns, Province was able to confirm that {half-yawns} do not exist.</p>\r\n<p dir=\"ltr\">Just like a {sneeze}, yawns cannot be interrupted after they have begun. This is because yawns occur as a {fixed action pattern} rather than a stimulus response as was previously thought.</p>\r\n<p dir=\"ltr\">In measuring the time taken to yawn, provive found that a typical yawn lasts about {6 seconds}. He also found that it is a common for people to yawn a number of times in quick succession with the yawns usually being around {68 seconds} apart. </p>\r\n<p dir=\"ltr\">When studying whether length and rate were connected, Province concluded that people who yawn less do not necessarily produce {long yawns} to make up for this.</p>", "answerOptions": [{"optionText": "form and function"}, {"optionText": "long yawns"}, {"optionText": "3 seconds"}, {"optionText": "fixed action pattern"}, {"optionText": "68 seconds"}, {"optionText": "short yawns"}, {"optionText": "reflex"}, {"optionText": "sneeze"}, {"optionText": "short duration"}, {"optionText": "6 seconds"}, {"optionText": "half-yawns"}], "matchingItems": null}', 'null', '[{"content": "<p>1. half-yawns<br />\n(Đoạn 3, “There are no half-yawns: this is an example of the typical intensity of fixed action patterns and a reason why you cannot stifle yawns.”)<br />\n→ Provine phát hiện rằng không tồn tại “nửa cơn ngáp”, vì ngáp là hành vi hoàn chỉnh – khi đã bắt đầu thì phải kết thúc. → Đáp án là half-yawns.</p>\n<p>2. sneeze<br />\n(Đoạn 3, “…once started, a yawn progresses with the inevitability of a sneeze.”)<br />\n→ Khi đã bắt đầu, cơn ngáp diễn ra tất yếu như hắt hơi, không thể dừng giữa chừng. → Đáp án là sneeze.</p>\n<p>3. fixed action pattern<br />\n(Đoạn 3, “It is an excellent example of the instinctive ‘fixed action pattern’… It is not a reflex (short-duration, rapid, proportional response to a simple stimulus)…”)<br />\n→ Ngáp không phải phản xạ đơn giản mà là hành vi theo mô hình “fixed action pattern” (hành vi bản năng cố định) – khi đã kích hoạt thì chạy trọn chuỗi. → Đáp án là fixed action pattern.</p>\n<p>4. 6 seconds<br />\n(Đoạn 3, “The standard yawn runs its course over about six seconds on average…”)<br />\n→ Một cơn ngáp trung bình kéo dài khoảng 6 giây. → Đáp án là 6 seconds.</p>\n<p>5. 68 seconds<br />\n(Đoạn 3, “…inter-yawn interval, which is generally about 68 seconds but rarely more than 70.”)<br />\n→ Khoảng thời gian giữa hai lần ngáp thường khoảng 68 giây. → Đáp án là 68 seconds.</p>\n<p>6. long yawns<br />\n(Đoạn 3, “There is no relation between yawn frequency and duration: producers of short or long yawns do not compensate by yawning more or less often.”)<br />\n→ Provine kết luận rằng tần suất và độ dài ngáp không liên quan – người ngáp ít không ngáp dài hơn để “bù lại”. → Đáp án là long yawns.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('6989e39f-7fc6-4a4d-b217-18e84c1723e8', '1d4aad16-808f-4fd8-aa1b-5df7db2516fd', 'matching', 'Questions 14–16', 'Complete the summary below using words from the box.', 'Choose the correct letter, A–F.', 'summary_completion', 'null', 'null', '{"layout_type": "summary", "summary_text": "The oceans absorb about 30 percent of {carbon dioxide} released by humans. However, this process leads to ocean {acidification}, which damages marine life. Well-managed protected areas can significantly increase fish {biomass}.", "answer_options": [{"option_text": "carbon dioxide"}, {"option_text": "oxygen"}, {"option_text": "biodiversity"}, {"option_text": "acidification"}, {"option_text": "biomass"}, {"option_text": "temperature"}], "matching_items": []}', 'null', 'null', 3);
INSERT INTO public.questions VALUES ('86bced8d-2bae-4fba-87a7-e314d5417a1d', '21f54837-757b-4f83-9593-0267b85585b2', 'radio', 'Questions 33-37', NULL, '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A Ending a yawn requires use of the nostrils."}, {"content": "B You can yawn without breathing through your nose"}, {"content": "C Breathing through the nose produces a silent yawn."}, {"content": "D The role of the nose in yawning needs further investigation."}], "question": "What did Provine conclude from his ‘closed nose yawn’ experiment?"}, {"correct": 2, "options": [{"content": "A yawning is unconnected with fatigue."}, {"content": "B a yawn is the equivalent of a deep intake of breath."}, {"content": "C you have to be able to open your mouth wide to yawn."}, {"content": "D breathing with the teeth together is as efficient as through the nose."}], "question": "Provine''s clenched teeth yawn''s experiment shows that"}, {"correct": 3, "options": [{"content": "A can be stopped after it has stated"}, {"content": "B is the result of motor programing"}, {"content": "C involves both inhalation and exhalation"}, {"content": "D can be accomplished only through the nose."}], "question": "The nose yawn experiment was used to test whether yawning"}, {"correct": 2, "options": [{"content": "A yawning may involve only one side of the face."}, {"content": "B the yawing response indicates that recovery is likely"}, {"content": "C movement in paralysed arm is stimulated by yawming"}, {"content": "D yawning can be used as an example to prevent muscle wasting."}], "question": "In people paralyzed on one side because of brain damage"}, {"correct": 1, "options": [{"content": "A yawning is a sign of boredom."}, {"content": "B we yawn is spite of the development of our species"}, {"content": "C yawning is a more passive activity than we imagine"}, {"content": "D we are stimulated to yawn when our brain activity is low"}], "question": "In the last paragraph, the writer concludes that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">33. What did Provine conclude from his ‘closed nose yawn’ experiment?</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong class=\"\" data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Đáp án:</strong><span class=\"\"> You can yawn without breathing through your nose.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"16\">i) The closed nose yawn</strong><span class=\"\">:</span><span class=\"\"> “This indicates that the inhalation…</span><span class=\"\"> and the exhalation…</span><span class=\"\"> need not involve the nostrils – the mouth provides a sufficient airway.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong class=\"\" data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Khi bịt mũi,</span><span class=\"\"> người tham gia vẫn ngáp bình thường được vì miệng đã cung cấp đủ đường thở.</span><span class=\"\"> Điều này chứng minh mũi không đóng vai trò bắt buộc trong cơ chế của cơn ngáp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">34. Provine’s clenched teeth yawn experiment shows that</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong><span class=\"\"> You have to be able to open your mouth wide to yawn.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"16\">ii) The clenched teeth yawn</strong><span class=\"\">:</span><span class=\"\"> “This shows that gaping of the jaws is an essential component…</span><span class=\"\"> and unless it is accomplished,</span><span class=\"\"> the program will not run to completion.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Việc cắn chặt răng khiến người ta cảm thấy bị “kẹt” giữa chừng.</span><span class=\"\"> Do đó,</span><span class=\"\"> việc há rộng hàm (gaping of the jaws) là điều kiện cần để hoàn thành một cơn ngáp trọn vẹn.</span></p>\n<p class=\"attachment-container search-images\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">35. The nose yawn experiment was used to test whether yawning</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án của bạn:</strong><span class=\"\"> Is the result of motor programming.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong class=\"\" data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><strong class=\"\" data-path-to-node=\"6,2,0\" data-index-in-node=\"16\">iii) The nose yawn</strong><span class=\"\">:</span><span class=\"\"> “The motor program for yawning will not run to completion without feedback that these parts of the program [inhalation through oral airway and gaping of jaws] have been accomplished.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong class=\"\" data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Thí nghiệm này cho thấy não bộ có một “chương trình vận động” (motor program) cài sẵn.</span><span class=\"\"> Nếu chỉ hít vào bằng mũi mà không qua miệng,</span><span class=\"\"> não không nhận được tín hiệu phản hồi rằng “các bước đã hoàn thành”,</span><span class=\"\"> dẫn đến việc cơn ngáp không thể kết thúc.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">36. In people paralyzed on one side because of brain damage</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong><span class=\"\"> Movement in paralysed arm is stimulated by yawning.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn gần cuối:</span><span class=\"\"> “…</span><span class=\"\">when these people yawn,</span><span class=\"\"> they are startled…</span><span class=\"\"> to observe that their otherwise paralyzed arm rises and flexes automatically in what neurologists term an ‘associated response’.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong class=\"\" data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Khi ngáp,</span><span class=\"\"> các kết nối vô thức giữa não và hệ vận động (không bị tổn thương bởi đột quỵ) được kích hoạt,</span><span class=\"\"> khiến cánh tay bị liệt tự động cử động mà người bệnh không tự điều khiển được.</span></p>\n<p class=\"attachment-container search-images\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">37. </strong><strong data-path-to-node=\"11\" data-index-in-node=\"0\">In the last paragraph, the writer concludes that </strong></p>\n<ul>\n<li data-path-to-node=\"9\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Đáp án: {B. we yawn is spite of the development of our species}</strong></li>\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn cuối):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"23\">“Yawning is also a reminder that <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"56\">ancient and unconscious behavior</strong> linking US to the animal world <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"120\">lurks beneath the veneer of culture, rationality and language</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả kết luận rằng ngáp là một hành vi cổ xưa và vô thức, nó vẫn tồn tại bên dưới lớp vỏ bọc văn minh, lý trí và ngôn ngữ của con người hiện đại.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('6f3f44c9-8f86-404f-9fbf-b5cbade5ffa1', '27e9504e-5236-41ef-b462-6bea3d3af335', 'matching', 'Questions 17–20', 'Match the correct heading to each section of the passage.', 'Choose the correct heading, i–vi, for each section.', 'matching_headings', 'null', 'null', '{"layout_type": "heading", "answer_options": [{"option_text": "Introduction"}, {"option_text": "Personalised Learning"}, {"option_text": "Automated Assessment"}, {"option_text": "Ethical Considerations"}, {"option_text": "Future Predictions"}, {"option_text": "Cost Analysis"}], "matching_items": []}', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('981c6410-5be5-4efb-9333-8e9a330662e5', '21f54837-757b-4f83-9593-0267b85585b2', 'radio', 'Question 38-40', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Research students were initially reluctant to appreciate the value of Provine''s studies."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "When foetuses yawn and stretch they are learning how to control movement"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "According to Provine, referring to only one function is probably inadequate to explain why people yawn."}]', 'null', 'null', 'null', '[{"content": "<p>38. YES<br />\n(Đoạn 1, “When Robert R. Provine began studying yawning in the 1960s, it was difficult for him to convince research students of the merits of ‘yawning science’.”)<br />\n→ Câu này cho thấy các sinh viên nghiên cứu ban đầu hoài nghi và không đánh giá cao giá trị nghiên cứu về ngáp của Provine. → Đáp án là YES.</p>\n<p>39. NOT GIVEN<br />\n(Đoạn nói về nghiên cứu của J.I.P. deVries về thai nhi: “Studies … observed a link between yawning and stretching.”)<br />\n→ Đoạn này chỉ nói có mối liên hệ giữa ngáp và duỗi người ở thai nhi, nhưng không nói rằng hành động này giúp chúng học cách kiểm soát chuyển động. → Đáp án là NOT GIVEN.</p>\n<p>40. YES<br />\n(Đoạn cuối, “Provine speculated that, in general, yawning may have many functions, and selecting a single function from the available options may be an unrealistic goal.”)<br />\n→ Provine tin rằng chỉ quy việc ngáp về một chức năng duy nhất là không đủ, vì nó có thể phục vụ nhiều mục đích khác nhau. → Đáp án là YES.</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('fe968e9e-19b7-46cb-9a5e-df813014f58a', 'b53c748a-d18c-4e54-9933-ba586cac5e2a', 'fillup', 'Questions 6-13', '<p>Complete the notes below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p><span style="font-size: 12pt;"><strong>The development of agriculture and food preservation</strong></span></p>
<p><strong>The changes agriculture brought about were:</strong></p>
<p style="padding-left: 40px;">-the development of equipment and larger {populations}</p>
<p style="padding-left: 40px;">-the ability to keep {records} as writing developed</p>
<p style="padding-left: 40px;">-the setting up of organised government</p>
<p><strong> Food preservation</strong></p>
<p style="padding-left: 40px;">-early methods of food preservation included: smoking, drymg and combining food with acid or {salt}</p>
<p style="padding-left: 40px;">-canning</p>
<p style="padding-left: 40px;">+ Nicholas Appert put food into containers made of {glass}</p>
<p>+ Appert’s method resulted in preserved food that had the same taste and {texture} as fresh food</p>
<p>+ Peter Durand introduced cans which had the advantage of being {light}. and hard to break</p>
<p>+ In 1855, the metal can opener replaced the {chisel}, which had been used with a hammer to open cans</p>
<p>+ Some food was still found to be edible after more than a hundred years, e.g. an old can of {meat}</p>
<p style="padding-left: 40px;">-freezing</p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">6. populations</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 4: &#8220;&#8230;and in turn <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"43\">populations</strong> increased in size.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự ra đời của các công cụ mới và nông nghiệp đã giúp quy mô dân số (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"80\">populations</strong>) gia tăng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">7. records</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 6: &#8220;&#8230;allowed people to maintain <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"58\">records</strong> of the harvest and taxes.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi chữ viết trở nên tinh vi hơn, nó cho phép con người lưu giữ các ghi chép (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"90\">records</strong>) về mùa màng và thuế phí.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">8. salt</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 3: &#8220;&#8230;smoking, drying, adding acid by fermentation or adding <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"86\">salt</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là một trong bốn phương pháp bảo quản thực phẩm cổ đại được liệt kê trong bài (xông khói, làm khô, lên men và thêm muối).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">9. glass</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng 3: &#8220;He sealed food in bottles fabricated from <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"70\">glass</strong> and then heated them&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nicholas Appert đã sử dụng các chai lọ được làm từ thủy tinh (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"74\">glass</strong>) để đựng và làm nóng thực phẩm nhằm bảo quản.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">10. texture</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng 6: &#8220;&#8230;and the flavour of the food as well as the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"74\">texture</strong> were similar to the freshly cooked product.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phương pháp của Appert giúp thực phẩm giữ được hương vị và kết cấu/cấu trúc (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"89\">texture</strong>) gần như đồ mới nấu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">11. light</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng 8: &#8220;&#8230;but he [Durand] produced the first ones which were <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"82\">light</strong> and resistant to damage.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước đó các hộp đựng thường quá nặng, nhưng Peter Durand đã tạo ra những chiếc hộp đầu tiên có đặc tính nhẹ (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"122\">light</strong>) và bền.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">12. chisel</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng 11: &#8220;&#8230;cans were opened with a <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"56\">chisel</strong> which was used to break open the top when hit with a hammer.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi dụng cụ mở đồ hộp ra đời, người ta phải dùng cái đục (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"76\">chisel</strong>) kết hợp với búa để mở nắp hộp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">13. meat</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng cuối: &#8220;&#8230;one can which contained <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"58\">meat</strong> dating from 1824 was opened in 1939 and the contents were still in good condition.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đưa ra ví dụ về một hộp thịt (<strong data-path-to-node=\"18,1,0\" data-index-in-node=\"50\">meat</strong>) từ năm 1824 vẫn có thể ăn được sau hơn 100 năm để chứng minh tính hiệu quả của việc đóng hộp.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('f1002aa2-247d-487e-8d97-952e4d15b089', '27e9504e-5236-41ef-b462-6bea3d3af335', 'matrix', 'Questions 21–25', 'Classify the following statements as relating to:', 'Write the correct letter, A, B, or C.', 'other', 'null', 'null', 'null', '{"matrix_items": [{"item_text": "Adjusts content difficulty based on student performance", "correct_category_letter": "A"}, {"item_text": "Uses NLP to grade written assignments", "correct_category_letter": "B"}, {"item_text": "Raises concerns about data privacy", "correct_category_letter": "C"}, {"item_text": "Can improve outcomes by up to 30 percent", "correct_category_letter": "A"}, {"item_text": "Provides instant feedback on student work", "correct_category_letter": "B"}], "matrix_categories": [{"category_text": "Personalised Learning", "category_letter": "A"}, {"category_text": "Automated Assessment", "category_letter": "B"}, {"category_text": "Ethical Considerations", "category_letter": "C"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('8103218e-2fa5-4415-9c10-d3cf052b27b7', '919a1913-01d5-4ee2-a513-640f87c35ffd', 'matching', 'Questions 37-40', '', '<p>Complete the summary below by dragging each phrase to the correct gap.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>A model study</strong></p>\n<p>The success of the Dunedin project has been put down to two principal factors: good fortune and Phil Silva''s methodology. The demographics of Dunedin mean that residents feel committed to the study, and that it also provides {H results} that can be applied both nationally and internationally, but even more important was Silva''s conviction that the {B study members}<span id=\"4827\" class=\"quests-numctn\" data-numctn=\"12\" data-count=\"12\" data-quest=\"12\"></span> must be looked after; nothing should be done to threaten the study''s {G confidentiality}<span id=\"4827\" class=\"quests-numctn\" data-numctn=\"13\" data-count=\"13\" data-quest=\"13\"></span> and as a result Silva is cautious when questioned, and a lot of work is done to minimise {F barriers to involvement}<span id=\"4827\" class=\"quests-numctn\" data-numctn=\"14\" data-count=\"14\" data-quest=\"14\"></span> in order to ensure that the study continues into the future.</p>", "answerOptions": [{"optionText": "A generalisable research"}, {"optionText": "B study members"}, {"optionText": "C government funding"}, {"optionText": "D assessments"}, {"optionText": "E loyalty"}, {"optionText": "F barriers to involvement"}, {"optionText": "G confidentiality"}, {"optionText": "H results"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. …provides {H results} that can be applied both nationally and internationally…</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…produce findings that can be <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"44\">generalised</strong> to New Zealand and other developed countries…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Generalised” (khái quát hóa) đồng nghĩa với việc kết quả có thể áp dụng rộng rãi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. …conviction that the {B study members} must be looked after…</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the most important asset they had was the <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"57\">sample group</strong> and these people must be <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"95\">nurtured at all costs</strong>.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sample group (nhóm mẫu) chính là các thành viên tham gia nghiên cứu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. …nothing should be done to threaten the study’s {G confidentiality}…</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"32,0,0\" data-index-in-node=\"12\">Privacy is absolutely paramount</strong>: Silva won’t even say how many of the study members are now in prison…” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Quyền riêng tư (Privacy) tương ứng với tính bảo mật (Confidentiality).</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. …work is done to minimise {F barriers to involvement}…</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…maintaining contact and <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"39\">removing obstacles to participation</strong>.” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Removing obstacles” (loại bỏ rào cản) tương ứng với “minimise barriers”.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('b597a387-84a3-4049-b3aa-8e6343118ef1', 'bd43b54e-b1b7-49da-929e-21171c504eaa', 'fillup', 'Questions 21–25', '<div class="quests-inner-desc">
<div class="txt">
<p>Answer the questions below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> from the passage for each answer.</p>
<p>When was the bittern population largest? {1950|IN 1950}</p>
<p>What word is used in the passage to describe the bittern’s character? {shy}</p>
<p>What is probably the main cause of death of bittern chicks? {starvation}</p>
<p>What food supply do bittern chicks depend on? {fish}</p>
<p>What other creatures mentioned in the passage have also benefited from improvements made to the bittern’s habitat? {otters}</p>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">21. When was the bittern population largest?</strong></p>\n<ul>\n<li style=\"list-style-type: none;\">\n<ul data-path-to-node=\"8,0,1\">\n<li>\n<p data-path-to-node=\"8,0,1,0,0\"><strong data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"0\">Đáp án</strong>: 1950</p>\n</li>\n<li>\n<p data-path-to-node=\"8,0,1,1,0\"><strong data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “…and in <strong data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"22\">1950</strong> the numbers of nature male bitterns rose to a <strong data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"73\">peak</strong> of about 70.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,0,1,2,0\"><strong data-path-to-node=\"8,0,1,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Từ “peak” (đỉnh điểm) xác nhận năm 1950 là lúc số lượng chim lớn nhất.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"8,0,1,2,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">22. What word is used in the passage to describe the bittern’s character?</strong></p>\n<ul data-path-to-node=\"8,1,1\">\n<li>\n<p data-path-to-node=\"8,1,1,0,0\"><strong data-path-to-node=\"8,1,1,0,0\" data-index-in-node=\"0\">Đáp án</strong>: shy</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,1,1,0\"><strong data-path-to-node=\"8,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “Bitterns have feathers that help them to conceal themselves and a <strong data-path-to-node=\"8,1,1,1,0\" data-index-in-node=\"78\">shy</strong> nature…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,1,2,0\"><strong data-path-to-node=\"8,1,1,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Bài đọc sử dụng trực tiếp tính từ “shy” để mô tả tính cách loài chim này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">23. What is probably the main cause of death of bittern chicks?</strong></p>\n<ul>\n<li style=\"list-style-type: none;\">\n<ul data-path-to-node=\"8,2,1\">\n<li>\n<p data-path-to-node=\"8,2,1,0,0\"><strong data-path-to-node=\"8,2,1,0,0\" data-index-in-node=\"0\">Đáp án</strong>: starvation</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,1,1,0\"><strong data-path-to-node=\"8,2,1,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “Many chicks did not survive… and <strong data-path-to-node=\"8,2,1,1,0\" data-index-in-node=\"47\">starvation</strong> was found to be the most likely reason for their demise.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,1,2,0\"><strong data-path-to-node=\"8,2,1,2,0\" data-index-in-node=\"0\">Giải thích</strong>: “Starvation” (sự chết đói) là nguyên nhân chính gây tử vong cho chim non.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"8,2,1,2,0\"><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">24. What food supply do bittern chicks depend on?</strong></p>\n<ul data-path-to-node=\"8,3,1\">\n<li>\n<p data-path-to-node=\"8,3,1,0,0\"><strong data-path-to-node=\"8,3,1,0,0\" data-index-in-node=\"0\">Đáp án</strong>: fish</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,1,1,0\"><strong data-path-to-node=\"8,3,1,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “The <strong data-path-to-node=\"8,3,1,1,0\" data-index-in-node=\"16\">fish</strong> prey fed to chicks was mainly those species penetrating into the reed edge.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,1,2,0\"><strong data-path-to-node=\"8,3,1,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Chim non phụ thuộc vào nguồn thức ăn là các loài cá.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8,4,0\"><strong data-path-to-node=\"8,4,0\" data-index-in-node=\"0\">25. What other creatures mentioned in the passage have also benefited from improvements made to the bittern’s habitat?</strong></p>\n<ul>\n<li style=\"list-style-type: none;\">\n<ul data-path-to-node=\"8,4,1\">\n<li>\n<p data-path-to-node=\"8,4,1,0,0\"><strong data-path-to-node=\"8,4,1,0,0\" data-index-in-node=\"0\">Đáp án</strong>: otters</p>\n</li>\n<li>\n<p data-path-to-node=\"8,4,1,1,0\"><strong data-path-to-node=\"8,4,1,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “…the work has helped a range of other spectacular wetland species such as <strong data-path-to-node=\"8,4,1,1,0\" data-index-in-node=\"88\">otters</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,4,1,2,0\"><strong data-path-to-node=\"8,4,1,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Ngoài chim bittern, loài rái cá (otters) cũng được hưởng lợi từ việc cải tạo môi trường đầm lầy.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('38cf134f-7d98-4112-a3e0-f07838127b8c', 'fb5d2a12-9aca-4da2-b05e-bf1b9a953d51', 'fillup', 'Questions 1-10', '<p><strong data-start="137" data-end="188">Write ONE WORD AND/OR A NUMBER for each answer.</strong></p>
<p style="text-align: center;" data-start="195" data-end="225"><strong data-start="199" data-end="225">Advice on family visit</strong></p>
<p><strong data-start="227" data-end="244">Accommodation</strong></p>
<ul data-start="247" data-end="332">
<li data-start="247" data-end="279"> {Kings | King’s} Hotel on George Street</li>
<li data-start="280" data-end="332">Cost of family room per night: 2 £ {125|one hundred and twenty-five |one hundred twenty-five} (approx.)</li>
</ul>
<p><strong data-start="339" data-end="360">Recommended trips</strong></p>
<ul data-start="363" data-end="459">
<li data-start="363" data-end="425">A {walking} tour of the city centre (starts in Carlton Square)</li>
<li data-start="426" data-end="459">A trip by {boat} to the old fort</li>
</ul>
<p><strong data-start="466" data-end="484">Science Museum</strong></p>
<ul data-start="487" data-end="566">
<li data-start="487" data-end="515">Best day to visit: {Tuesday}</li>
<li data-start="516" data-end="566">See the exhibition about {space}, which opens soon</li>
</ul>
<p><strong>Food</strong><br data-start="581" data-end="584">Clacton Market:</p>
<ul data-start="606" data-end="668">
<li data-start="606" data-end="629">Good for {vegetarian} food</li>
<li data-start="630" data-end="668">Need to have lunch before {2.30|two thirty} p.m.</li>
</ul>
<p><strong data-start="675" data-end="694">Theatre tickets</strong></p>
<ul data-start="697" data-end="756">
<li data-start="697" data-end="756">Save up to {75|seventy-five} % on ticket prices at bargaintickets.com</li>
</ul>
<p><strong data-start="763" data-end="782">Free activities</strong><br data-start="782" data-end="785"><strong data-start="785" data-end="807">Blakewell Gardens:</strong></p>
<ul data-start="810" data-end="885">
<li data-start="810" data-end="834">Roots Music Festival</li>
<li data-start="835" data-end="885">Climb Telegraph Hill to see a view of the {port}</li>
</ul>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. Nơi Ở và Hoạt Động (Questions 1–6)<br /> </p>\n<p>MAN: Sandra, I seem to remember you had some family visitors staying with you recently.</p>\n<p>SANDRA: Yeah, that&#8217;s right.</p>\n<p>SANDRA: My brother and his family were here a couple of months ago.</p>\n<p>MAN: OK, good.</p>\n<p>MAN: Well, I wanted to ask your advice.</p>\n<p>MAN: I&#8217;ve got my cousin and her family visiting next month and as I don&#8217;t have kids, I&#8217;ve no idea where to take them.</p>\n<p>SANDRA: Right.</p>\n<p>SANDRA: What about accommodation?</p>\n<p>SANDRA: Are they going to stay with you in your flat?</p>\n<p>MAN: No, thankfully.</p>\n<p>MAN: There wouldn&#8217;t be room.</p>\n<p>MAN: My cousin wants me to recommend a hotel.</p>\n<p>MAN: Do you know anywhere?</p>\n<p>SANDRA: Yes, I do actually.</p>\n<p>SANDRA: I always recommend people stay at the King&#8217;s Hotel. (Question 1)</p>\n<p>MAN: Where&#8217;s that near?</p>\n<p>SANDRA: It&#8217;s about five minutes walk from Murray Station, so nice and central.</p>\n<p>SANDRA: It&#8217;s actually on George Street. (Question 2)</p>\n<p>MAN: Oh yes, I know.</p>\n<p>MAN: I think they&#8217;re on quite a tight budget.</p>\n<p>MAN: So how much, roughly, is it to stay there?</p>\n<p>SANDRA: If you book a family room, it&#8217;s about £125 per night.</p>\n<p>SANDRA: My brother paid for two double rooms in the end and I think that was around £95 for each room. (Question 3)</p>\n<p>MAN: Oh, that&#8217;s not too bad.</p>\n<p>SANDRA: So how old are your cousin&#8217;s kids?</p>\n<p>MAN: Twelve and nine.</p>\n<p>MAN: So I want to organise some trips while they&#8217;re here.</p>\n<p>MAN: I was thinking of doing a bus tour of the city centre as none of them have been here before.</p>\n<p>SANDRA: Those bus tours are quite expensive.</p>\n<p>SANDRA: I think it&#8217;s better to do a walking tour. (Question 4)</p>\n<p>SANDRA: It gives you a much better feel for the city.</p>\n<p>SANDRA: There&#8217;s one that starts from Colton Square.</p>\n<p>SANDRA: It takes a couple of hours and doesn&#8217;t cost that much.</p>\n<p>MAN: Sounds good.</p>\n<p>MAN: I&#8217;ll look that up.</p>\n<p>MAN: Thanks.</p>\n<p>SANDRA: If the weather&#8217;s nice, one thing you could do is visit the old fort. (Question 5)</p>\n<p>SANDRA: You could get there by boat.</p>\n<p>SANDRA: The whole trip takes half a day.</p>\n<p>MAN: That&#8217;s a really good idea.</p>\n<p>MAN: I&#8217;d like to do that myself.</p>\n<p>MAN: And if the weather&#8217;s bad, I was thinking they could go to the Science Museum.</p>\n<p>MAN: But maybe they could do that when I&#8217;m at work.</p>\n<p>SANDRA: Yeah, don&#8217;t forget it&#8217;s closed on Mondays.</p>\n<p>MAN: They&#8217;re here from Saturday for four nights, so Tuesday would be best, I think. (Question 6)</p>\n<p>SANDRA: And it won&#8217;t be so crowded then.</p>\n<p>SANDRA: Saturdays are terrible.</p>\n<p>SANDRA: I took my kids to the exhibition on old computers there and it was far too crowded.</p>\n<p>SANDRA: I wanted to go back but it&#8217;s finished now.</p>\n<p>MAN: That&#8217;s a shame.</p>\n<p>MAN: My cousin&#8217;s kids would have enjoyed that.</p>\n<p>SANDRA: There&#8217;s another one starting soon on Space, which looks really good too.</p>\n<p>MAN: OK, well, I&#8217;ll mention that to my cousin.</p>\n<p> <br /> </p>\n<p>2. Ăn Uống và Giải Trí Miễn Phí (Questions 7–10)<br /> </p>\n<p>SANDRA: Have you thought about where to take them to eat?</p>\n<p>MAN: Well, I really like all the food stalls at Clacton Market. (Question 7)</p>\n<p>MAN: My cousin&#8217;s vegetarian.</p>\n<p>MAN: I know it&#8217;s one of the best places for that kind of food.</p>\n<p>SANDRA: Definitely.</p>\n<p>SANDRA: And there&#8217;ll be loads of choice for the kids too.</p>\n<p>SANDRA: You need to get there quite early though.</p>\n<p>SANDRA: At the weekend, most of the stalls stop serving lunch at 2.30. (Question 8)</p>\n<p>MAN: Good point. It&#8217;s all going to need careful planning.</p>\n<p>MAN: My cousin said she&#8217;d love to take the kids to a show at the theatre, but tickets are so expensive.</p>\n<p>SANDRA: I know.</p>\n<p>SANDRA: But you can get some good deals if you book online with bargain-tickets.com for the following day.</p>\n<p>SANDRA: On some seats there&#8217;s a 75% discount. (Question 9)</p>\n<p>MAN: Really?</p>\n<p>MAN: I must try and get some.</p>\n<p>SANDRA: Yeah.</p>\n<p>SANDRA: There are lots of things you can do for free as well.</p>\n<p>SANDRA: No need to spend a fortune.</p>\n<p>MAN: Like what?</p>\n<p>SANDRA: They&#8217;re coming next month, right?</p>\n<p>SANDRA: Well, check and see if it&#8217;s the same weekend as the Roots Music Festival in Blakewell Gardens. (Question 10)</p>\n<p>MAN: R-O-O-T-S?</p>\n<p>SANDRA: Yeah, check it out online.</p>\n<p>SANDRA: It&#8217;s always a family-friendly event and there&#8217;s no entry charge.</p>\n<p>MAN: That sounds perfect.</p>\n<p>SANDRA: And if you&#8217;re in Blakewell Gardens, climb Telegraph Hill.</p>\n<p>SANDRA: You&#8217;ll be able to look right down on the port.</p>\n<p>SANDRA: Everyone&#8217;s always really impressed because it&#8217;s so huge.</p>\n<p>MAN: Oh yeah, I&#8217;ve been meaning to do that for ages.</p>\n<p>MAN: I&#8217;ve heard the view&#8217;s amazing.</p>\n<p>SANDRA: Yeah, it&#8217;s really worth the effort.</p>\n<p>MAN: Well, that&#8217;s given me loads of ideas.</p>\n<p>MAN: Thanks so much.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('dfd893e1-3811-4afd-8299-909f02bd65a8', '3d0f5b40-ddfc-42e7-a8a7-977b0b4ce976', 'matching', 'Questions 32–36', NULL, '<p>Complete the summary using the list of words, A-I, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>The television series based on Ekman’s work</strong></p>\r\n<p>A new TV series based on Ekman’s work features a hero named Lightman, who detects lies. Initially, Ekman was unenthusiastic about the TV project because he feared the possibility of encouraging viewers {C false belief}. For example, he was worried that one day the programme could result in {E justice} not being carried out. Ultimately though, he has given the show his blessing because he is not aware of any other comparable programme based on a single person’s {H research}.</p>\r\n<p>The {D motives} of the show’s producer have been another pleasant surprise and, considering the genre of the programme, Ekman is happy with the show’s overall {F accuracy}</p>", "answerOptions": [{"optionText": "A consequences"}, {"optionText": "B crimes"}, {"optionText": "C false belief"}, {"optionText": "D motives"}, {"optionText": "E justice"}, {"optionText": "F accuracy"}, {"optionText": "G acting"}, {"optionText": "H research"}, {"optionText": "I ratings"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>32. Initially, Ekman was unenthusiastic about the TV project because he feared the possibility of encouraging viewers  C. false belief.</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong>Đáp án:</strong> <strong>C. false belief</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “…he was fearful that the show would exaggerate the effectiveness of his techniques and <strong>create the quite inaccurate impression</strong> among audiences that criminals could no longer hope to get away with lying.”</li>\n<li><strong>Giải thích:</strong> Ông lo sợ chương trình sẽ tạo ra ấn tượng sai lệch (false belief) về tính hiệu quả của kỹ thuật.</li>\n</ul>\n<p><strong>33. For example, he was worried that one day the programme could result in E. justice not being carried out.</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong>Đáp án:</strong> <strong>E. justice</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) “In the worst-case scenario, he was concerned about <strong>unfair convictions</strong>, that one day someone not properly trained in his techniques might be sitting on a jury and <strong>wrongly find someone guilty of a crime</strong>…”</li>\n<li><strong>Giải thích:</strong> Ông lo sợ việc kết án sai người vô tội (unfair convictions/wrongly find someone guilty) sẽ dẫn đến việc công lý (<strong>justice</strong>) không được thực thi.</li>\n</ul>\n<p><strong>34. Ultimately though, he has given the show his blessing because he is not aware of any other comparable programme based on a single person’s  H. research.</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong>Đáp án:</strong> <strong>H. research</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “It is the first time, as far as Ekman is aware, that a commercial TV drama has been based on the work of <strong>just one scientist</strong>.”</li>\n<li><strong>Giải thích:</strong> Ông bị thuyết phục vì chương trình dựa trên công trình nghiên cứu (<strong>research</strong>) của cá nhân ông.</li>\n</ul>\n<p><strong>35. The <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> D. motives of the show’s producer have been another pleasant surprise, and considering the genre of the programme, Ekman is happy with the show’s overall  F. accuracy.</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong>Đáp án:</strong> <strong>D. motives</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “He was also impressed with the producer’s manifestly serious and <strong>well-intentioned reasons</strong> for making the programme.”</li>\n<li><strong>Giải thích:</strong> Ekman ấn tượng với lý do (motives) nghiêm túc và có ý định tốt của nhà sản xuất.</li>\n</ul>\n<p><strong>36. …Ekman is happy with the show’s overall  F. accuracy.</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong>Đáp án:</strong> <strong>F. accuracy</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “Now that the first series has been completed, he believes probably <strong>80-90 per cent of the show is based on fact</strong> and that’s good enough for what is.”</li>\n<li><strong>Giải thích:</strong> Việc tin rằng 80-90% chương trình dựa trên sự thật thể hiện sự hài lòng về tính chính xác (<strong>accuracy</strong>) tổng thể của chương trình</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('7f7d8248-3d0d-427b-a0c8-80a47aeb58be', '3d0f5b40-ddfc-42e7-a8a7-977b0b4ce976', 'radio', 'Questions 37–40', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Choose YES if the statement agrees with the claims of the writer, choose NO if the statement contradicts the claims of the writer, or NOT GIVEN if it is impossible to say what the writer thinks about this."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": " People who are good at lying tend to be good at detecting lies."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Ekman has worked with poker players to help them lie more convincingly."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Ekman is more interested in the types of lies with serious consequences."}]', 'null', 'null', 'null', '[{"content": "<p><strong>37. Ekman regrets the lies he told as a child.</strong></p>\n<ul data-path-to-node=\"27\">\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) “Ekman, incidentally, <strong>professes to have been a terrible liar ever since he was a small boy</strong>…”</li>\n<li><strong>Giải thích:</strong> Ông thừa nhận là một người nói dối kém từ nhỏ, nhưng <strong>không nói</strong> ông có hối hận (regrets) về những lời nói dối đó hay không.</li>\n</ul>\n<p><strong>38. People who are good at lying tend to be good at detecting lies.</strong></p>\n<ul data-path-to-node=\"29\">\n<li><strong>Đáp án:</strong> <strong>NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) “…and observes that <strong>ability to detect a lie and the ability to lie successfully are completely unrelated</strong>.”</li>\n<li><strong>Giải thích:</strong> Hai khả năng này hoàn toàn không liên quan đến nhau (completely unrelated).</li>\n</ul>\n<p><strong>39. Ekman has worked with poker players to help them lie more convincingly.</strong></p>\n<ul data-path-to-node=\"31\">\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) Ông nói poker players không phải là người nói dối thực sự, nhưng <strong>không có thông tin</strong> về việc ông có làm việc với họ để cải thiện khả năng lừa dối hay không.</li>\n</ul>\n<p><strong>40. Ekman is more interested in the types of lies with serious consequences.</strong></p>\n<ul data-path-to-node=\"33\">\n<li><strong>Đáp án:</strong> <strong>YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) “He prefers to focus on the kinds of lies where <strong>the liar would be on grave trouble if they were found out</strong>, and where the target would feel properly aggrieved if they knew.”</li>\n<li><strong>Giải thích:</strong> Ông tập trung vào những lời nói dối gây ra hậu quả nghiêm trọng (“grave trouble” / “serious consequences”).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('4ed61434-7091-47a0-8300-a873923b92bd', '5971a32d-d158-4282-a451-dd15a92e581b', 'checkbox', 'Questions 19–20', '', '<p data-start="384" data-end="412">Choose <strong data-start="391" data-end="411">TWO letters, A–E</strong>.</p>
<p data-start="414" data-end="476">Which <strong data-start="420" data-end="427">TWO</strong> points does Heather make about a potter’s tools?</p>
<p data-start="478" data-end="638" data-is-last-node="" data-is-only-node=""> </p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A Some are hard to hold"}, {"correct": false, "option_text": "B Some are worth buying"}, {"correct": true, "option_text": "C Some are essential items"}, {"correct": false, "option_text": "D Some have memorable names"}, {"correct": true, "option_text": "E Some are available for use by participants"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('b6f8f829-3d7c-494b-a047-1c578eb9c09f', '0ab9d0cd-58e5-4f6d-b848-688be43091e8', 'radio', 'Questions 1–5', '', '<p id="p-rc_15b35af655f2be62-56" data-path-to-node="3,0,0"><span class="citation-2428">Choose </span><strong data-path-to-node="3,0,0" data-index-in-node="0"><span class="citation-2428">TRUE</span></strong><span class="citation-2428"> if the statement agrees with th</span><span class="citation-2427 citation-2428 citation-end-2428">e information,</span><strong data-path-to-node="3,1,0" data-index-in-node="0"><span class="citation-2425 citation-2426">FALSE</span></strong><span class="citation-2425 citation-2426 citation-end-2426"> if the statement contradicts the inform</span><span class="citation-2425 citation-end-2425">ation,</span><strong data-path-to-node="3,2,0" data-index-in-node="0"><span class="citation-2424">NOT GIVEN</span></strong><span class="citation-2424 citation-end-2424"> if there is no information on this</span></p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Cuneiform tablets were produced in different shapes and sizes."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "When Sumerian writers marked the clay tablets, the tablets were dry."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Cuneiform was often difficult to read because of its size."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "A number of languages adopted cuneiform."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Cuneiform signs can be found in some modern alphabets."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"0\"> </p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">1. Cuneiform tablets were produced in different shapes and sizes. — {TRUE}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…most often inscribed on <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"39\">palm-sized, rectangular</strong> clay tablets… although occasionally <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"101\">larger tablets or cylinders</strong> were used.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê nhiều hình dạng (chữ nhật, hình trụ) và kích cỡ (vừa lòng bàn tay, hoặc lớn hơn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. When Sumerian writers marked the clay tablets, the tablets were dry. — {FALSE}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Sumerian writers would impress these lines into the <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"64\">wet clay</strong> with a stylus…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người viết ấn bút lên đất sét khi nó còn <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"53\">ướt</strong> (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"58\">wet</em>), trái ngược hoàn toàn với ý “đã khô” (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"101\">dry</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. Cuneiform was often difficult to read because of its size. — {TRUE}</strong></p>\n<ul>\n<li data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Dẫn chứng:</strong> \"...Oddly, the signs were often almost <strong data-path-to-node=\"3\" data-index-in-node=\"50\">too small to see with the naked eye</strong>.\"</li>\n<li data-path-to-node=\"3\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Giải thích:</strong> Việc các ký tự quá nhỏ để nhìn bằng mắt thường (<strong data-path-to-node=\"4\" data-index-in-node=\"60\">too small to see with the naked eye</strong>) đồng nghĩa với việc chúng rất khó đọc (<strong data-path-to-node=\"4\" data-index-in-node=\"136\">difficult to read</strong>) do kích thước (<strong data-path-to-node=\"4\" data-index-in-node=\"170\">size</strong>) tí hon của mình.</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. A number of languages adopted cuneiform. — {TRUE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Cuneiform signs were used for the writing of <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"57\">at least a dozen languages</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “At least a dozen” (ít nhất 12) tương ứng với “a number of languages”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">5. Cuneiform signs can be found in some modern alphabets. — {FALSE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “In fact, it <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"24\">died out and remained unintelligible</strong> for almost 2,000 years.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết cho biết hệ thống này đã hoàn toàn biến mất và không còn ai hiểu được trong 2.000 năm cho đến khi Rawlinson giải mã. Nó không để lại dấu vết trực tiếp trong các bảng chữ cái hiện đại.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c1c8b13f-80fa-40c3-85f3-c6e20d1691a7', '0ab9d0cd-58e5-4f6d-b848-688be43091e8', 'fillup', 'Questions 6–13', '<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 6–13 on your answer sheet.</p>
<p data-path-to-node="8"><strong>The Development and Translation of Cuneiform</strong></p>
<p data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0">Before cuneiform</strong></p>
<ul data-path-to-node="10">
<li>
<p data-path-to-node="10,0,0">tokens, for example {stones} were often used</p>
</li>
<li>
<p data-path-to-node="10,1,0">the first tokens were kept in containers made of {cloth}</p>
</li>
<li>
<p data-path-to-node="10,2,0">tokens were used as a {receipt} to give when selling something</p>
</li>
</ul>
<p data-path-to-node="11"><strong data-path-to-node="11" data-index-in-node="0">By the 4th century BCE</strong></p>
<ul data-path-to-node="12">
<li>
<p data-path-to-node="12,0,0">tokens were put in a container that looked like a clay {envelope}</p>
</li>
</ul>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">Complex, abstract symbols developed</strong></p>
<ul data-path-to-node="14">
<li>
<p data-path-to-node="14,0,0">at first, signs looked like what they indicated, e.g. {sheep}</p>
</li>
<li>
<p data-path-to-node="14,1,0">then signs became more abstract</p>
</li>
<li>
<p data-path-to-node="14,2,0">eventually, cuneiform signs shaped like {triangles} were developed</p>
</li>
<li>
<p data-path-to-node="14,3,0">according to experts, cuneiform was mainly used for {accounting}</p>
</li>
</ul>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">19th-century translation of cuneiform inscriptions by Henry Rawlinson</strong></p>
<ul data-path-to-node="16">
<li>
<p data-path-to-node="16,0,0">Rawlinson found cuneiform inscriptions in the Behistun Mountains</p>
</li>
<li>
<p data-path-to-node="16,1,0">Rawlinson copied the inscriptions onto {paper}</p>
</li>
<li>
<p data-path-to-node="16,2,0">Rawlinson realised that each word of the inscriptions appeared in three languages</p>
</li>
<li>
<p data-path-to-node="16,3,0">When translated, Rawlinson found that the writings were about a 5th-century BCE king</p>
</li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">6. …tokens, for example {stones} were often used.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…they might take small <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"37\">stones</strong> and use them as tokens…” (Đoạn 3)</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">7. …the first tokens were kept in containers made of {cloth}.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “These tokens might then be placed in a <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"51\">cloth</strong> container…” (Đoạn 3)</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">8. …tokens were used as a {receipt} to give when selling something.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…provided to a buyer as a <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"40\">receipt</strong> for a transaction…” (Đoạn 3)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">9. …tokens were put in a container that looked like a clay {envelope}.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…putting tokens in a container resembling an <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"59\">envelope</strong>, one made of clay…” (Đoạn 4)</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">10. …signs looked like what they indicated, e.g. {sheep}.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “For example, an image which resembled the drawing of a <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"67\">sheep</strong> meant just that.” (Đoạn 5)</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">11. …eventually, cuneiform signs shaped like {triangles} were developed.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the signs took the form of <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"42\">triangles</strong>, which became common cuneiform signs.” (Đoạn 5)</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">12. …according to experts, cuneiform was mainly used for {accounting}.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…most linguists and historians agree cuneiform developed primarily as a tool for <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"95\">accounting</strong>.” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">13. …Rawlinson copied the inscriptions onto {paper}.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Rawlinson made impressions of the marks on large pieces of <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"71\">paper</strong>…” (Đoạn 7)</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('20cbd2cc-eeab-4031-abc7-1fc02b5699e7', 'df820a30-8015-461e-a1d4-8cbf4199a024', 'matching', 'Questions 14–19', '', '<p>The text has six paragraphs. Choose the correct heading for each paragraph and move it into the gap.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "Evidence that man’s ancestors had a concept of the future"}, {"optionText": "Research into the relation between brain size and memory"}, {"optionText": "Animals that can remember places and time"}, {"optionText": "Research into various animals’ capacity for future planning"}, {"optionText": "A memory type described with reference to brain damage"}, {"optionText": "Conflicting experimental results concerning animal memory"}, {"optionText": "Research evidence of memory loss in various animals"}, {"optionText": "Experimental evidence of a relation between past and future in human mental processes"}, {"optionText": "Research into ways to improve episodic memory"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. A memory type described with reference to brain damage</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Clues about different kinds of memory can be discovered from research conducted on <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"95\">people with certain brain injuries</strong>… A man known as <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"148\">KC</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giới thiệu về <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"35\">episodic memory</strong> (trí nhớ tình tiết) thông qua ví dụ về bệnh nhân KC — người bị chấn thương não (<em data-path-to-node=\"4,2,0\" data-index-in-node=\"131\">brain damage/injuries</em>) dẫn đến việc mất đi khả năng nhớ các sự kiện cá nhân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. Animals that can remember places and time</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…test American birds called <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"42\">western scrub jays</strong>… The birds that waited only <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"91\">four hours</strong> tended to dig up larvae, while the birds that had to wait for <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"164\">five days</strong>… dug up peanuts instead.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thí nghiệm chứng minh loài chim này không chỉ nhớ <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"62\">vị trí</strong> (<em data-path-to-node=\"6,2,0\" data-index-in-node=\"70\">places/location</em>) giấu đồ ăn mà còn nhớ cả <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"112\">thời gian</strong> (<em data-path-to-node=\"6,2,0\" data-index-in-node=\"123\">time/how long ago</em>) để biết khi nào sâu bướm sẽ bị hỏng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. Conflicting experimental results concerning animal memory</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Research with other animals… has had <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"51\">mixed results</strong>. When experimental <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"84\">rats</strong>… seem to be able to recall… <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"121\">hummingbirds</strong>… show that they remember… Tests using <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"176\">Rhesus monkeys</strong> have found that they can remember where… but <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"238\">not how long ago</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Mixed results” ở đây chính là các kết quả trái chiều (<em data-path-to-node=\"8,2,0\" data-index-in-node=\"67\">conflicting</em>). Trong khi chuột và chim ruồi có vẻ có trí nhớ tình tiết, thì khỉ Rhesus lại thất bại trong việc ghi nhớ yếu tố thời gian.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Evidence that man’s ancestors had a concept of the future</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…discovery of <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"28\">stone tools</strong> which <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"46\">primitive humans</strong> used… 1.6 million years ago. …the only reason you’re going to take a tool with you is if you <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"160\">anticipate using it in the future</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tổ tiên loài người mang theo công cụ đá đi xa nơi sản xuất là bằng chứng cho thấy họ có khả năng dự tính cho nhu cầu trong tương lai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. Experimental evidence of a relation between past and future in human mental processes</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"12\">Recent brain scanning studies</strong>… many parts of the <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"63\">same episodic memory networks</strong> become active again [when thinking about the future]… suggesting an <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"163\">inter-connection</strong> between the processing of the past and future.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các cuộc quét não cung cấp bằng chứng thực nghiệm (<em data-path-to-node=\"12,2,0\" data-index-in-node=\"63\">experimental evidence</em>) cho thấy vùng não nhớ về quá khứ và vùng não tưởng tượng tương lai có liên quan chặt chẽ với nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. Research into various animals’ capacity for future planning</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…look for evidence that <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"38\">animals can also think ahead</strong>. …<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"71\">Cebus monkeys</strong>… will eat until they are full and throw the rest… [but] <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"145\">squirrel monkeys</strong>… learned to choose one [to get water sooner].”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này tập trung vào các nghiên cứu trên các loài động vật khác nhau (<em data-path-to-node=\"14,2,0\" data-index-in-node=\"84\">various animals</em>) để xem chúng có khả năng lập kế hoạch cho tương lai (<em data-path-to-node=\"14,2,0\" data-index-in-node=\"154\">future planning/think ahead</em>) hay không.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2e1fc4ea-a094-4a8a-819e-b52fd8560abe', '57ece189-00b1-4012-b0fd-d77735bc7f26', 'checkbox', 'Questions 21–22', '', '<p data-start="139" data-end="167">Choose <strong data-start="146" data-end="166">TWO letters, A–E</strong>.</p>
<p data-start="169" data-end="266">Which <strong data-start="175" data-end="182">TWO</strong> things do the students both believe are responsible for the increase in loneliness?</p>
<p data-start="268" data-end="374"> </p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A social media"}, {"correct": false, "option_text": "B smaller nuclear families"}, {"correct": true, "option_text": "C urban design"}, {"correct": false, "option_text": "D longer lifespans"}, {"correct": true, "option_text": "E a mobile workforce"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3 – RESEARCH INTO LONELINESS</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">TAMARA:</strong> Shall we go through the notes we’ve made from our research into loneliness now, Dev?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">DEV:</strong> OK, Tamara. It’s been a real eye-opener. I had no idea that loneliness has been increasing steadily for the last twenty years.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">TAMARA:</strong> I know. And it’s the same all over the world – the downside of a modern lifestyle I guess.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">DEV:</strong> Did you come to any conclusions about what the reasons for the increase are?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">TAMARA:</strong> Well, I’d assumed it was mainly an issue for the elderly – but in fact it’s something which affects young people just as much.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">DEV:</strong> Mmm. So nothing really to do with longer lifespans. What about social media? In my case, far from making me feel isolated, it actually does the opposite.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">TAMARA:</strong> It definitely does more good than harm.<span style=\"background-color: #f3db7b;\"> I’d say <strong data-path-to-node=\"9\" data-index-in-node=\"56\">loneliness has a lot to do with the way cities are designed</strong> – people living in high-rise flats with not much opportunity to speak to their neighbours. (Q21/22)</span></p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">DEV:</strong> I think you’re right.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">TAMARA:</strong> Another possible reason is that people are having fewer children and don’t live in large extended family groups.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">DEV:</strong> But, in this country anyway, that all changed decades ago and yet loneliness is a more recent problem.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">TAMARA:</strong> I suppose so<span style=\"background-color: #f3db7b;\">. A more plausible explanation is that <strong data-path-to-node=\"13\" data-index-in-node=\"59\">people are having to move around for work and often end up living miles away from their family and friends.</strong> (Q21/22)</span></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">DEV:</strong> That’s true.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">TAMARA:</strong> Looking at the studies on health risks and loneliness, there are claims that loneliness has as much impact as smoking 15 cigarettes a day.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">DEV:</strong> Or similar to the risks caused by obesity. But I’m not sure there’s enough evidence for some of these claims.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">TAMARA:</strong> Well – <span style=\"background-color: #f3db7b;\">what about that one in Finland which showed that <strong data-path-to-node=\"17\" data-index-in-node=\"64\">loneliness increased the risk of cancer by about ten per cent?</strong></span> And those findings have been supported by other studies too. (Q23/24)</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">DEV:</strong> You’re right about that one. I was actually thinking of the studies on dementia. Some found no association between loneliness and dementia and others found the opposite.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">TAMARA:</strong> Not exactly reliable then. There’s been a lot of research on cardiovascular disease and whether loneliness contributes to that.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">DEV:</strong> Yes, I read that it was hard to reach a judgement as the definition of loneliness varied quite a lot and the responses from participants were too subjective.<span style=\"background-color: #f3db7b;\"> But <strong data-path-to-node=\"20\" data-index-in-node=\"167\">there’s no doubt that loneliness contributes to a weakened immune system.</strong> (Q23/24)</span></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">TAMARA:</strong> Unquestionably. The data on that is sound.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">DEV:</strong> What did you think about the evolutionary theory of loneliness?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">TAMARA:</strong> Well, I thought the idea that loneliness evolved because it motivated people to be with other people quite convincing. Survival often depended on group cooperation.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">DEV:</strong> But I don’t think there’s enough evidence to claim that there must be a group of neurons in our brains which influence social behaviour, by making us feel bad when we’re alone.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">TAMARA:</strong> There are a few studies which support the theory but not conclusively enough.<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"25\" data-index-in-node=\"86\">More evidence is needed.</strong> (Q25/26)</span></p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">DEV:</strong> Mmm. <span style=\"background-color: #f3db7b;\">And anyway, <strong data-path-to-node=\"26\" data-index-in-node=\"22\">this theory’s not really useful when it comes to solving the problem of loneliness today.</strong> (Q25/26)</span></p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">TAMARA:</strong> True.</p>\n<hr data-path-to-node=\"28\">\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">DEV:</strong> Should we look at the relationship between loneliness and mental health now?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">TAMARA:</strong> OK. So, loneliness and depression are clearly related and that’s been recognised by various governments around the world. But unlike depression, loneliness has no recognised clinical form.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">DEV:</strong> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"31\" data-index-in-node=\"5\">There’s no available diagnosis or effective treatment – and that’s not likely to change.</strong> (Q27)</span></p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">TAMARA:</strong> I don’t think so either. I was thinking we should start our presentation with an example from our own experience. I’d like to talk about how lonely I was when I started university. Being away from home for the first time and all that.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">DEV:</strong> Good idea. <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"33\" data-index-in-node=\"16\">Everyone will be able to relate to that</strong> – although a lot of students were probably too embarrassed to admit it. (Q28)</span></p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">TAMARA:</strong> Yeah. We could discuss ways of dealing with loneliness as well. Like just talking to strangers.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">DEV:</strong> Loads of studies have shown that interactions with shop assistants and bar staff make people feel more optimistic and relaxed.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">TAMARA:</strong><span style=\"background-color: #f3db7b;\"> I don’t know about that but <strong data-path-to-node=\"36\" data-index-in-node=\"36\">it must make people feel more connected with their community.</strong> (Q29)</span></p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">DEV:</strong> True. Although you need to be a certain kind of person to be able to just strike up a conversation.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">TAMARA:</strong> Good point. We should say something about solitude and how being alone and being lonely aren’t the same thing. It’s strange the way some people can’t stand being by themselves while others love it.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">DEV:</strong> Yeah. <span style=\"background-color: #f3db7b;\">The research shows a certain amount of solitude is beneficial for well-being, which I appreciate – but <strong data-path-to-node=\"39\" data-index-in-node=\"114\">being alone isn’t something I actually like.</strong> (Q30)</span> I’d never choose to go on holiday alone, for example.</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">TAMARA:</strong> Me neither.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">DEV:</strong> Well let’s not…</p>"}]', 0);
INSERT INTO public.questions VALUES ('6f346424-2751-462e-8455-c513a1a20c42', 'df820a30-8015-461e-a1d4-8cbf4199a024', 'checkbox', 'Questions 20–21', '', '<p>Choose <strong>TWO </strong>correct answers</p>
<p>Which <strong>TWO </strong>of the following statements concerning episodic memory are found in the text?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "Dr Tulving believes that most kinds of memory involve aspects of episodic memories"}, {"correct": true, "option_text": "The experimental subject KC was unable to recall the process by which he learned to play a particular board game"}, {"correct": true, "option_text": "In the case of KC, the subject’s episodic memory was affected by his brain injuries"}, {"correct": false, "option_text": "Dr Tulving carried out extensive observations of the episodic memories of animals as well as humans"}, {"correct": false, "option_text": "To test his episodic memory, KC was given various mathematical problems to solve"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Đáp án đúng: B và C</strong></p>\n<ul>\n<li data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">B. The experimental subject KC was unable to recall the process by which he learned to play a particular board game.</strong>\n<ul data-path-to-node=\"8,0,1\">\n<li>\n<p data-path-to-node=\"8,0,1,0,0\"><em data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…could play chess with no memory of having ever played it before.” (Đoạn 1).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,0,1,1,0\"><em data-path-to-node=\"8,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> KC biết chơi cờ nhưng không nhớ quá trình mình đã học nó như thế nào.</p>\n</li>\n</ul>\n</li>\n<li data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">C. In the case of KC, the subject’s episodic memory was affected by his brain injuries.</strong>\n<ul>\n<li>\n<p data-path-to-node=\"8,1,1,0,0\"><em data-path-to-node=\"8,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…certain brain injuries that cause them to forget autobiographical details… KC had lost what psychologists now call ‘episodic memory’.” (Đoạn 1).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,1,1,0\"><em data-path-to-node=\"8,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> Chấn thương não đã khiến KC mất đi trí nhớ về các trải nghiệm cá nhân.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('931b8aee-96d3-4acb-ae36-89208a88c23d', 'b2a7c2e8-badf-456b-970c-242f36e19d9e', 'matching', 'Questions 14-20', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. Why it is necessary to explain the meaning of the word celebrity"}, {"optionText": "ii The influence of non-human celebrities on societies"}, {"optionText": "iii. The impact of broadcasting on concepts of celebrity"}, {"optionText": "iv. Creativity having greater value"}, {"optionText": "v. Admiration for physical achievement"}, {"optionText": "vi. The advantages of celebrity status in the ancient world"}, {"optionText": "vii A result of hardship"}, {"optionText": "viii Literacy and widespread celebrity"}, {"optionText": "ix. Attitudes of celebrities towards the media"}, {"optionText": "x. The original definition of celebrity"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">14. Đoạn 1: x. The original definition of celebrity</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “The word ‘celebrity’ has its </span><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"41\">roots</strong><span class=\"\"> in the language of the ancient Roman civilization…</span><span class=\"\"> derived from the </span><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"117\">Latin word ‘celeber’</strong><span class=\"\">,</span><span class=\"\"> meaning frequented or populous.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này tập trung vào nguồn gốc ngôn ngữ học và ý nghĩa sơ khai của từ “celebrity” trong tiếng Latin.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. Đoạn 2: ii. The influence of non-human celebrities on societies</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “The celebrities of the ancient world were the </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"58\">powerful and awesome deities</strong><span class=\"\"> of Greece and Rome…</span><span class=\"\"> believed in a vast number of </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"138\">immortals</strong><span class=\"\">…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Non-human” (không phải con người) ở đây chính là các vị thần (deities/immortals).</span><span class=\"\"> Đoạn văn giải thích tầm ảnh hưởng của các vị thần này đối với đời sống con người thời cổ đại.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. Đoạn 3: v. Admiration for physical achievement</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Victors in the ancient </span><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"35\">Olympic Games</strong><span class=\"\">…</span><span class=\"\"> gladiators…</span><span class=\"\"> revered…</span><span class=\"\"> for their heroics and </span><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"99\">seemingly superhuman strength</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Thành tựu thể chất (physical achievement) thể hiện qua sức mạnh của các đấu sĩ và vinh quang của các vận động viên Olympic.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. Đoạn 4: vii. A result of hardship</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “spiritual figures lent excitement to the lives of common people…</span><span class=\"\"> as they faced </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"93\">war, disease, and food shortages</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Hardship” (sự gian khổ) chính là chiến tranh,</span><span class=\"\"> dịch bệnh và thiếu thốn thực phẩm.</span><span class=\"\"> Sự nổi tiếng của các nhân vật tôn giáo là cứu cánh tinh thần cho người dân trong giai đoạn này.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. Đoạn 5: iv. Creativity having greater value</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “This period of </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"27\">appreciation for the arts</strong><span class=\"\">…</span><span class=\"\"> artists began to </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"73\">surpass political and religious individuals</strong><span class=\"\"> for supreme celebrity.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Creativity” (sự sáng tạo) đại diện cho giới nghệ sĩ (artists).</span><span class=\"\"> Thời kỳ Phục hưng coi trọng giá trị sáng tạo nghệ thuật hơn là quyền lực chính trị hay tôn giáo.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Đoạn 6: viii. Literacy and widespread celebrity</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">huge rise in the number of </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"42\">common people who could read</strong><span class=\"\">…</span><span class=\"\"> allowing a </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"85\">mass audience</strong><span class=\"\"> to find out about celebrities for the first time.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong class=\"\" data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Khả năng biết chữ (</span><strong class=\"\" data-path-to-node=\"13,1,0\" data-index-in-node=\"31\">Literacy</strong><span class=\"\">) tăng cao giúp danh tiếng của các cá nhân lan tỏa rộng rãi (</span><strong class=\"\" data-path-to-node=\"13,1,0\" data-index-in-node=\"100\">widespread</strong><span class=\"\">) thông qua báo chí và sách vở.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. Đoạn 7: iii. The impact of broadcasting on concepts of celebrity</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"18\">radio and film</strong> took off in the 1900s… Then, the rise of <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"76\">television</strong> in the 1950s…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Broadcasting” (truyền thông quảng bá) bao gồm đài phát thanh, phim ảnh và tivi đã thay đổi hoàn toàn cách thức con người trở nên nổi tiếng.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('da4db1fe-6693-4f3e-8dec-944bbe521cb5', 'b2a7c2e8-badf-456b-970c-242f36e19d9e', 'matrix', 'Questions 21-23', NULL, '<p>Match each statement with the correct historical period</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "Historical periods", "matrixItems": [{"itemText": "A wide variety of people achieve a brief period of fame.", "correctCategoryLetter": "D"}, {"itemText": "Stories are invented about celebrities'' lives.", "correctCategoryLetter": "A"}, {"itemText": "The fame of rulers is starting to diminish.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Ancient times", "categoryLetter": "A"}, {"categoryText": "Dark Ages", "categoryLetter": "B"}, {"categoryText": "Renaissance", "categoryLetter": "C"}, {"categoryText": "Modern era", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">21. A wide variety of people achieve a brief period of fame.</strong></p>\n<p data-path-to-node=\"3\">(Nhiều nhóm người khác nhau đạt được một khoảng thời gian nổi tiếng ngắn ngủi.)</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: D. Modern era (Kỷ nguyên hiện đại)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The emergence of reality television shows in the late 1990s allowed <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"80\">all kinds of people</strong> with little ability to enjoy a <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"131\">short burst of fame</strong> on the television screen.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “all kinds of people” tương ứng với “a wide variety of people”, và “short burst of fame” tương ứng với “brief period of fame”. Hiện tượng này gắn liền với truyền hình thực tế trong kỷ nguyên hiện đại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Stories are invented about celebrities’ lives.</strong></p>\n<p data-path-to-node=\"7\">(Các câu chuyện được thêu dệt/sáng tạo ra về cuộc đời của những người nổi tiếng.)</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: A. Ancient times (Thời cổ đại)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This need to know led to the <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"41\">creation of myths</strong>, which personalized the gods and involved them in ancient celebrity scandals…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Creation of myths” (sáng tạo ra các huyền thoại/thần thoại) chính là việc thêu dệt nên các câu chuyện. Trong thời cổ đại, các vị thần được coi là người nổi tiếng và người dân đã tạo ra các thần thoại để tìm hiểu về đời tư của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">23. The fame of rulers is starting to diminish.</strong></p>\n<p data-path-to-node=\"11\">(Sự nổi tiếng của các nhà cầm quyền bắt đầu suy giảm.)</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: C. Renaissance (Thời kỳ Phục hưng)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “During the period 1300-1600 AD, or the <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"51\">Renaissance</strong> period as it is known, <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"86\">interest in ruling figures faded</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “interest in ruling figures faded” (sự quan tâm đến các nhân vật cầm quyền phai nhạt dần) đồng nghĩa với việc sự nổi tiếng của các nhà cầm quyền đang bắt đầu suy giảm (starting to diminish).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('5fe66127-f2eb-4b2b-9061-24c44f03c00d', 'df820a30-8015-461e-a1d4-8cbf4199a024', 'checkbox', 'Questions 22–23', '', '<p data-start="791" data-end="822">Choose <strong data-start="798" data-end="805">TWO</strong> correct answers.</p>
<p data-start="824" data-end="839">Which <strong>TWO </strong>of the following statements are true concerning Dr Clayton’s experiments with scrub jays?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "The experiments indicated that the birds could remember how long their food had been buried"}, {"correct": false, "option_text": "In the experiments, the scrub jays preferred burying moth larvae to burying peanuts"}, {"correct": false, "option_text": "In the experiments, the birds were guided by the smell of the hidden food"}, {"correct": false, "option_text": "Scrub jays were taught by Dr Clayton to store food for future use"}, {"correct": true, "option_text": "Scrub jays would rather eat certain nuts than decaying moth larvae"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Đáp án đúng: A và E</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">A. The experiments indicated that the birds could remember how long their food had been buried.</strong></p>\n<ul data-path-to-node=\"12,0,1\">\n<li>\n<p data-path-to-node=\"12,0,1,0,0\"><em data-path-to-node=\"12,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “The time the scrub jays had spent away… affected the type of food they looked for.” (Đoạn 2).</p>\n</li>\n<li>\n<p data-path-to-node=\"12,0,1,1,0\"><em data-path-to-node=\"12,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> Chúng biết chọn sâu bướm sau 4 giờ nhưng chọn lạc sau 5 ngày vì biết sâu sẽ hỏng theo thời gian.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">E. Scrub jays would rather eat certain nuts than decaying moth larvae.</strong></p>\n<ul data-path-to-node=\"12,1,1\">\n<li>\n<p data-path-to-node=\"12,1,1,0,0\"><em data-path-to-node=\"12,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…if the larvae have been dead for even a few hours, the jays prefer peanuts.” (Đoạn 2).</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,1,1,0\"><em data-path-to-node=\"12,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</em> Lũ chim thích lạc (nuts) hơn là sâu bướm đã bị thối rữa (decaying).</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('70261350-ecac-4900-9f31-c031c687a9e4', 'df820a30-8015-461e-a1d4-8cbf4199a024', 'fillup', 'Questions 24–26', '<p>Complete the summary.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;" data-start="2059" data-end="2098"><span style="font-size: 12pt;"><strong data-start="2063" data-end="2098">What is ‘true’ episodic memory?</strong></span></p>
<p data-start="2100" data-end="2514">Dr Suddendorf believes that ‘true’ episodic memory requires the ability to use the memory for the future. He cites as evidence ancient {tools} which early humans had taken some distance from where they had been originally fashioned. Dr Suddendorf’s theory is supported by brain scans showing activation of certain networks in particular areas of the brain both by episodic memory and by consideration of the future.</p>
<p data-start="2516" data-end="2832">Do non-human animals also exhibit ‘true’ episodic memory? Cebus monkeys appear to waste food once they are full, indicating that they do not plan for the future. However, in experiments, squirrel monkeys chose not to take the extra {dates} they were offered as food, in anticipation of wanting {water} soon afterwards.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">24. He cites as evidence ancient {tools} which early humans had taken some distance…</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><em data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…discovery of stone <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"34\">tools</strong> which primitive humans used… were moved many kilometres from where they were originally made.” (Đoạn 4).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">25. …squirrel monkeys chose not to take the extra {dates} they were offered…</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><em data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “…gave squirrel monkeys a choice of between one or four <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"69\">dates</strong> to eat… The monkeys learned to choose one.” (Đoạn 6).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">26. …in anticipation of wanting {water} soon afterwards.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><em data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</em> “If the monkeys took four, the scientists kept the <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"62\">water</strong> away for three hours. If the monkeys took one, the scientists returned it in half an hour.” (Đoạn 6).</p>\n</li>\n</ul>"}]', 3);
INSERT INTO public.questions VALUES ('a6f396b2-2107-4d63-aa85-322395c9e547', '1890bf51-20b0-4241-b056-35310f700de8', 'matching', 'Questions 27–31', '', '<p>Complete each sentence with the correct ending, <strong data-path-to-node="3" data-index-in-node="48">A–H</strong>, below.</p>
<p>Write the correct letter, <strong data-path-to-node="3" data-index-in-node="86">A–H</strong>, in boxes 27–31 on your answer sheet.</p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "should be easy to understand"}, {"optionText": "can improve without treatment"}, {"optionText": "can cost the patient less"}, {"optionText": "ought to last a minimum length of time"}, {"optionText": "can require a range of different products"}, {"optionText": "can be described as serious"}, {"optionText": "should give it greater recognition"}, {"optionText": "should be able to get a high income"}], "matchingItems": [{"questionPart": "An appointment with an alternative practitioner", "correctAnswer": "D"}, {"questionPart": "An alternative practitioner’s explanation of their treatment", "correctAnswer": "A"}, {"questionPart": "If alternative practitioners have faith in their treatment, they", "correctAnswer": "H"}, {"questionPart": "Quite often, a patient’s illness", "correctAnswer": "B"}, {"questionPart": "Conventional doctors are aware of the placebo effect and they", "correctAnswer": "G"}]}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. An appointment with an alternative practitioner — {D} ought to last a minimum length of time.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…each session with your patients should take <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"59\">at least half an hour</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “At least half an hour” tương ứng với “a minimum length of time”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. An alternative practitioner’s explanation of their treatment — {A} should be easy to understand.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Describe your treatment in <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"39\">familiar words</strong>…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sử dụng “từ ngữ quen thuộc” nghĩa là cách giải thích đó phải dễ hiểu với bệnh nhân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. If alternative practitioners have faith in their treatment, they — {H} should be able to get a high income.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “And a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"18\">very good living</strong> if you are sufficiently convincing or, better still, really <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"95\">believe in your therapy</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A very good living” (có cuộc sống tốt) đồng nghĩa với “get a high income” (có thu nhập cao).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. Quite often, a patient’s illness — {B} can improve without treatment.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"12\">Many illnesses get better on their own</strong>, so if you are lucky… you’ll get the credit.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Get better on their own” tương ứng với “improve without treatment” (tự khỏi mà không cần điều trị).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. Conventional doctors are aware of the placebo effect and they — {G} should give it greater recognition.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…conventional medicine recognizes but remains <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"60\">oddly ambivalent</strong> about [it]… though its role is <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"110\">often neglected and misunderstood</strong>.” (Đoạn 2 &amp; 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì y học hiện đại vẫn còn “mơ hồ” (ambivalent) và “bỏ qua/hiểu sai” (neglected/misunderstood) về hiệu ứng này, nên tác giả ngụ ý họ cần phải công nhận nó nhiều hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('8dca50c3-68be-4262-9449-27ecabd91089', 'd962d32e-8405-4650-8fd8-53875d5fcb5a', 'matching', 'Questions 27–30', '', '<p>What do they think of each of the following courses?</p>
<p>Choose the correct answer and move it into the gap.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Courses</strong></p>\n<p> </p>\n<p>Metallurgy {Useful material online}</p>\n<p> </p>\n<p>Fluid mechanics {Professor’s explanation was clear}</p>\n<p> </p>\n<p>Computing {became more engaging}</p>\n<p> </p>\n<p>Energy economy {involved lots of practical work}</p>", "answerOptions": [{"optionText": "became more engaging"}, {"optionText": "Professor’s note was detailed"}, {"optionText": "involved lots of practical work"}, {"optionText": "Professor’s explanation was clear"}, {"optionText": "Useful material online"}, {"optionText": "Harder than expected"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('be004754-6b4d-4969-98ab-b0c53bc2f5b8', '1890bf51-20b0-4241-b056-35310f700de8', 'radio', 'Questions 32–34', '', '<p><span class="citation-6165 citation-6166 citation-end-6166">Choose the correct le</span><span class="citation-6165">tter, </span><strong data-path-to-node="9" data-index-in-node="27"><span class="citation-6165">A, B, C</span></strong><span class="citation-6165"> or </span><strong data-path-to-node="9" data-index-in-node="38"><span class="citation-6165">D</span></strong><span class="citation-6165 citation-end-6165">.</span></p>
<p><span class="citation-6164 citation-end-6164">Write the correct letter in b</span>oxes 32–34 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A works best in tablet form."}, {"option_text": "B is a new type of medical treatment."}, {"option_text": "C is trusted more by some patients than by others."}, {"option_text": "D has a significant role in both alternative and conventional medicine."}], "question": "In the third paragraph, the writer says that the placebo effect"}, {"correct": 0, "options": [{"option_text": "A personal feelings can alter our physical condition."}, {"option_text": "B some human behaviour has no clear explanation."}, {"option_text": "C placebos, like emotions, are experienced by everyone."}, {"option_text": "D people find some physical reactions hard to control."}], "question": "A reference is made to anger and sadness in order to show that"}, {"correct": 2, "options": [{"option_text": "A Only a limited amount of research has been conducted so far."}, {"option_text": "B Scientists have discovered that endorphins can help to reduce pain."}, {"option_text": "C Pain-reducing agents might also be involved in the placebo effect."}, {"option_text": "D Patients often experience pain and like to complain about it."}], "question": "Research on pain control attracts most of the attention because"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. In the third paragraph, the writer says that the placebo effect — {D} has a significant role in both alternative and conventional medicine.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “In fact, the placebo is a <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"38\">powerful part of all medical care, orthodox or otherwise</strong>…” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Orthodox or otherwise” có nghĩa là cả y học chính thống (conventional) và các loại hình khác (alternative).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. A reference is made to anger and sadness in order to show that — {A} personal feelings can alter our physical condition.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…our <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"19\">state of mind can influence our physiology</strong>: anger opens the superficial blood vessels… sadness pumps the tear glands.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cảm xúc (anger, sadness) dẫn đến các thay đổi vật lý (mặt đỏ, chảy nước mắt) chứng minh tâm trí có thể thay đổi tình trạng cơ thể.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Research on pain control attracts most of the attention because — {C} Pain-reducing agents might also be involved in the placebo effect.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Any of the <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"23\">neurochemicals involved in transmitting pain impulses</strong>… might also be involved in <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"106\">generating the placebo response</strong>…” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các chất dẫn truyền thần kinh liên quan đến giảm đau được cho là cũng tham gia vào việc tạo ra phản ứng giả dược.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('17e56da7-f4f0-4724-b38d-e6bfbeb2dfe2', 'b2a7c2e8-badf-456b-970c-242f36e19d9e', 'fillup', 'Questions 24-26', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.<br />
Write your answers in boxes <strong>24-26</strong> on your answer sheet.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Celebrities Achieve a Global Status</strong></span></p>
<p>The development of the publishing industry in the 1700s signalled the beginning of international fame. A growing number of people could read, which meant they had the chance to become informed about their favourite figures by reading {newspapers}. This exposure to celebrities expanded further when radio and television became popular, and it was mass media attention that resulted in higher status and fame for some celebrities. The recent rise of reality television has also meant that a person’s {appearance} rather than their talent can bring fame. With this type of television programme, fame may be entirely dependent on the response of the {audience}.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">24. newspapers</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, câu 4: “Suddenly, the lives of authors, politicians, war heroes, and other celebrities could now be read about in <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"133\">newspapers</strong> around the world.”</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản cho biết nhờ sự phát triển của ngành in ấn và số người biết đọc tăng lên, công chúng có thể tìm hiểu về các nhân vật họ ngưỡng mộ thông qua việc đọc <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"169\">báo chí</strong> (newspapers).</li>\n</ul>\n<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">25. appearance</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 7, câu 5-6: “…reality television shows… allowed all kinds of people with little ability to enjoy a short burst of fame… All you needed, it seemed, was an attractive <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"187\">appearance</strong>.”</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong các chương trình truyền hình thực tế hiện đại, thay vì tài năng, một người có thể trở nên nổi tiếng chỉ nhờ vào <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"130\">ngoại hình</strong> (appearance) thu hút của mình.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">26. audience</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 7, câu 7: “…with the <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"39\">audience</strong> deciding whether someone deserves to become a celebrity or not.”</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đối với loại chương trình truyền hình này, sự nổi tiếng phụ thuộc hoàn toàn vào việc <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"97\">khán giả</strong> (audience) quyết định xem người đó có xứng đáng trở thành ngôi sao hay không.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('dc993f55-aa64-4093-b036-2f03e4a504ff', '0fe88398-e380-44ce-9420-98b7d4b9252f', 'matching', 'Questions 38-40', NULL, '<p>Complete the summary using the list of words, A-H, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"ql-align-center\" style=\"text-align: center;\"><strong>The Bilbao effect</strong></p>\r\n<p class=\"ql-align-justify\">MONA has huge appeal for visitors to Hobart, just as Gehry’s Guggenheim Museum has for Bilbao. While MONA may lack the {C visual<span class=\"fill-history-correct\">}</span> effect of the Guggenheim, David Walsh explains that MONA’s architect had a different objective when designing MONA: unlike the architectural showcasing of the Guggenheim, with MONA there was a major {A challenge<span class=\"fill-history-correct\">}</span> that needed to be dealt with; the gallery was set beneath the ground. In any case, both galleries have transformed their cities, just as successful public buildings have for thousands of years. It remains to be seen how the {D contribution<span class=\"fill-history-correct\">}</span> of David Walsh will be expanded upon in Tasmania.</p>", "answerOptions": [{"optionText": "A challenge"}, {"optionText": "B pipe"}, {"optionText": "C visual"}, {"optionText": "D contribution"}, {"optionText": "E lasting"}, {"optionText": "F essential"}, {"optionText": "G ambition"}, {"optionText": "H attraction"}], "matchingItems": null}', 'null', '[{"content": "<p><strong data-path-to-node=\"2\" data-index-in-node=\"0\">38. C (visual)</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, dòng 4-7.</li>\n<li><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;whereas Fender Katsalidis’s MONA does not have the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"66\">same spectacular impact</strong> as the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"97\">shimmering metal surfaces</strong> of Gehry’s building.&#8221;</li>\n<li><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc so sánh vẻ ngoài của hai bảo tàng. Trong khi bảo tàng Guggenheim có bề mặt kim loại lung linh tạo ra tác động thị giác cực mạnh, thì kiến trúc của MONA không có được hiệu ứng <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"195\">thị giác (visual effect)</strong> ngoạn mục như vậy vì nó nằm dưới lòng đất.</li>\n</ul>\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">39. A (challenge)</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, dòng 8-10.</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"citation-13\"> &#8220;&#8230;Fender Katsalidis </span><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"33\"><span class=\"citation-13\">solved a problem</span></strong><span class=\"citation-13\"> when he designed MONA, in executing a project of this scale in an </span><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"116\"><span class=\"citation-13\">underground location</span></strong><span class=\"citation-13 citation-end-13\">.&#8221;</span>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</li>\n<li><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> David Walsh cho rằng kiến trúc sư của ông phải giải quyết một vấn đề/thử thách (<strong data-path-to-node=\"5,2,0\" data-index-in-node=\"92\">problem</strong> tương ứng với <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"114\">challenge</strong>) thực tế, đó là xây dựng một công trình quy mô lớn hoàn toàn dưới lòng đất, thay vì chỉ tập trung vào phô diễn kiến trúc như ở Bilbao.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">40. D (contribution)</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, câu cuối.</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Now the question is how Tasmania will build on <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"59\">David Walsh’s input</strong> into its cultural setting.&#8221;</li>\n<li><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ &#8220;input&#8221; (sự đóng góp/đầu vào) trong bài tương ứng với từ <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"72\">contribution</strong>. Tác giả đặt ra câu hỏi về việc Tasmania sẽ tiếp tục phát triển dựa trên những gì David Walsh đã đóng góp cho bối cảnh văn hóa của bang này như thế nào.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('f71f4356-d47b-40a3-9be7-12c63f07bab4', 'a4b0ff40-afa9-4f18-9e73-f5814cac01ba', 'matrix', 'Questions 14-18', NULL, '<p>Which paragraph contains the following information? Choose the correct letter, A-H</p>', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "an observation that the nature of vocal sound makes it impossible to find evidence of how music began.", "correctCategoryLetter": "G"}, {"itemText": "examples of sounds that babies are able to perceive before they are born.", "correctCategoryLetter": "C"}, {"itemText": "examples of characteristics that one researcher believes all music must possess.", "correctCategoryLetter": "D"}, {"itemText": "a claim that motherese is not as simple as it might seem when first heard.", "correctCategoryLetter": "B"}, {"itemText": "an explanation of the origins of motherese.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<h3 data-path-to-node=\"2\">Câu 14</h3>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">G</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"3,1,0\" data-index-in-node=\"11\">“Vocal music, like speech, leaves no physical traces that could help us determine its ancient origins… None of these theories are provable.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn G, chuyên gia Sandra Trehub nhận định rằng âm nhạc bằng giọng nói (vocal sound) không để lại dấu tích vật lý nào (no physical traces), điều này khiến việc tìm bằng chứng xác thực về cách âm nhạc bắt đầu là điều không thể (impossible to find evidence).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"4\">Câu 15</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">C</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,1,0\" data-index-in-node=\"11\">“…a fetus begins hearing nearly four months before birth, as it regularly hears its mother’s voice, heartbeat, and digestive sounds…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C liệt kê các ví dụ cụ thể về âm thanh mà thai nhi (fetus) có thể cảm nhận được trước khi sinh ra (before birth) như: giọng nói của mẹ, nhịp tim và tiếng tiêu hóa.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">Câu 16</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,1,0\" data-index-in-node=\"11\">“…measure their validity against a set of criteria which he called ‘universal aspects of music’. Some key aspects are that music is meaningful… it involves movement… it has structural components… it performs certain social functions…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D trình bày các ví dụ về những đặc điểm (rhythm, melody, social functions, v.v.) mà nhà nghiên cứu Parncutt tin rằng là “phổ quát” (universal), nghĩa là mọi loại âm nhạc đều phải sở hữu các yếu tố này.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">Câu 17</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">B</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,1,0\" data-index-in-node=\"11\">“Although it might appear amusing or even nonsensical on the surface, ‘motherese’ is actually a sophisticated form of communication.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định rằng dù “motherese” nghe có vẻ buồn cười hay vô nghĩa khi mới nghe qua, nhưng thực tế nó là một hình thức giao tiếp “sophisticated” (tinh vi/phức tạp). Điều này khớp với ý “không đơn giản như vẻ ngoài”.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">Câu 18</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,1,0\" data-index-in-node=\"11\">“As the theory goes, increased human brain sizes… resulted in earlier births… ‘motherese’ arose as a way to strengthen this maternal bond and to help infants survive.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A giải thích nguồn gốc hình thành của motherese (the origins) là kết quả của quá trình tiến hóa (não lớn hơn dẫn đến sinh non), buộc người mẹ phải phát triển cách giao tiếp này để giúp trẻ sơ sinh sống sót.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('17737993-ba3e-4062-a2ca-995d850c4fa4', 'a4b0ff40-afa9-4f18-9e73-f5814cac01ba', 'matrix', 'Questions 19-23', NULL, '<p>Match each statement with the correct researcher.</p>
<p>NB You may use any letter more than once.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "Theories about how music first began are just guesswork.", "correctCategoryLetter": "C"}, {"itemText": "Music can help people cope with boredom in their jobs. ", "correctCategoryLetter": "D"}, {"itemText": "An analysis of the various accounts for the origin of music has greatly enriched understanding.", "correctCategoryLetter": "B"}, {"itemText": "Motherese reinforces the connection between a mother and her baby. ", "correctCategoryLetter": "A"}, {"itemText": "The motherese theory fails to explain the beginnings of music that is not produced by the voice. ", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Richard Parncutt", "categoryLetter": "A"}, {"categoryText": "Gary McPherson", "categoryLetter": "B"}, {"categoryText": "Sandra Trehub", "categoryLetter": "C"}, {"categoryText": "Neil McLachlan", "categoryLetter": "D"}]}', '[{"content": "<h3 data-path-to-node=\"3\">Câu 19</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">C (Sandra Trehub)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"4,1,0\" data-index-in-node=\"11\">“Sandra Trehub… warns, ‘Many ideas about music’s beginnings are speculative—quite wild speculations at that… None of these theories are provable’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn G, Sandra Trehub nhận định rằng các ý tưởng về khởi đầu của âm nhạc chỉ là sự suy đoán (speculative/wild speculations) và không thể chứng minh được. Điều này đồng nghĩa với việc chúng chỉ là sự đoán mò (guesswork).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"5\">Câu 20</h3>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">D (Neil McLachlan)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,1,0\" data-index-in-node=\"11\">“In work, music could help distract from monotonous tasks’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Neil McLachlan đề cập trong đoạn H rằng trong công việc, âm nhạc giúp con người xao nhãng khỏi những nhiệm vụ đơn điệu (monotonous tasks). “Monotonous” chính là trạng thái gây ra sự buồn chán (boredom) trong công việc.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">Câu 21</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">B (Gary McPherson)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,1,0\" data-index-in-node=\"11\">“By evaluating all these theories, he constructs a compelling argument. It’s an excellent contribution’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở đoạn F, Gary McPherson đánh giá cao phương pháp của Parncutt khi xem xét và đánh giá toàn bộ các lý thuyết hiện có (evaluating all these theories) để xây dựng lập luận. Ông coi đây là một đóng góp xuất sắc (excellent contribution), giúp làm giàu/mở rộng sự hiểu biết (enriched understanding) về lĩnh vực này.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"9\">Câu 22</h3>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">A (Richard Parncutt)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,1,0\" data-index-in-node=\"11\">“…’motherese’ arose as a way to strengthen this maternal bond and to help infants survive.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tại đoạn A, Richard Parncutt đề xuất rằng “motherese” xuất hiện như một cách để củng cố mối liên kết mẫu tử (strengthen this maternal bond). Cụm từ “strengthen the bond” tương ứng hoàn toàn với “reinforces the connection” trong câu hỏi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"11\">Câu 23</h3>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"8\">D (Neil McLachlan)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,1,0\" data-index-in-node=\"11\">“…it does not cover all music—especially non-vocal forms like rhythmic entertainment’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Neil McLachlan phê bình ở đoạn H rằng lý thuyết về “motherese” không bao quát được hết các loại hình âm nhạc, đặc biệt là các dạng không dùng giọng hát (non-vocal forms). Điều này khớp với ý lý thuyết này “thất bại trong việc giải thích” (fails to explain) âm nhạc không do giọng nói tạo ra.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('bb43a6b4-4a74-40e3-aafa-498cdc4d6881', '1890bf51-20b0-4241-b056-35310f700de8', 'radio', 'Questions 35–40', '', '<p data-path-to-node="19,0,0">Choose<strong data-path-to-node="19,0,0" data-index-in-node="0"> YES</strong> if the statement agrees with the views of the writer,<strong data-path-to-node="19,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the views of the writer,<strong data-path-to-node="19,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Scientists now have enough information to understand how the placebo effect becomes active in people."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "As a result of experiments, some painkillers have been taken off the market."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Individual preference can have an impact on the effectiveness of different brands of headache tablets."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Doctors expressed a range of views on the drug chlorpromazine when it was first introduced."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Ernst’s study had a big influence on doctors’ behaviour with patients."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Alternative practitioners work in a way that is likely to trigger the placebo effect."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">35. Scientists now have enough information to understand how the placebo effect becomes active… — {NO}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “But exactly <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"24\">how placebos work their medical magic is still largely unknown</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái ngược hoàn toàn với ý “đã có đủ thông tin để hiểu”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. As a result of experiments, some painkillers have been taken off the market. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói về các thí nghiệm màu sắc viên thuốc (đỏ, xanh, xanh lá) hoặc thương hiệu (Aspro, Tylenol), <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"120\">không hề đề cập</strong> đến việc có loại thuốc nào bị thu hồi khỏi thị trường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. Individual preference can have an impact on the effectiveness of different brands… — {YES}</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…if Aspro or Tylenol are <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"39\">what you like</strong> to take… their chemically identical generic equivalents <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"111\">may be less effective</strong>.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “What you like” chính là sở thích cá nhân (<em data-path-to-node=\"28,1,0\" data-index-in-node=\"55\">individual preference</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. Doctors expressed a range of views on the drug chlorpromazine… — {YES}</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…categorised his colleagues according to whether they were <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"73\">keen on it, openly sceptical… or took a let’s-try-and-see attitude</strong>.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các thái độ “thích thú”, “hoài nghi” và “thử xem sao” chính là “một loạt các quan điểm” (<em data-path-to-node=\"30,1,0\" data-index-in-node=\"101\">range of views</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. Ernst’s study had a big influence on doctors’ behaviour with patients. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “A recent survey by Ernst on doctors’ bedside manners turned up one consistent finding…” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu kết quả khảo sát của Ernst về phong cách tiếp xúc bệnh nhân, <strong data-path-to-node=\"32,1,0\" data-index-in-node=\"89\">không nói</strong> khảo sát này có làm thay đổi hành vi của các bác sĩ sau đó hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. Alternative practitioners work in a way that is likely to trigger the placebo effect. — {YES}</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…complementary practitioners are <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"47\">generally best at mobilising the placebo effect</strong>…” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Mobilising” (huy động/kích hoạt) tương ứng với “trigger”.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('acacb6d8-fcc5-4a33-a867-eea0025b1eea', '40bf7e0c-b4d7-4bf0-9c1e-96a89294e032', 'matching', 'Questions 14–20', NULL, '<p>Reading Passage 2 has seven paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, i-viii, in boxes 14-20</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i A character who provoked sympathy and amusement"}, {"optionText": "ii Outdoor performances with a standard set of"}, {"optionText": "iii Pantomime as a means of focusing on political issues"}, {"optionText": "iv Discovering pantomime at a young age"}, {"optionText": "v A way of dealing with a negative attitude toward pantomime"}, {"optionText": "vi An explanation of how a pantomime character appeals to modern audiences"}, {"optionText": "vii Debate about the origins of pantomime"}, {"optionText": "viii A successful merging of artistic sources"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">14. Đoạn 1: iv Discovering pantomime at a young age</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Khám phá kịch pantomime khi còn nhỏ.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “For many <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"21\">British children</strong>, their <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"45\">first family trip</strong> to see a pantomime… is their <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"94\">introduction</strong> to the magic of the theatre.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn này nói về việc trẻ em Anh lần đầu tiếp xúc với nghệ thuật sân khấu thông qua các buổi diễn pantomime vào dịp Giáng sinh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. Đoạn 2: ii Outdoor performances with a standard set of characters</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Các buổi biểu diễn ngoài trời với một nhóm nhân vật chuẩn mực.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “These improvised shows took place in <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"49\">streets and marketplaces</strong>… Distinctive masks enabled audiences to <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"116\">recognise the people</strong> in these stories immediately… rich old men… young lovers… quick-witted servants.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn văn mô tả bối cảnh biểu diễn ở đường phố/chợ (ngoài trời) và liệt kê các loại nhân vật điển hình (old men, lovers, servants) mà khán giả nhìn là nhận ra ngay.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. Đoạn 3: viii A successful merging of artistic sources</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một sự pha trộn thành công các nguồn nghệ thuật.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “…interwove Ovid’s… poem Metamorphoses with aspects of the Italian commedia… <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"94\">cleverly mixed</strong> spectacle, music, ballet and myth…”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn này mô tả cách John Rich kết hợp (mix/interweave) nhiều yếu tố từ thơ ca La Mã, kịch Ý, âm nhạc và vũ ba-lê để tạo nên kịch pantomime hiện đại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. Đoạn 4: v A way of dealing with a negative attitude toward pantomime</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một cách để đối phó với thái độ tiêu cực đối với pantomime.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “Critics <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"20\">bitterly attacked</strong> pantomimes… David Garrick… tactic was to set about changing pantomime’s cultural identity, partly by <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"143\">confining shows to his theatre’s Christmas season</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Khi bị các nhà phê bình chỉ trích là đe dọa kịch chính thống, Garrick đã đối phó bằng cách đưa pantomime vào mùa lễ hội Giáng sinh để biến nó thành một hình thức giải trí nhẹ nhàng, không còn là mối đe dọa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. Đoạn 5: iii Pantomime as a means of focusing on political issues</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Pantomime như một phương tiện để tập trung vào các vấn đề chính trị.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “…a world of comic <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"32\">revenge against a highly repressive government</strong>. Grimaldi became one of the great <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"113\">satirists</strong> of his age… commentaries on everything from the <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"173\">ruling classes</strong> to fashion…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn này nói về nhân vật Chú hề (Clown) của Grimaldi, người sử dụng kịch để châm biếm chính phủ áp bức và các tầng lớp thống trị (vấn đề chính trị).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Đoạn 6: i A character who provoked sympathy and amusement</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một nhân vật khơi dậy sự đồng cảm và sự vui vẻ.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “…the pantomime ‘Dame’: a tired housewife… Leno developed a persona whose theatrical power comes from the <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"121\">locking together of compassion and laughter</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Nhân vật “Dame” (quý bà – do nam đóng) khiến khán giả vừa cười (laughter/amusement) vừa thương cảm (compassion/sympathy) vì hoàn cảnh nghèo khó của cô ấy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. Đoạn 7: vi An explanation of how a pantomime character appeals to modern audiences</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Giải thích cách một nhân vật pantomime thu hút khán giả hiện đại.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: “Pantomimes are as <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"30\">popular today</strong> as they have ever been… Her comical conversations with the audience <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"114\">cut across the boundaries</strong> between performers and spectators, drawing us into her chaotic world.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn cuối giải thích sức hút của nhân vật Dame đối với khán giả ngày nay thông qua việc phá vỡ khoảng cách giữa sân khấu và người xem, tạo ra sự gắn kết cộng đồng.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('849a451e-c82a-464d-a744-092c6f9fe9a9', '40bf7e0c-b4d7-4bf0-9c1e-96a89294e032', 'fillup', 'Questions 21–23', '<p class="MsoNormal">Complete the sentences below.</p>
<p class="MsoNormal">Write <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
<p class="MsoNormal"> Commedia dell’arte actors used {Masks} to disguise their real identities.</p>
<p class="MsoNormal"> Harlequinades combined elements of a 16th-century art form with a {Poem} written many centuries earlier.</p>
<p class="MsoNormal"> In early 19th-century pantomimes, {Policemen} were often victims of the Clown’s activities.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">21. Masks</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 2, câu 3: “Distinctive <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"39\">masks</strong> enabled audiences to recognise the people in these stories immediately; they also allowed actors to be rude or disrespectful without fear of being recognised.”</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Các diễn viên kịch Commedia dell’arte sử dụng những chiếc mặt nạ đặc trưng để khán giả nhận diện nhân vật, đồng thời giúp họ che giấu danh tính thật (disguise real identities) để có thể diễn những hành động khiếm nhã mà không sợ bị phát hiện.</li>\n</ul>\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">22. Poem</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 3, câu 2: “Among the most popular performances were harlequinades, a new kind of entertainment which interwove Ovid’s first-century Latin <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"154\">poem</strong> Metamorphoses with aspects of the Italian commedia.”</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Kịch Harlequinades là sự kết hợp giữa các yếu tố của kịch Ý (Commedia dell’arte – nghệ thuật thế kỷ 16) với bài thơ “Metamorphoses” (viết từ thế kỷ thứ 1, tức là nhiều thế kỷ trước đó).</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">23. Policemen</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 5, câu 4: “His anarchic activities included chasing and imprisoning <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"84\">policemen</strong> and stealing gigantic quantities of sausages.”</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Trong các buổi diễn đầu thế kỷ 19, nhân vật Chú hề (Clown) của Grimaldi thường thực hiện các hành động nổi loạn nhắm vào cảnh sát (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"143\">policemen</strong>) như đuổi bắt và tống giam họ, biến họ thành nạn nhân trong các trò đùa của mình.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('e84ef48f-dc39-4f8d-834c-8d1311da218a', '88b1febd-23d2-40cc-8483-40dfaa6c8a37', 'fillup', 'Questions 1-5', '<p><strong>Write ONE WORD ONLY for each answer.</strong></p>
<p><strong>Poppy Reserve</strong></p>
<p>Almond Valley Poppy Reserve is a nature reserve</p>
<p>The poppies will be at their best at the end of the {month}</p>
<p>The poppies on the hills are {orange} in colour.</p>
<p>The reserve is located to the {east} of Lakeside.</p>
<p>The best time for photography is mid-afternoon.</p>
<p>Wear {trousers} because of rattlesnakes.</p>
<p>The reserve is a {state} park.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 1: ALMOND VALLEY POPPY RESERVE</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Ranger:</strong> Almond Valley Poppy Reserve, may I help you?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Woman:</strong> Is the nature reserve open now?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Ranger:</strong> Yes, we are actually open all year, although this is the best time of year to see the wildflowers.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Woman:</strong> Are the poppies blooming yet?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Ranger:</strong> Absolutely, they started to bloom last week and are already beautiful, but they should peak and be in full bloom at the end of the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"139\">(Q1) month</strong>.</span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Woman:</strong> Oh, I was planning on coming at the end of this week. Is that too early?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Ranger:</strong> No, not at all. The hills are already covered with <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"59\">(Q2) orange</strong></span> poppies.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Woman:</strong> I thought poppies were red.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Ranger:</strong> Not in California. I''ve never seen a red poppy here.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Woman:</strong> The Poppy Reserve is in Ocean County, right?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Ranger:</strong> Right. From Lakeside, you''ll need to drive about an hour <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"65\">(Q3) east</strong></span>.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Woman:</strong> What time does the reserve open?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Ranger:</strong> The reserve is open from sunrise to sunset. It''s best to come early in the morning to beat the crowds, but for the best photography, you might want to consider a mid-afternoon visit on a weekday.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Woman:</strong> I heard that there are a lot of rattlesnakes in the desert. Is it dangerous to walk about?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Ranger:</strong> Most wildlife is quite safe. There are very few people bitten by rattlesnakes, so we do recommend wearing <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"114\">(Q4) trousers</strong></span> just to be on the safe side.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Woman:</strong> Alright. I was hoping that I might have the chance to see some wildlife too. Oh, how much is the admission to the reserve?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Ranger:</strong> It''s $5.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Woman:</strong> Can I use my national park pass to enter the reserve?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Ranger:</strong> Unfortunately not, since it is a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"41\">(Q5) state</strong></span> park, not a national park.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Woman:</strong> Alright. I heard from a friend that there is a nature tour available. Can you tell me about it?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Ranger:</strong> Certainly, but can you excuse me just a sec? I''ll be right back.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"3\" data-index-in-node=\"1740\">Woman:</strong> Okay.</p>\n<hr data-path-to-node=\"23\">\n<h3 data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">TOUR INFORMATION (Questions 6–10)</strong></h3>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Ranger: </strong>Hello?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"3\" data-index-in-node=\"1740\">Woman: </strong>Yes, I''m still here.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Ranger: </strong>Now, you are interested in the nature tours, right?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Woman:</strong> Oh, there''s more than one?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Ranger:</strong> Yes, we have the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"25\">(Q6) general</strong></span> tour, which is the one your friend may have taken, but we also have two more specialized tours. Starting at 7:00 am is our general tour that''s early for some people, I know. It''s offered every hour too, but it''s a great time and it only lasts <strong data-path-to-node=\"5\" data-index-in-node=\"534\">30 minutes</strong>.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Woman:</strong> Is that the tour that takes you to the Vista points?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Ranger:</strong> Yes, that is one of the highlights, along with a film introducing the park and the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"91\">(Q7) museum</strong></span>. You''re welcome to tour the museum at your leisure. It''s a great tour for those who just want to take panoramic pictures with automatic cameras.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Woman:</strong> Well, if I come all that way, I''d like to have a more detailed tour.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Ranger:</strong> Then you are in luck, because we have a wonderful wildflower tour every two hours from 8:00 am. It lasts <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"32\" data-index-in-node=\"113\">(Q8) one</strong></span> hour and the volunteer will give you information about many of the flowers on the reserve.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Woman:</strong> Besides the poppies will cream cups be in bloom?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Ranger:</strong> Yes, and you will see lots of sage too. We have a volunteer who is really good at giving tips on close-up photography.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Woman:</strong> You mentioned another tour?</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Ranger:</strong> Yes, the last one is the wildlife tour, but it is offered at very limited times.</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Woman:</strong> Is that because most of the wildlife is nocturnal?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Ranger:</strong> Yes, so we offer this tour only two times: <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"38\" data-index-in-node=\"51\">(Q9) 5:30</strong></span> am or 7:00 pm.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Woman:</strong> Wow, that early! But don''t the snakes and lizards like the sun?</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Ranger:</strong> Right. First let me say it takes about an hour and a half, but you will have the opportunity to see other animals like coyotes, quail, and roadrunners. You have to get here before the crowds arrive or after most of them leave.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Woman:</strong> Well, that makes sense. Does it require a lot of walking?</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Ranger:</strong> More like a lot of standing, but most of the time you will be at one or two locations, so we recommend bringing a tripod and <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"42\" data-index-in-node=\"133\">(Q10) zoom</strong></span> lens if you want to take pictures.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Woman:</strong> Well, thank you very much. You''ve been extremely helpful and informative.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"5\" data-index-in-node=\"2195\">Ranger:</strong> You''re welcome, glad I could be of service. </p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"5\" data-index-in-node=\"2256\">Woman:</strong> Goodbye.</p>\n<p data-path-to-node=\"43\"><strong>Ranger:</strong> Goodbye.</p>"}]', 0);
INSERT INTO public.questions VALUES ('5fd45123-e7c7-4554-8a8a-cfda71760f3e', '88b1febd-23d2-40cc-8483-40dfaa6c8a37', 'fillup', 'Questions 6-10', '<p>Complete the table below</p>
